        #[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
        #[serde(deny_unknown_fields)]
        pub struct PermissionBinding {
            pub principal_id: String,
            pub authority: BTreeSet<String>,
            pub requested: BTreeSet<String>,
            pub approved_by: Vec<String>,
            pub expires_at_ms: Option<u64>,
            pub authorization_hash: String,
        }

        impl PermissionBinding {
            pub fn recompute_authorization_hash(&self) -> BrtResult<String> {
                hash_serializable(&serde_json::json!({
                    "principal_id": self.principal_id,
                    "authority": self.authority,
                    "requested": self.requested,
                    "approved_by": self.approved_by,
                    "expires_at_ms": self.expires_at_ms,
                }))
            }

            pub fn validate(&self, now_ms: u64, require_human: bool) -> Vec<String> {
                let mut errors = Vec::new();
                if self.principal_id.trim().is_empty() {
                    errors.push("principal_id_empty".into());
                }
                if !self.requested.is_subset(&self.authority) {
                    errors.push("privilege_exceeds_authority".into());
                }
                if self
                    .expires_at_ms
                    .map(|expires| expires <= now_ms)
                    .unwrap_or(false)
                {
                    errors.push("authorization_expired".into());
                }
                if require_human && self.approved_by.is_empty() {
                    errors.push("human_approval_missing".into());
                }
                match self.recompute_authorization_hash() {
                    Ok(hash) if hash == self.authorization_hash => {}
                    _ => errors.push("authorization_hash_invalid".into()),
                }
                errors
            }
        }

