        #[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
        #[serde(deny_unknown_fields)]
        pub struct GateMeasurement {
            pub gain: f64,
            pub risk: f64,
            pub uncertainty: f64,
            pub bridge_debt: f64,
            pub runtime_debt: f64,
            pub ontology_debt: f64,
            pub security_debt: f64,
            pub control: f64,
            pub verifier: f64,
            pub rollback: f64,
            pub policy: f64,
            pub audit: f64,
            pub cost_paid: f64,
            pub shutdown: f64,
        }

        impl GateMeasurement {
            pub fn is_finite_nonnegative(&self) -> bool {
                [
                    self.gain,
                    self.risk,
                    self.uncertainty,
                    self.bridge_debt,
                    self.runtime_debt,
                    self.ontology_debt,
                    self.security_debt,
                    self.control,
                    self.verifier,
                    self.rollback,
                    self.policy,
                    self.audit,
                    self.cost_paid,
                    self.shutdown,
                ]
                .into_iter()
                .all(|value| value.is_finite() && value >= 0.0)
            }

            pub fn ratio(&self) -> f64 {
                if !self.is_finite_nonnegative() {
                    return f64::INFINITY;
                }
                let numerator = self.gain
                    + self.risk
                    + self.uncertainty
                    + self.bridge_debt
                    + self.runtime_debt
                    + self.ontology_debt
                    + self.security_debt;
                let denominator = self.control
                    + self.verifier
                    + self.rollback
                    + self.policy
                    + self.audit
                    + self.cost_paid
                    + self.shutdown
                    + f64::EPSILON;
                numerator / denominator
            }
        }

