            #[test]
            fn artifact_registry_persists_and_rejects_tampering() {
                let path = temp_path("artifact-registry");
                let artifact =
                    certified_artifact(CandidateType::Code, BrtDeploymentStage::Sandbox, "deps-a");
                let mut registry = ArtifactRegistry::default();
                let id = registry.put(artifact).unwrap();
                registry.set_current("active", &id).unwrap();
                registry.save(&path).unwrap();

                let loaded = ArtifactRegistry::load(&path).unwrap();
                assert_eq!(loaded.current("active").unwrap().artifact_id, id);

                let mut snapshot: serde_json::Value =
                    serde_json::from_slice(&fs::read(&path).unwrap()).unwrap();
                snapshot["snapshot_hash"] = serde_json::json!(hash("tampered"));
                fs::write(&path, serde_json::to_vec_pretty(&snapshot).unwrap()).unwrap();
                assert!(ArtifactRegistry::load(&path).is_err());
                let _ = fs::remove_file(path);
            }

            #[test]
            fn dependency_drift_revokes_artifacts_and_current_pointer() {
                let mut registry = ArtifactRegistry::default();
                let id = registry
                    .put(certified_artifact(
                        CandidateType::Code,
                        BrtDeploymentStage::Sandbox,
                        "deps-old",
                    ))
                    .unwrap();
                registry.set_current("active", &id).unwrap();
                let revoked = registry.invalidate_dependency_drift(&hash("deps-new"));
                assert_eq!(revoked, vec![id.clone()]);
                assert!(registry.get(&id).unwrap().revoked);
                assert!(registry.current("active").is_none());
            }

            #[test]
