            #[test]
            fn ontology_promotion_detects_conflicts_and_rolls_back() {
                let artifact = certified_artifact(
                    CandidateType::OntologyLift,
                    BrtDeploymentStage::Replay,
                    "deps",
                );
                let mut registry = OntologyRegistry::default();
                let base = OntologyVersion {
                    ontology_id: "core".into(),
                    version_hash: String::new(),
                    parent_hash: None,
                    types: BTreeSet::from(["Claim".into(), "Evidence".into()]),
                    relations: BTreeSet::from(["Claim->Evidence:supported_by".into()]),
                    constraints: BTreeSet::from(["allow:grounded_claim".into()]),
                    audit_hash: artifact.audit_hash.clone(),
                };
                let base_hash = registry.promote(&artifact, base).unwrap();
                let next = OntologyVersion {
                    ontology_id: "core".into(),
                    version_hash: String::new(),
                    parent_hash: Some(base_hash.clone()),
                    types: BTreeSet::from(["Claim".into(), "Evidence".into()]),
                    relations: BTreeSet::from(["Claim->Evidence:supported_by".into()]),
                    constraints: BTreeSet::from(["deny:ungrounded_claim".into()]),
                    audit_hash: artifact.audit_hash.clone(),
                };
                let next_hash = registry.promote(&artifact, next).unwrap();
                assert_eq!(registry.current("core").unwrap().version_hash, next_hash);
                assert_eq!(registry.rollback("core").unwrap(), base_hash);

                let conflicting = OntologyVersion {
                    ontology_id: "other".into(),
                    version_hash: String::new(),
                    parent_hash: None,
                    types: BTreeSet::from(["Claim".into()]),
                    relations: BTreeSet::from(["Claim->Claim:implies".into()]),
                    constraints: BTreeSet::from(["allow:x".into(), "deny:x".into()]),
                    audit_hash: artifact.audit_hash.clone(),
                };
                assert!(registry.promote(&artifact, conflicting).is_err());
            }

            #[test]
            fn deployment_is_adjacent_canaried_and_bounded_by_certificate() {
                let replay_artifact = certified_artifact(
                    CandidateType::Deployment,
                    BrtDeploymentStage::Replay,
                    "deps",
                );
                let mut controller = DeploymentController::default();
                assert!(controller
                    .stage(&replay_artifact, BrtDeploymentStage::Replay, true)
                    .is_err());
                assert!(controller
                    .stage(&replay_artifact, BrtDeploymentStage::Sandbox, true)
                    .is_ok());
                assert!(controller
                    .stage(&replay_artifact, BrtDeploymentStage::Replay, true)
                    .is_ok());
                assert!(controller
                    .stage(&replay_artifact, BrtDeploymentStage::Canary, true)
                    .is_err());

                let canary_artifact = certified_artifact(
                    CandidateType::Deployment,
                    BrtDeploymentStage::Canary,
                    "deps",
                );
                assert!(controller
                    .stage(&canary_artifact, BrtDeploymentStage::Sandbox, true)
                    .is_ok());
                assert!(controller
                    .stage(&canary_artifact, BrtDeploymentStage::Replay, true)
                    .is_ok());
                assert!(controller
                    .stage(&canary_artifact, BrtDeploymentStage::Canary, false)
                    .is_err());
                assert!(controller
                    .stage(&canary_artifact, BrtDeploymentStage::Canary, true)
                    .is_ok());
            }

