    #[derive(Debug, Clone, Copy, Default, PartialEq, Eq, Hash, Serialize, Deserialize)]
    #[repr(u8)]
    pub enum DeploymentStage {
        #[default]
        Draft = 0,
        IRValid = 1,
        Compiled = 2,
        Sandboxed = 3,
        Evaluated = 4,
        Verified = 5,
        Governed = 6,
        Shadow = 7,
        Canary = 8,
        LimitedLive = 9,
        Live = 10,
    }

    impl DeploymentStage {
        const ALL: [Self; 11] = [
            Self::Draft,
            Self::IRValid,
            Self::Compiled,
            Self::Sandboxed,
            Self::Evaluated,
            Self::Verified,
            Self::Governed,
            Self::Shadow,
            Self::Canary,
            Self::LimitedLive,
            Self::Live,
        ];
        const NAMES: [&'static str; 11] = [
            "Draft",
            "IRValid",
            "Compiled",
            "Sandboxed",
            "Evaluated",
            "Verified",
            "Governed",
            "Shadow",
            "Canary",
            "LimitedLive",
            "Live",
        ];
        pub fn ordinal(self) -> u8 {
            self as u8
        }
        pub fn can_promote_to(self, target: Self) -> bool {
            target.ordinal() == self.ordinal() + 1
        }
        pub fn next(self) -> Option<Self> {
            Self::from_ordinal(self.ordinal() + 1)
        }
        pub fn from_ordinal(v: u8) -> Option<Self> {
            Self::ALL.get(v as usize).copied()
        }

        pub fn as_str(self) -> &'static str {
            Self::NAMES[self as usize]
        }
    }
    impl fmt::Display for DeploymentStage {
        fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
            f.write_str(self.as_str())
        }
    }

