    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct PolicyIR {
        pub allow: Vec<String>,
        pub deny: Vec<String>,
        pub approval_required: Vec<String>,
        pub max_risk: f64,
        pub risk_class: String,
        pub approved_external_side_effects: bool,
    }
    impl PolicyIR {
        pub fn legal(&self, required_caps: &[&str]) -> (bool, Vec<String>) {
            let allow: HashSet<&str> = self.allow.iter().map(|s| s.as_str()).collect();
            let deny: HashSet<&str> = self.deny.iter().map(|s| s.as_str()).collect();
            let mut reasons = Vec::new();
            let missing: Vec<_> = required_caps
                .iter()
                .filter(|c| !allow.contains(**c))
                .copied()
                .collect();
            let denied: Vec<_> = required_caps
                .iter()
                .filter(|c| deny.contains(**c))
                .copied()
                .collect();
            if !missing.is_empty() {
                reasons.push(format!("missing_allowed_caps={}", missing.join(",")));
            }
            if !denied.is_empty() {
                reasons.push(format!("denied_caps={}", denied.join(",")));
            }
            if !self.approval_required.is_empty() && !self.approved_external_side_effects {
                reasons.push(format!(
                    "approval_required={}",
                    self.approval_required.join(",")
                ));
            }
            (reasons.is_empty(), reasons)
        }
    }
