    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct CompilerNativeGraph {
        pub name: String,
        pub domain: String,
        pub ops: Vec<CompilerNativeOp>,
        pub contracts: InterfaceContracts,
        pub metadata: HashMap<String, serde_json::Value>,
    }
    impl CompilerNativeGraph {
        pub fn from_domain_ir(ir: &DomainIR) -> Self {
            let ops = ir
                .operations
                .iter()
                .enumerate()
                .map(|(idx, attrs)| {
                    let name = attrs
                        .get("op")
                        .or_else(|| attrs.get("name"))
                        .and_then(|v| v.as_str())
                        .unwrap_or("operation")
                        .to_string();
                    let dialect = attrs
                        .get("dialect")
                        .and_then(|v| v.as_str())
                        .unwrap_or("domain")
                        .to_string();
                    CompilerNativeOp {
                        dialect,
                        name: format!("{}#{}", name, idx),
                        inputs: vec![],
                        outputs: vec![CompilerNativeValue::new(
                            format!("{}_out", idx),
                            attrs
                                .get("output_type")
                                .and_then(|v| v.as_str())
                                .unwrap_or("i64"),
                            vec![],
                            attrs
                                .get("result")
                                .cloned()
                                .unwrap_or(serde_json::Value::Null),
                        )],
                        attrs: attrs.clone(),
                        proof_obligations: vec![
                            "deterministic_lowering".into(),
                            "bounded_effects".into(),
                        ],
                    }
                })
                .collect();
            Self {
                name: format!("{}::{}", ir.domain, ir.task),
                domain: ir.domain.clone(),
                ops,
                contracts: build_interface_contracts(),
                metadata: HashMap::from([
                    (
                        "mlir_text_hash".into(),
                        serde_json::json!(stable_json_hash(&serde_json::json!(ir.mlir_text))),
                    ),
                    ("constraints".into(), serde_json::json!(ir.constraints)),
                ]),
            }
        }
        pub fn add_op(&mut self, op: CompilerNativeOp) {
            self.ops.push(op);
        }
        pub fn verify(&self) -> (bool, Vec<String>) {
            let mut errors = Vec::new();
            if self.name.trim().is_empty() {
                errors.push("graph_name_empty".into());
            }
            if self.ops.is_empty() {
                errors.push("graph_has_no_ops".into());
            }
            for op in &self.ops {
                if op.name.trim().is_empty() {
                    errors.push("op_name_empty".into());
                }
                if !JARVIS_LOWERING_DIALECTS.contains(&op.dialect.as_str()) {
                    errors.push(format!("unsupported_dialect={}", op.dialect));
                }
            }
            (errors.is_empty(), errors)
        }
        pub fn mlir_text(&self) -> String {
            let mut text = format!(
                "jarvis.module @{} attributes {{domain = \"{}\"}} {{\n",
                self.name, self.domain
            );
            for op in &self.ops {
                let attrs = serde_json::to_string(&op.attrs).unwrap_or_else(|_| "{}".into());
                text.push_str(&format!(
                    "  jarvis.{} @{} attrs {}\n",
                    op.dialect, op.name, attrs
                ));
            }
            text.push_str("}\n");
            text
        }
        pub fn to_value(&self) -> serde_json::Value {
            serde_json::json!({
                "name": self.name,
                "domain": self.domain,
                "ops": self.ops,
                "contracts": self.contracts,
                "metadata": self.metadata,
            })
        }
        pub fn artifact_hash(&self) -> String {
            stable_json_hash(&self.to_value())
        }
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct ConversionPattern {
        pub name: String,
        pub source: String,
        pub target: String,
        pub legality: String,
        pub proof_obligations: Vec<String>,
        pub risk_weight: f64,
    }
    impl ConversionPattern {
        pub fn matches(&self, op: &CompilerNativeOp) -> bool {
            op.dialect == self.source
        }
        pub fn rewrite(&self, op: &CompilerNativeOp) -> CompilerNativeOp {
            let mut next = op.clone();
            next.dialect = self.target.clone();
            next.attrs
                .insert("lowered_by".into(), serde_json::json!(self.name));
            next.attrs
                .insert("legality".into(), serde_json::json!(self.legality));
            for obligation in &self.proof_obligations {
                if !next.proof_obligations.contains(obligation) {
                    next.proof_obligations.push(obligation.clone());
                }
            }
            next
        }
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct LoweringSnapshot {
        pub level: String,
        pub graph_hash: String,
        pub op_count: usize,
        pub legal: bool,
        pub diagnostics: Vec<String>,
        pub mlir_text: String,
        #[serde(default)]
        pub elapsed_us: f64,
        #[serde(default)]
        pub rewrites_applied: usize,
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct ConversionPassManager {
        pub patterns: Vec<ConversionPattern>,
        pub levels: Vec<LoweringLevel>,
    }
    impl ConversionPassManager {
        pub fn os7_default() -> Self {
            Self {
                patterns: build_os7_conversion_patterns(),
                levels: LoweringLevel::all(),
            }
        }
        pub fn run(&self, graph: &mut CompilerNativeGraph) -> Vec<LoweringSnapshot> {
            let mut snapshots = Vec::new();
            for level in &self.levels {
                let t0 = std::time::Instant::now();
                let target = level.as_str();
                let mut rewrites_applied = 0usize;

                for pattern in self
                    .patterns
                    .iter()
                    .filter(|pattern| pattern.target == target)
                {
                    let mut rewritten = Vec::with_capacity(graph.ops.len());
                    for op in &graph.ops {
                        if pattern.matches(op) {
                            rewritten.push(pattern.rewrite(op));
                            rewrites_applied += 1;
                        } else {
                            rewritten.push(op.clone());
                        }
                    }
                    graph.ops = rewritten;
                }
                let (legal, mut diagnostics) = graph.verify();
                if graph.ops.is_empty() && !diagnostics.iter().any(|d| d.contains("no_ops")) {
                    diagnostics.push(format!("level_{}_produced_empty_graph", target));
                }

                let elapsed_us = t0.elapsed().as_micros() as f64;
                snapshots.push(LoweringSnapshot {
                    level: target.into(),
                    graph_hash: graph.artifact_hash(),
                    op_count: graph.ops.len(),
                    legal,
                    diagnostics,
                    mlir_text: graph.mlir_text(),
                    elapsed_us,
                    rewrites_applied,
                });
            }
            snapshots
        }
        pub fn pattern_summary(&self) -> Vec<HashMap<String, serde_json::Value>> {
            self.patterns
                .iter()
                .map(|p| {
                    HashMap::from([
                        ("name".into(), serde_json::json!(p.name)),
                        ("source".into(), serde_json::json!(p.source)),
                        ("target".into(), serde_json::json!(p.target)),
                        ("risk_weight".into(), serde_json::json!(p.risk_weight)),
                    ])
                })
                .collect()
        }
    }

