    #[derive(Debug, Clone)]
    pub struct DomainLowering {
        pub domain_ir: DomainIR,
        pub program: Vec<VMInstruction>,
        pub plugin_ok: bool,
        pub diagnostics: Vec<CompilerDiagnostic>,
        pub outputs: HashMap<String, serde_json::Value>,
    }

    pub type DomainPluginLowerer =
        fn(&str, &HashMap<String, serde_json::Value>) -> Option<DomainLowering>;

    #[derive(Clone)]
    pub struct DomainPlugin {
        pub domains: Vec<String>,
        pub lower: DomainPluginLowerer,
    }

    #[derive(Clone, Default)]
    pub struct DomainPluginRegistry {
        plugins: Vec<DomainPlugin>,
    }

    impl DomainPluginRegistry {
        pub fn new() -> Self {
            Self { plugins: vec![] }
        }

        pub fn with_plugin(mut self, domains: &[&str], lower: DomainPluginLowerer) -> Self {
            self.add_plugin(domains, lower);
            self
        }

        pub fn add_plugin(&mut self, domains: &[&str], lower: DomainPluginLowerer) {
            self.plugins.push(DomainPlugin {
                domains: domains.iter().map(|domain| (*domain).to_string()).collect(),
                lower,
            });
        }

        pub fn supported_domains(&self) -> Vec<String> {
            let mut domains = self
                .plugins
                .iter()
                .flat_map(|plugin| plugin.domains.iter().cloned())
                .collect::<Vec<_>>();
            domains.sort();
            domains.dedup();
            domains
        }

        pub fn is_supported(&self, full_domain: &str) -> bool {
            self.plugins
                .iter()
                .any(|plugin| plugin.domains.iter().any(|domain| domain == full_domain))
        }

        pub fn lower(
            &self,
            full_domain: &str,
            spec: &HashMap<String, serde_json::Value>,
        ) -> Option<DomainLowering> {
            for plugin in &self.plugins {
                if plugin.domains.iter().any(|domain| domain == full_domain) {
                    if let Some(lowering) = (plugin.lower)(full_domain, spec) {
                        return Some(lowering);
                    }
                }
            }
            None
        }
    }

    pub fn stable_json_hash(payload: &serde_json::Value) -> String {
        fn canonical(value: &serde_json::Value) -> String {
            match value {
                serde_json::Value::Null => "null".into(),
                serde_json::Value::Bool(v) => v.to_string(),
                serde_json::Value::Number(v) => v.to_string(),
                serde_json::Value::String(v) => serde_json::to_string(v).unwrap_or_default(),
                serde_json::Value::Array(values) => {
                    let inner = values.iter().map(canonical).collect::<Vec<_>>().join(",");
                    format!("[{}]", inner)
                }
                serde_json::Value::Object(map) => {
                    let mut keys = map.keys().collect::<Vec<_>>();
                    keys.sort();
                    let inner = keys
                        .iter()
                        .map(|key| {
                            let encoded_key = serde_json::to_string(*key).unwrap_or_default();
                            format!("{}:{}", encoded_key, canonical(&map[*key]))
                        })
                        .collect::<Vec<_>>()
                        .join(",");
                    format!("{{{}}}", inner)
                }
            }
        }
        let mut hasher = Sha256::new();
        hasher.update(canonical(payload).as_bytes());
        format!("{:x}", hasher.finalize())
    }

    fn runtime_timestamp() -> String {
        let secs = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .map(|duration| duration.as_secs())
            .unwrap_or(0);
        format!("unix:{}", secs)
    }

    fn split_memory_key(raw: &str) -> (String, String) {
        let mut parts = raw.splitn(2, '.');
        let namespace = parts.next().unwrap_or("memory");
        let key = parts.next().unwrap_or(raw);
        (
            if namespace.is_empty() {
                "memory".into()
            } else {
                namespace.into()
            },
            if key.is_empty() {
                raw.into()
            } else {
                key.into()
            },
        )
    }

    fn compiler_diag(
        stage: &str,
        level: &str,
        message: impl Into<String>,
        op: Option<String>,
        suggestion: Option<String>,
    ) -> CompilerDiagnostic {
        CompilerDiagnostic {
            stage: stage.into(),
            level: level.into(),
            message: message.into(),
            op,
            suggestion,
        }
    }

    fn compiler_pass(
        name: &str,
        ok: bool,
        diagnostics: Vec<CompilerDiagnostic>,
        artifact: serde_json::Value,
    ) -> CompilerPassLog {
        CompilerPassLog {
            name: name.into(),
            ok,
            elapsed_ms: 0.0,
            diagnostics,
            artifact_hash: Some(stable_json_hash(&artifact)),
        }
    }

    fn op_attrs(pairs: Vec<(&str, serde_json::Value)>) -> HashMap<String, serde_json::Value> {
        let mut attrs = HashMap::new();
        for (key, value) in pairs {
            attrs.insert(key.into(), value);
        }
        attrs
    }

    fn spec_value<'a>(
        spec: &'a HashMap<String, serde_json::Value>,
        key: &str,
    ) -> Option<&'a serde_json::Value> {
        spec.get(key)
            .or_else(|| spec.get("inputs").and_then(|v| v.get(key)))
            .or_else(|| spec.get("parameters").and_then(|v| v.get(key)))
            .or_else(|| spec.get("metadata").and_then(|v| v.get(key)))
    }

    fn json_string_from_spec(
        spec: &HashMap<String, serde_json::Value>,
        key: &str,
        default: &str,
    ) -> String {
        spec_value(spec, key)
            .and_then(|v| v.as_str())
            .unwrap_or(default)
            .to_string()
    }

    fn json_i64_from_spec(
        spec: &HashMap<String, serde_json::Value>,
        key: &str,
        default: i64,
    ) -> i64 {
        spec_value(spec, key)
            .and_then(|v| v.as_i64().or_else(|| v.as_f64().map(|x| x as i64)))
            .unwrap_or(default)
    }

    fn json_f64_from_spec(
        spec: &HashMap<String, serde_json::Value>,
        key: &str,
        default: f64,
    ) -> f64 {
        spec_value(spec, key)
            .and_then(|v| v.as_f64().or_else(|| v.as_i64().map(|x| x as f64)))
            .unwrap_or(default)
    }

    fn json_array_from_spec(
        spec: &HashMap<String, serde_json::Value>,
        key: &str,
    ) -> Vec<serde_json::Value> {
        spec_value(spec, key)
            .and_then(|v| v.as_array())
            .cloned()
            .unwrap_or_default()
    }

    fn json_string_list_from_value(value: &serde_json::Value) -> Vec<String> {
        match value {
            serde_json::Value::Array(items) => items
                .iter()
                .filter_map(|v| {
                    v.as_str()
                        .map(|s| s.to_string())
                        .or_else(|| v.as_i64().map(|n| n.to_string()))
                })
                .collect(),
            serde_json::Value::String(s) => vec![s.clone()],
            _ => vec![],
        }
    }

    fn normalize_domain_task(spec: &HashMap<String, serde_json::Value>) -> String {
        let domain = json_string_from_spec(spec, "domain", "unknown");
        if domain.contains('.') {
            return domain;
        }
        let task = spec_value(spec, "task")
            .or_else(|| spec_value(spec, "op"))
            .and_then(|v| v.as_str())
            .unwrap_or("");
        if task.is_empty() {
            domain
        } else {
            format!("{}.{}", domain, task)
        }
    }

    fn risk_class_score(risk_class: &str) -> f64 {
        match risk_class {
            "low" => 0.1,
            "medium" => 0.35,
            "high" => 0.7,
            "critical" => 1.0,
            _ => 0.25,
        }
    }

    fn vm_instr(op: VMOpcode, a: i64, b: i64, c: i64, imm: i64) -> VMInstruction {
        VMInstruction { op, a, b, c, imm }
    }

    fn emit_result_program(result: i64) -> Vec<VMInstruction> {
        vec![
            vm_instr(VMOpcode::MOV, 0, 0, 0, result),
            vm_instr(VMOpcode::HALT, 0, 0, 0, 0),
        ]
    }

    fn emit_binary_math_program(op: VMOpcode, a: i64, b: i64) -> Vec<VMInstruction> {
        vec![
            vm_instr(VMOpcode::MOV, 0, 0, 0, a),
            vm_instr(VMOpcode::MOV, 1, 0, 0, b),
            vm_instr(op, 0, 0, 1, 0),
            vm_instr(VMOpcode::HALT, 0, 0, 0, 0),
        ]
    }

    fn prove_program(program: &[VMInstruction]) -> VMExecutionProof {
        let (final_state, trace) = match vm_execute(program, None, 256, 16) {
            Ok(execution) => execution,
            Err(error) => {
                return VMExecutionProof {
                    ok: false,
                    residual: f64::INFINITY,
                    trace_hash: vm_hash_json(&serde_json::json!({
                        "program": program,
                        "execution_error": error,
                    })),
                    final_state_hash: String::new(),
                    public_output: None,
                    witness_rows: 0,
                    constraints: serde_json::json!({"ok": false, "execution_error": error}),
                    errors: vec![error],
                }
            }
        };
        let output = final_state.registers.first().copied();
        let et = ExecutionTrace {
            states: trace,
            program: program.to_vec(),
            input_vals: vec![],
            output,
        };
        et.prove()
    }

    fn lower_domain_plugin(
        full_domain: &str,
        spec: &HashMap<String, serde_json::Value>,
    ) -> Option<DomainLowering> {
        match full_domain {
            "math.add" | "math.sub" | "math.mul" => {
                let a = json_i64_from_spec(spec, "a", 0);
                let b = json_i64_from_spec(spec, "b", 0);
                let (op_name, opcode, expected) = match full_domain {
                    "math.add" => ("add", VMOpcode::ADD, a.wrapping_add(b)),
                    "math.sub" => ("sub", VMOpcode::SUB, a.wrapping_sub(b)),
                    _ => ("mul", VMOpcode::MUL, a.wrapping_mul(b)),
                };
                let program = emit_binary_math_program(opcode, a, b);
                let ir = DomainIR {
                    domain: "math".into(),
                    task: op_name.into(),
                    operations: vec![op_attrs(vec![
                        ("dialect", serde_json::json!("domain")),
                        ("op", serde_json::json!(format!("math.{}", op_name))),
                        ("a", serde_json::json!(a)),
                        ("b", serde_json::json!(b)),
                        ("result", serde_json::json!(expected & vm_word_mask(32))),
                        ("output_type", serde_json::json!("i64")),
                    ])],
                    constraints: vec!["word_size=32".into(), "public_output_register=r0".into()],
                    mlir_text: format!(
                    "jarvis.domain @math.{} {{\n  %0 = math.{} {}, {}\n  jarvis.return %0\n}}\n",
                    op_name, op_name, a, b
                ),
                };
                Some(DomainLowering {
                    domain_ir: ir,
                    program,
                    plugin_ok: true,
                    diagnostics: vec![],
                    outputs: HashMap::from([
                        (
                            "expected_result".into(),
                            serde_json::json!(expected & vm_word_mask(32)),
                        ),
                        ("word_size".into(), serde_json::json!(32)),
                    ]),
                })
            }
            "software.workflow" => {
                let steps = json_array_from_spec(spec, "steps");
                let mut ids = HashSet::new();
                for (idx, step) in steps.iter().enumerate() {
                    let id = step
                        .get("id")
                        .and_then(|v| v.as_str())
                        .map(|s| s.to_string())
                        .or_else(|| step.as_str().map(|s| s.to_string()))
                        .unwrap_or_else(|| format!("step_{}", idx));
                    ids.insert(id);
                }
                let mut dependency_errors = Vec::new();
                let mut operations = Vec::new();
                for (idx, step) in steps.iter().enumerate() {
                    let id = step
                        .get("id")
                        .and_then(|v| v.as_str())
                        .map(|s| s.to_string())
                        .or_else(|| step.as_str().map(|s| s.to_string()))
                        .unwrap_or_else(|| format!("step_{}", idx));
                    let deps = step
                        .get("deps")
                        .or_else(|| step.get("dependencies"))
                        .map(json_string_list_from_value)
                        .unwrap_or_default();
                    for dep in &deps {
                        if dep == &id {
                            dependency_errors.push(format!("self_dependency={}", id));
                        }
                        if !ids.contains(dep) {
                            dependency_errors.push(format!("missing_dependency={}->{}", id, dep));
                        }
                    }
                    operations.push(op_attrs(vec![
                        ("dialect", serde_json::json!("domain")),
                        ("op", serde_json::json!("workflow.step")),
                        ("id", serde_json::json!(id)),
                        ("dependencies", serde_json::json!(deps)),
                        ("result", serde_json::json!(1)),
                        ("output_type", serde_json::json!("i1")),
                    ]));
                }
                let plugin_ok = !steps.is_empty() && dependency_errors.is_empty();
                let program = emit_result_program(if plugin_ok { 1 } else { 0 });
                let ir = DomainIR {
                    domain: "software".into(),
                    task: "workflow".into(),
                    operations,
                    constraints: vec!["dependency_closure".into(), "bounded_side_effects".into()],
                    mlir_text: format!(
                    "jarvis.domain @software.workflow {{\n  // steps={} dependency_errors={}\n}}\n",
                    steps.len(),
                    dependency_errors.len()
                ),
                };
                let diagnostics = dependency_errors
                    .iter()
                    .map(|err| {
                        compiler_diag(
                            "domain_plugin",
                            "error",
                            err.clone(),
                            Some("workflow.step".into()),
                            Some("fix workflow dependencies".into()),
                        )
                    })
                    .collect();
                Some(DomainLowering {
                    domain_ir: ir,
                    program,
                    plugin_ok,
                    diagnostics,
                    outputs: HashMap::from([
                        ("step_count".into(), serde_json::json!(steps.len())),
                        (
                            "dependency_errors".into(),
                            serde_json::json!(dependency_errors),
                        ),
                        ("valid".into(), serde_json::json!(plugin_ok)),
                    ]),
                })
            }
            "research.note" => {
                let claims = json_array_from_spec(spec, "claims");
                let sources = json_array_from_spec(spec, "sources");
                let min_support = json_f64_from_spec(spec, "min_support", 0.5).clamp(0.0, 1.0);
                let mut supported = 0usize;
                for claim in &claims {
                    let claim_sources = claim
                        .get("sources")
                        .or_else(|| claim.get("source_ids"))
                        .map(json_string_list_from_value)
                        .unwrap_or_default();
                    if !claim_sources.is_empty() || !sources.is_empty() {
                        supported += 1;
                    }
                }
                let support_score = if claims.is_empty() {
                    0.0
                } else {
                    supported as f64 / claims.len() as f64
                };
                let plugin_ok = !claims.is_empty() && support_score >= min_support;
                let scaled = (support_score * 1000.0).round() as i64;
                let program = emit_result_program(scaled);
                let operations = claims
                    .iter()
                    .enumerate()
                    .map(|(idx, claim)| {
                        op_attrs(vec![
                            ("dialect", serde_json::json!("domain")),
                            ("op", serde_json::json!("research.claim")),
                            (
                                "id",
                                serde_json::json!(claim
                                    .get("id")
                                    .and_then(|v| v.as_str())
                                    .unwrap_or("claim")),
                            ),
                            ("index", serde_json::json!(idx)),
                            ("result", serde_json::json!(support_score)),
                            ("output_type", serde_json::json!("f64")),
                        ])
                    })
                    .collect::<Vec<_>>();
                let ir = DomainIR {
                domain: "research".into(),
                task: "note".into(),
                operations,
                constraints: vec!["claim_requires_evidence".into(), "contradiction_budget<=0.25".into()],
                mlir_text: format!(
                    "jarvis.domain @research.note {{\n  // claims={} sources={} support={:.3}\n}}\n",
                    claims.len(), sources.len(), support_score
                ),
            };
                let diagnostics = if plugin_ok {
                    vec![]
                } else {
                    vec![compiler_diag(
                        "domain_plugin",
                        "warning",
                        format!(
                            "claim_support_score={:.3} below threshold={:.3}",
                            support_score, min_support
                        ),
                        Some("research.claim".into()),
                        Some("attach sources to each claim".into()),
                    )]
                };
                Some(DomainLowering {
                    domain_ir: ir,
                    program,
                    plugin_ok,
                    diagnostics,
                    outputs: HashMap::from([
                        ("claim_count".into(), serde_json::json!(claims.len())),
                        ("source_count".into(), serde_json::json!(sources.len())),
                        ("support_score".into(), serde_json::json!(support_score)),
                        ("min_support".into(), serde_json::json!(min_support)),
                    ]),
                })
            }
            "security.audit" => {
                let findings = json_array_from_spec(spec, "findings");
                let max_risk = json_f64_from_spec(spec, "max_risk", 0.45).clamp(0.0, 1.0);
                let mut risk_total = 0.0;
                let mut critical_count = 0usize;
                let mut operations = Vec::new();
                for (idx, finding) in findings.iter().enumerate() {
                    let severity = finding
                        .get("severity")
                        .and_then(|v| v.as_str())
                        .unwrap_or("low");
                    let weight = match severity {
                        "critical" => {
                            critical_count += 1;
                            1.0
                        }
                        "high" => 0.7,
                        "medium" => 0.4,
                        "low" => 0.15,
                        _ => 0.25,
                    };
                    risk_total += weight;
                    operations.push(op_attrs(vec![
                        ("dialect", serde_json::json!("domain")),
                        ("op", serde_json::json!("security.finding")),
                        ("index", serde_json::json!(idx)),
                        ("severity", serde_json::json!(severity)),
                        ("risk_weight", serde_json::json!(weight)),
                        ("result", serde_json::json!(weight)),
                        ("output_type", serde_json::json!("f64")),
                    ]));
                }
                let normalized_risk = if findings.is_empty() {
                    0.0
                } else {
                    (risk_total / findings.len() as f64).clamp(0.0, 1.0)
                };
                let plugin_ok = normalized_risk <= max_risk && critical_count == 0;
                let program = emit_result_program(if plugin_ok { 1 } else { 0 });
                let ir = DomainIR {
                    domain: "security".into(),
                    task: "audit".into(),
                    operations,
                    constraints: vec![
                        "deny_critical_findings".into(),
                        "risk_score<=max_risk".into(),
                    ],
                    mlir_text: format!(
                    "jarvis.domain @security.audit {{\n  // findings={} risk={:.3} max={:.3}\n}}\n",
                    findings.len(), normalized_risk, max_risk
                ),
                };
                let diagnostics = if plugin_ok {
                    vec![]
                } else {
                    vec![compiler_diag(
                        "domain_plugin",
                        "error",
                        format!(
                            "security risk {:.3} exceeds policy or has critical findings={}",
                            normalized_risk, critical_count
                        ),
                        Some("security.finding".into()),
                        Some("mitigate high-risk findings before approval".into()),
                    )]
                };
                Some(DomainLowering {
                    domain_ir: ir,
                    program,
                    plugin_ok,
                    diagnostics,
                    outputs: HashMap::from([
                        ("finding_count".into(), serde_json::json!(findings.len())),
                        ("normalized_risk".into(), serde_json::json!(normalized_risk)),
                        ("critical_count".into(), serde_json::json!(critical_count)),
                        ("approved".into(), serde_json::json!(plugin_ok)),
                    ]),
                })
            }
            _ => None,
        }
    }

