    pub fn build_compiler_native_symbol_map() -> HashMap<String, serde_json::Value> {
        let domains = JARVIS_SUPPORTED_DOMAINS
            .iter()
            .map(|domain| (*domain).to_string())
            .collect::<Vec<_>>();
        build_compiler_native_symbol_map_for_domains(&domains)
    }

    fn validate_compile_spec(
        spec: &HashMap<String, serde_json::Value>,
    ) -> (String, Vec<CompilerDiagnostic>) {
        let supported_domains = JARVIS_SUPPORTED_DOMAINS
            .iter()
            .map(|domain| (*domain).to_string())
            .collect::<Vec<_>>();
        validate_compile_spec_against(spec, &supported_domains)
    }

    fn supported_domains_with_plugins(
        plugin_registry: Option<&DomainPluginRegistry>,
    ) -> Vec<String> {
        let mut domains = JARVIS_SUPPORTED_DOMAINS
            .iter()
            .map(|domain| (*domain).to_string())
            .collect::<Vec<_>>();
        if let Some(registry) = plugin_registry {
            domains.extend(registry.supported_domains());
        }
        domains.sort();
        domains.dedup();
        domains
    }

    fn validate_compile_spec_against(
        spec: &HashMap<String, serde_json::Value>,
        supported_domains: &[String],
    ) -> (String, Vec<CompilerDiagnostic>) {
        let full_domain = normalize_domain_task(spec);
        let mut diags = Vec::new();
        if full_domain.is_empty() || full_domain == "unknown" {
            diags.push(compiler_diag(
                "parse",
                "error",
                "missing or empty 'domain' field in spec",
                None,
                Some(format!("supported: {}", supported_domains.join(", "))),
            ));
        }
        if !supported_domains
            .iter()
            .any(|domain| domain == &full_domain)
            && !full_domain.is_empty()
        {
            diags.push(compiler_diag(
                "parse",
                "error",
                format!("unsupported domain '{}'", full_domain),
                None,
                Some(format!("supported: {}", supported_domains.join(", "))),
            ));
        }

        let mut typed_error = |message: String, suggestion: &str| {
            diags.push(compiler_diag(
                "type",
                "error",
                message,
                Some(full_domain.clone()),
                Some(suggestion.into()),
            ));
        };
        match full_domain.as_str() {
        "math.add" | "math.sub" | "math.mul" => {
            for field in ["a", "b"] {
                if spec_value(spec, field)
                    .and_then(|value| value.as_i64())
                    .is_none()
                {
                    typed_error(
                        format!("field '{}' must be a signed integer", field),
                        "provide an exact JSON integer; implicit coercion is forbidden",
                    );
                }
            }
        }
        "software.workflow" => {
            if spec_value(spec, "steps")
                .and_then(|value| value.as_array())
                .map(|steps| steps.is_empty())
                .unwrap_or(true)
            {
                typed_error(
                    "software.workflow requires a non-empty steps array".into(),
                    "provide typed workflow steps",
                );
            }
        }
        "research.note" => typed_error(
            "legacy research.note cannot certify truth without a BRT V11 evidence/source bridge"
                .into(),
            "use brt-compile with content-addressed evidence and independent validation",
        ),
        "security.audit"
            if spec_value(spec, "findings")
                .and_then(|value| value.as_array())
                .map(|findings| findings.is_empty())
                .unwrap_or(true) =>
        {
            typed_error(
                "security.audit requires a non-empty findings array".into(),
                "supply independently collected findings",
            );
        }
        "security.audit" => {}
        _ => {}
    }
        if let Some(risk_class) = spec_value(spec, "risk_class").and_then(|value| value.as_str()) {
            if !matches!(risk_class, "low" | "medium" | "high" | "critical") {
                typed_error(
                    format!("unsupported risk_class {:?}", risk_class),
                    "use low, medium, high, or critical",
                );
            }
        }

        (full_domain, diags)
    }

    fn domain_permissions(full_domain: &str, risk_class: &str) -> Vec<String> {
        let mut permissions = vec!["compile".into(), "prove".into(), "read_memory".into()];
        if full_domain.starts_with("math.") {
            permissions.push("execute.vm.math".into());
        } else if full_domain.starts_with("software.") {
            permissions.push("plan.workflow".into());
        } else if full_domain.starts_with("research.") {
            permissions.push("write.research_evidence".into());
        } else if full_domain.starts_with("security.") {
            permissions.push("write.audit".into());
        } else {
            permissions.push(format!("domain.{}", full_domain.replace('.', "_")));
        }
        if matches!(risk_class, "high" | "critical") {
            permissions.push("approval.required".into());
        }
        permissions.sort();
        permissions.dedup();
        permissions
    }

    fn memory_ir_for_domain(
        full_domain: &str,
        spec: &HashMap<String, serde_json::Value>,
    ) -> MemoryIR {
        let domain = full_domain.split('.').next().unwrap_or("unknown");
        let goal = json_string_from_spec(spec, "goal", "compiler_native_goal");
        let proof_key = stable_json_hash(&serde_json::json!({"domain": full_domain, "goal": goal}));
        MemoryIR {
            reads: vec![
                format!("registry.{}", domain),
                "policy.compiler_native_v7".into(),
            ],
            writes: vec![
                format!("skill.{}", full_domain.replace('.', "_")),
                format!("proof.{}", &proof_key[..12]),
            ],
        }
    }

    fn proof_ir_for_domain(
        full_domain: &str,
        snapshots: &[LoweringSnapshot],
        proof: Option<&VMExecutionProof>,
    ) -> ProofIR {
        let mut obligations = vec![
            "transition_validity".into(),
            "memory_consistency".into(),
            "opcode_dispatch_validity".into(),
            "final_output_validity".into(),
            "policy_compliance".into(),
            "mlir_bundle_hash_stable".into(),
        ];
        for snapshot in snapshots {
            obligations.push(format!("lowering_level_{}", snapshot.level));
        }
        obligations.sort();
        obligations.dedup();

        ProofIR {
            obligations,
            thresholds: HashMap::from([
                ("air_residual".into(), 1e-6),
                (
                    "max_risk".into(),
                    if full_domain.starts_with("security.") {
                        0.45
                    } else {
                        0.7
                    },
                ),
                (
                    "observed_residual".into(),
                    proof.map(|p| p.residual).unwrap_or(f64::INFINITY),
                ),
            ]),
            backends: vec![
                "rust-vm-air".into(),
                "memory-consistency".into(),
                "dispatch-preflight".into(),
                "mlir-source-bundle".into(),
            ],
        }
    }

    fn skill_package_for_report(
        full_domain: &str,
        spec: &HashMap<String, serde_json::Value>,
        program: &[VMInstruction],
        proof: Option<&VMExecutionProof>,
        proof_ir: &ProofIR,
        mlir_bundle_hash: &str,
        compile_status: &str,
    ) -> SkillPackage {
        let risk_default = json_string_from_spec(spec, "risk", "low");
        let risk_class = json_string_from_spec(spec, "risk_class", &risk_default);
        let intent_hash = stable_json_hash(&serde_json::json!({
            "domain": full_domain,
            "spec": spec,
            "version": JARVIS_COMPILER_NATIVE_VERSION,
        }));
        let bytecode_hash = stable_json_hash(&serde_json::json!(program));
        let proof_hash = proof
            .map(|p| stable_json_hash(&serde_json::json!(p)))
            .unwrap_or_else(|| {
                stable_json_hash(&serde_json::json!({"missing": true, "domain": full_domain}))
            });
        let skill_id = format!(
            "skill.{}.{}",
            full_domain.replace('.', "_"),
            &intent_hash[..12]
        );
        let status = if compile_status == "legacy_consistency_checked" {
            "research_only"
        } else {
            "needs_review"
        };
        SkillPackage {
            skill_id,
            version: "v7-rust".into(),
            intent_hash,
            bytecode_hash,
            proof_hash,
            risk_class: risk_class.clone(),
            permissions: domain_permissions(full_domain, &risk_class),
            status: status.into(),
            program: program.to_vec(),
            proof_obligations: proof_ir.obligations.clone(),
            metadata: HashMap::from([
                (
                    "compiler_native_version".into(),
                    serde_json::json!(JARVIS_COMPILER_NATIVE_VERSION),
                ),
                (
                    "driver".into(),
                    serde_json::json!("CompilerNativeDriverV7Rust"),
                ),
                (
                    "mlir_bundle_hash".into(),
                    serde_json::json!(mlir_bundle_hash),
                ),
                (
                    "active_compiler_driver".into(),
                    serde_json::json!("CompilerNativeDriverV7Rust"),
                ),
                (
                    "proof_summary_v7".into(),
                    serde_json::json!({
                        "proof_ok": proof.map(|p| p.ok).unwrap_or(false),
                        "residual": proof.map(|p| p.residual).unwrap_or(f64::INFINITY),
                        "witness_rows": proof.map(|p| p.witness_rows).unwrap_or(0),
                    }),
                ),
                (
                    "risk_score".into(),
                    serde_json::json!(risk_class_score(&risk_class)),
                ),
            ]),
            tags: vec![
                "compiler-native-os7".into(),
                "mlir-lowering-driver".into(),
                "rust-runtime-registry".into(),
            ],
        }
    }

    fn unsupported_domain_lowering(
        full_domain: &str,
        supported_domains: &[String],
    ) -> DomainLowering {
        DomainLowering {
            domain_ir: DomainIR {
                domain: full_domain.split('.').next().unwrap_or("unknown").into(),
                task: full_domain.split('.').nth(1).unwrap_or("unknown").into(),
                operations: vec![],
                constraints: vec![],
                mlir_text: String::new(),
            },
            program: vec![],
            plugin_ok: false,
            diagnostics: vec![compiler_diag(
                "parse",
                "error",
                format!("unsupported domain '{}'", full_domain),
                None,
                Some(format!(
                    "supported domains: {}",
                    supported_domains.join(", ")
                )),
            )],
            outputs: HashMap::new(),
        }
    }

    pub fn compile_domain_spec(spec: &HashMap<String, serde_json::Value>) -> UnifiedProofReport {
        compile_domain_spec_with_plugins(spec, None)
    }

    pub fn compile_domain_spec_typed(spec: &CompileSpec) -> FrameworkResult<UnifiedProofReport> {
        JarvisProductionFramework::new().try_compile_spec(spec)
    }

    pub fn compile_domain_spec_with_plugins(
        spec: &HashMap<String, serde_json::Value>,
        plugin_registry: Option<&DomainPluginRegistry>,
    ) -> UnifiedProofReport {
        let supported_domains = supported_domains_with_plugins(plugin_registry);
        let (full_domain, validation_diags) =
            validate_compile_spec_against(spec, &supported_domains);
        let manifest = build_compiler_native_manifest_with_plugins(plugin_registry);
        let mut pass_log = Vec::new();
        let mut diagnostics = Vec::new();
        let mut plugin_outputs = HashMap::new();
        let mut lowering_snapshots = Vec::new();
        let mut program = Vec::new();
        let mut vm_proof = None;
        let mut domain_ir = None;
        let mut mlir_bundle_hash = stable_json_hash(&serde_json::json!({ "domain": full_domain }));

        let parse_ok = validation_diags.is_empty();
        diagnostics.extend(validation_diags.clone());
        pass_log.push(compiler_pass(
            "ParseDomainSpec",
            parse_ok,
            validation_diags,
            serde_json::json!({ "domain": full_domain, "spec": spec }),
        ));

        let compilation = lower_domain_plugin(&full_domain, spec)
            .or_else(|| plugin_registry.and_then(|registry| registry.lower(&full_domain, spec)))
            .unwrap_or_else(|| unsupported_domain_lowering(&full_domain, &supported_domains));
        diagnostics.extend(compilation.diagnostics.clone());
        plugin_outputs.extend(compilation.outputs.clone());

        if !compilation.program.is_empty() {
            program = compilation.program.clone();
            domain_ir = Some(compilation.domain_ir.clone());
            pass_log.push(compiler_pass(
                "LowerDomainPlugin",
                compilation.plugin_ok,
                compilation.diagnostics.clone(),
                serde_json::json!({
                    "domain_ir": compilation.domain_ir,
                    "outputs": compilation.outputs,
                }),
            ));

            let mut graph = CompilerNativeGraph::from_domain_ir(domain_ir.as_ref().unwrap());
            let pass_manager = ConversionPassManager::os7_default();
            lowering_snapshots = pass_manager.run(&mut graph);
            mlir_bundle_hash = graph.artifact_hash();
            let lowering_ok = lowering_snapshots.iter().all(|snapshot| snapshot.legal);
            pass_log.push(compiler_pass(
                "OS7LoweringPipeline",
                lowering_ok,
                lowering_snapshots
                    .iter()
                    .flat_map(|snapshot| {
                        snapshot
                            .diagnostics
                            .iter()
                            .map(|diag| {
                                compiler_diag(
                                    "lowering",
                                    "error",
                                    diag.clone(),
                                    Some(snapshot.level.clone()),
                                    Some("repair illegal lowering dialect or empty graph".into()),
                                )
                            })
                            .collect::<Vec<_>>()
                    })
                    .collect(),
                serde_json::json!({
                    "graph_hash": mlir_bundle_hash,
                    "snapshots": lowering_snapshots,
                }),
            ));

            vm_proof = Some(prove_program(&program));
            let proof_ok = vm_proof.as_ref().map(|proof| proof.ok).unwrap_or(false);
            pass_log.push(compiler_pass(
                "EmitVMBytecodeAndAIRProof",
                proof_ok,
                vec![],
                serde_json::json!({
                    "program": program,
                    "proof": vm_proof,
                }),
            ));
        } else {
            diagnostics.extend(compilation.diagnostics.clone());
            pass_log.push(compiler_pass(
                "LowerDomainPlugin",
                false,
                compilation.diagnostics.clone(),
                serde_json::json!({ "domain": full_domain }),
            ));
        }

        let proof_ok = vm_proof.as_ref().map(|proof| proof.ok).unwrap_or(false);
        let lowering_ok = lowering_snapshots.iter().all(|snapshot| snapshot.legal);
        let ok = compilation.plugin_ok
            && proof_ok
            && lowering_ok
            && diagnostics.iter().all(|d| d.level != "error");
        let compile_status = if ok {
            "legacy_consistency_checked"
        } else if proof_ok {
            "compiled_with_policy_findings"
        } else {
            "failed"
        }
        .to_string();
        let memory_ir = if !program.is_empty() {
            Some(memory_ir_for_domain(&full_domain, spec))
        } else {
            None
        };
        let proof_ir = if !program.is_empty() {
            Some(proof_ir_for_domain(
                &full_domain,
                &lowering_snapshots,
                vm_proof.as_ref(),
            ))
        } else {
            None
        };
        let skill_package = proof_ir.as_ref().map(|proof_ir| {
            skill_package_for_report(
                &full_domain,
                spec,
                &program,
                vm_proof.as_ref(),
                proof_ir,
                &mlir_bundle_hash,
                &compile_status,
            )
        });

        UnifiedProofReport {
            ok,
            compile_status,
            version: JARVIS_COMPILER_NATIVE_VERSION.into(),
            pass_log,
            diagnostics,
            program,
            vm_proof,
            manifest,
            domain_ir,
            lowering_snapshots,
            plugin_outputs,
            mlir_bundle_hash,
            skill_package,
            memory_ir,
            proof_ir,
            runtime_registry: None,
            scheduler_process: None,
        }
    }

    pub fn compile_domain_spec_with_runtime(
        spec: &HashMap<String, serde_json::Value>,
        registry_path: Option<&str>,
    ) -> UnifiedProofReport {
        compile_domain_spec_with_runtime_and_plugins(spec, registry_path, None)
    }

    pub fn compile_domain_spec_with_runtime_and_plugins(
        spec: &HashMap<String, serde_json::Value>,
        registry_path: Option<&str>,
        plugin_registry: Option<&DomainPluginRegistry>,
    ) -> UnifiedProofReport {
        let mut report = compile_domain_spec_with_plugins(spec, plugin_registry);
        let mut registry = match CompilerNativeRuntimeRegistry::open(registry_path) {
            Ok(registry) => registry,
            Err(error) => {
                report.ok = false;
                report.compile_status = "runtime_registry_open_failed".into();
                report.diagnostics.push(compiler_diag(
                    "runtime_registry",
                    "error",
                    format!("failed to open runtime registry: {}", error),
                    None,
                    Some("repair or explicitly replace the invalid registry".into()),
                ));
                return report;
            }
        };
        registry.save_report(&report);
        if report.skill_package.is_some() {
            report.scheduler_process = registry.enqueue_report(&report, 1, 0, Vec::new());
        }
        registry.snapshot.readiness_audits.push(serde_json::json!({
            "ok": report.ok,
            "compile_status": &report.compile_status,
            "mlir_bundle_hash": &report.mlir_bundle_hash,
            "lowering_ok": report.lowering_snapshots.iter().all(|s| s.legal),
            "created_at": runtime_timestamp(),
        }));
        if let Err(err) = registry.persist() {
            report.ok = false;
            report.compile_status = "runtime_registry_persist_failed".into();
            report.diagnostics.push(compiler_diag(
                "runtime_registry",
                "error",
                format!("failed to persist runtime registry: {}", err),
                None,
                Some("check registry path permissions and free space".into()),
            ));
        }
        report.runtime_registry = Some(registry.snapshot.clone());
        report
    }

    pub fn build_compiler_native_runtime_audit_report(
        registry_path: Option<&str>,
    ) -> serde_json::Value {
        let (mut registry, registry_open_error) =
            match CompilerNativeRuntimeRegistry::open(registry_path) {
                Ok(registry) => (registry, None),
                Err(error) => (
                    CompilerNativeRuntimeRegistry {
                        path: None,
                        snapshot: CompilerNativeRegistrySnapshot::empty(None),
                    },
                    Some(error.to_string()),
                ),
            };
        let health = registry.health();
        let manifest = build_compiler_native_manifest();
        let plugin_health_ok = manifest
            .get("domain_plugin_health")
            .and_then(|v| v.as_array())
            .map(|items| !items.is_empty())
            .unwrap_or(false);
        let persisted = registry_path.is_some() && registry_open_error.is_none();
        let replay_ok = false;
        let provenance_ok = false;
        let tamper_evidence_ok = false;
        let ok = persisted && replay_ok && provenance_ok && tamper_evidence_ok;
        serde_json::json!({
            "ok": ok,
            "authority": "legacy_inventory_only",
            "production_authority": false,
            "registry_open_error": registry_open_error,
            "version": JARVIS_COMPILER_NATIVE_VERSION,
            "display_name": JARVIS_DISPLAY_NAME,
            "active_compiler_driver": "CompilerNativeDriverV7Rust",
            "plugin_inventory_present": plugin_health_ok,
            "registry_health": health,
            "manifest": manifest,
            "runtime_device_contract": runtime_device_contract(),
            "root_cause_closures": {
                "hash_ok": health.get("ok").and_then(|v| v.as_bool()).unwrap_or(false),
                "provenance_ok": provenance_ok,
                "replay_ok": replay_ok,
                "tamper_evidence_ok": tamper_evidence_ok,
                "persisted_registry": persisted,
                "brt_v11_audit_required_for_authority": true,
            }
        })
    }

    pub fn run_compiler_native_scheduler_self_test() -> serde_json::Value {
        let spec = HashMap::from([
            ("domain".into(), serde_json::json!("math")),
            ("task".into(), serde_json::json!("add")),
            ("inputs".into(), serde_json::json!({"a": 3, "b": 5})),
            ("goal".into(), serde_json::json!("rust_scheduler_self_test")),
        ]);
        let report = compile_domain_spec(&spec);
        let mut registry = CompilerNativeRuntimeRegistry {
            path: None,
            snapshot: CompilerNativeRegistrySnapshot::empty(None),
        };
        registry.save_report(&report);
        let queued = registry.enqueue_report(&report, 1, 3, Vec::new());
        let blocked = registry.enqueue_report(&report, 1, 2, vec!["proc.missing".into()]);
        let timed_out = registry.enqueue_report(&report, 0, 1, Vec::new());
        let completed = registry.drain();
        let health = registry.health();
        let checks = serde_json::json!({
            "compile_verified": report.ok,
            "queued_created": queued.is_some(),
            "blocked_created": blocked.is_some(),
            "timeout_created": timed_out.is_some(),
            "scheduler_finalized": completed.iter().any(|p| p.status == "done"),
            "blocked_or_timed_out_recorded": completed.iter().any(|p| p.status == "blocked" || p.status == "timed_out"),
            "registry_schema_v7": health.get("schema_version").and_then(|v| v.as_u64()) == Some(7),
        });
        let ok = checks
            .as_object()
            .map(|m| m.values().all(|v| v.as_bool().unwrap_or(false)))
            .unwrap_or(false);
        serde_json::json!({
            "ok": ok,
            "version": JARVIS_COMPILER_NATIVE_VERSION,
            "checks": checks,
            "completed": completed,
            "registry_health": health,
        })
    }

