    pub const JARVIS_CAYLEY_LOSS_WEIGHT: f64 = 0.02; // Cayley distance loss coefficient
    pub const JARVIS_WORLD_LOSS_WEIGHT: f64 = 0.03; // world-model prediction loss
    pub const JARVIS_RLG_LOSS_WEIGHT: f64 = 0.05; // RL-geometric policy gradient
    pub const JARVIS_PPO_LOSS_WEIGHT: f64 = 0.05; // PPO clipped surrogate
    pub const JARVIS_SPARSE_FFN_L1: f64 = 0.0003; // sparse gated FFN L1 regularization

    pub const JARVIS_LR: f64 = 0.0006; // Adam learning rate
    pub const JARVIS_NUM_STEPS: usize = 1000; // default training steps
    pub const JARVIS_WARMUP_STEPS: usize = 50; // WSD warmup phase length
    pub const JARVIS_LR_STABLE_FRACTION: f64 = 0.80; // fraction of post-warmup at constant lr
    pub const JARVIS_LR_MIN_RATIO: f64 = 0.10; // min lr = base_lr × this
    pub const JARVIS_GRAD_CLIP: f64 = 1.0; // base gradient clipping threshold
    pub const JARVIS_EMA_LOSS_DECAY: f64 = 0.95; // EMA smoothing for loss tracking

    #[inline]
    pub fn wsd_lr_schedule(
        step: usize,
        total_steps: usize,
        base_lr: f64,
        warmup_steps: usize,
        stable_fraction: f64,
        min_ratio: f64,
    ) -> f64 {
        let min_lr = base_lr * min_ratio;
        if step < warmup_steps {
            return base_lr * (step as f64 + 1.0) / warmup_steps.max(1) as f64;
        }
        let remaining = total_steps.saturating_sub(warmup_steps);
        let stable_steps = (remaining as f64 * stable_fraction) as usize;
        let decay_steps = remaining.saturating_sub(stable_steps);
        let past_warmup = step.saturating_sub(warmup_steps);
        if past_warmup < stable_steps {
            base_lr
        } else {
            let decay_progress = (past_warmup - stable_steps) as f64 / decay_steps.max(1) as f64;
            let coeff = 0.5 * (1.0 + (std::f64::consts::PI * decay_progress).cos());
            min_lr + (base_lr - min_lr) * coeff
        }
    }

    #[inline]
    pub fn dynamic_grad_clip(grad_norm_history: &[f64], base_clip: f64) -> f64 {
        if grad_norm_history.len() < 10 {
            return base_clip;
        }
        let recent: Vec<f64> = grad_norm_history.iter().rev().take(50).copied().collect();
        let n = recent.len() as f64;
        let mean = recent.iter().sum::<f64>() / n;
        let variance = recent.iter().map(|x| (x - mean).powi(2)).sum::<f64>() / n;
        let std_dev = variance.sqrt();
        let adaptive = mean + 3.0 * std_dev;
        adaptive.clamp(0.5, base_clip * 3.0)
    }

