    pub struct RMSNorm {
        pub weight: Tensor,
        pub eps: f64,
    }
    impl RMSNorm {
        pub fn new(dim: usize, eps: f64, vb: VarBuilder) -> CResult<Self> {
            let weight = vb.get_with_hints((dim,), "weight", candle_nn::Init::Const(1.0))?;
            Ok(Self { weight, eps })
        }
    }
    impl Module for RMSNorm {
        fn forward(&self, x: &Tensor) -> CResult<Tensor> {
            let x_f32 = x.to_dtype(DType::F32)?;
            let ms = x_f32.sqr()?.mean_keepdim(D::Minus1)?;
            let rms = (ms + self.eps)?.sqrt()?;
            let normed = x_f32.broadcast_div(&rms)?;
            let result = normed.broadcast_mul(&self.weight.to_dtype(DType::F32)?)?;
            result.to_dtype(x.dtype())
        }
    }

    pub struct AdaptiveLayerNorm {
        pub weight: Tensor,
        pub bias: Tensor,
        pub eps: f64,
    }
    impl AdaptiveLayerNorm {
        pub fn new(dim: usize, eps: f64, vb: VarBuilder) -> CResult<Self> {
            let weight = vb.get_with_hints((dim,), "weight", candle_nn::Init::Const(1.0))?;
            let bias = vb.get_with_hints((dim,), "bias", candle_nn::Init::Const(0.0))?;
            Ok(Self { weight, bias, eps })
        }
    }
    impl Module for AdaptiveLayerNorm {
        fn forward(&self, x: &Tensor) -> CResult<Tensor> {
            let x_f32 = x.to_dtype(DType::F32)?;
            let mean = x_f32.mean_keepdim(D::Minus1)?;
            let x_centered = x_f32.broadcast_sub(&mean)?;
            let var = x_centered.sqr()?.mean_keepdim(D::Minus1)?;
            let normed = x_centered.broadcast_div(&(var + self.eps)?.sqrt()?)?;
            let result = normed
                .broadcast_mul(&self.weight.to_dtype(DType::F32)?)?
                .broadcast_add(&self.bias.to_dtype(DType::F32)?)?;
            result.to_dtype(x.dtype())
        }
    }

    #[allow(clippy::too_many_arguments)]
    pub fn compute_gate_features(
        fast_action: &Tensor,
        slow_action: &Tensor,
        _tool_route: &Tensor,
        _value: &Tensor,
        board_status: &Tensor,
        memory_write: &Tensor,
        proof: &Tensor,
        _governance: &Tensor,
        runtime: &Tensor,
        asi: Option<&ASISystemOutput>,
    ) -> CResult<Tensor> {
        let fast_conf = candle_nn::ops::softmax(fast_action, D::Minus1)?;
        let fast_confidence = fast_conf.max(D::Minus1)?.unsqueeze(D::Minus1)?;
        let slow_conf = candle_nn::ops::softmax(slow_action, D::Minus1)?;
        let slow_confidence = slow_conf.max(D::Minus1)?.unsqueeze(D::Minus1)?;
        let (risk, alignment, shutdown, asi_value, tool_entropy_val, uncertainty) =
            if let Some(system) = asi {
                let risk_tensor = &system.risk_adjusted_logit;
                let risk = candle_nn::ops::sigmoid(risk_tensor)?.unsqueeze(D::Minus1)?;
                let alignment =
                    candle_nn::ops::sigmoid(&system.alignment_logit)?.unsqueeze(D::Minus1)?;
                let shutdown =
                    candle_nn::ops::sigmoid(&system.shutdown_logit)?.unsqueeze(D::Minus1)?;
                let value_sig = system.value.tanh()?.unsqueeze(D::Minus1)?;
                let tool_entropy = {
                    let tp = candle_nn::ops::softmax(&system.tool_logits, D::Minus1)?;
                    let log_tp = (tp.clone() + 1e-8)?.log()?;
                    (tp * log_tp)?.neg()?.sum(D::Minus1)?.unsqueeze(D::Minus1)?
                };
                let unc = if !system.metacognition_logits.dims().is_empty() {
                    let first = system.metacognition_logits.narrow(D::Minus1, 0, 1)?;
                    candle_nn::ops::sigmoid(&first)?
                } else {
                    Tensor::zeros_like(&risk)?
                };
                (risk, alignment, shutdown, value_sig, tool_entropy, unc)
            } else {
                let zeros = Tensor::zeros(
                    fast_confidence.shape(),
                    fast_confidence.dtype(),
                    fast_confidence.device(),
                )?;
                let ones = Tensor::ones(
                    fast_confidence.shape(),
                    fast_confidence.dtype(),
                    fast_confidence.device(),
                )?;
                (
                    zeros.clone(),
                    ones,
                    zeros.clone(),
                    zeros.clone(),
                    zeros.clone(),
                    zeros,
                )
            };
        let proof_need =
            candle_nn::ops::sigmoid(&proof.to_dtype(DType::F32)?)?.narrow(D::Minus1, 0, 1)?;
        let runtime_pressure =
            candle_nn::ops::sigmoid(&runtime.to_dtype(DType::F32)?)?.narrow(D::Minus1, 0, 1)?;
        let memory_prob = candle_nn::ops::sigmoid(&memory_write.to_dtype(DType::F32)?)?;
        let novelty_score = (memory_prob.max(D::Minus1)?.unsqueeze(D::Minus1)?.neg()? + 1.0)?;
        let dep_pressure = candle_nn::ops::sigmoid(&board_status.to_dtype(DType::F32)?)?
            .mean_keepdim(D::Minus1)?;

        Tensor::cat(
            &[
                risk,
                alignment,
                shutdown,
                asi_value,
                tool_entropy_val,
                uncertainty,
                proof_need,
                runtime_pressure,
                fast_confidence,
                slow_confidence,
                novelty_score,
                dep_pressure,
            ],
            D::Minus1,
        )
    }

    pub struct LatentWorldModelHead {
        state_norm: RMSNorm,
        action_emb_weight: Tensor, // Embedding(ASI_ACTION_BINS, dim)
        transition1: Linear,       // Linear(dim*2, hidden)
        transition2: Linear,       // Linear(hidden, dim)
        delta_scale_raw: Tensor,   // Parameter(-2.0) → sigmoid → scale
    }

    impl LatentWorldModelHead {
        pub fn new(dim: usize, vb: VarBuilder) -> CResult<Self> {
            let hidden = (dim * 2).max(64);
            let state_norm = RMSNorm::new(dim, 1e-6, vb.pp("state_norm"))?;
            let action_emb_weight = vb.get_with_hints(
                (ASI_ACTION_BINS, dim),
                "action_emb",
                candle_nn::Init::Randn {
                    mean: 0.0,
                    stdev: 0.02,
                },
            )?;
            let transition1 = linear(dim * 2, hidden, vb.pp("transition1"))?;
            let transition2 = linear(hidden, dim, vb.pp("transition2"))?;
            let delta_scale_raw =
                vb.get_with_hints((1,), "delta_scale", candle_nn::Init::Const(-2.0))?;
            Ok(Self {
                state_norm,
                action_emb_weight,
                transition1,
                transition2,
                delta_scale_raw,
            })
        }

        pub fn forward(&self, states: &Tensor, action_ids: &Tensor) -> CResult<Tensor> {
            let clamped = action_ids.clamp(0u32, (ASI_ACTION_BINS - 1) as u32)?;
            let action = match clamped.dims() {
                [b] => self.action_emb_weight.embedding(&clamped.reshape((*b,))?)?,
                [b, t] => {
                    let flat = clamped.reshape((b * t,))?;
                    self.action_emb_weight.embedding(&flat)?.reshape((
                        *b,
                        *t,
                        states.dim(D::Minus1)?,
                    ))?
                }
                dims => {
                    return Err(candle_core::Error::Msg(format!(
                        "LatentWorldModelHead action_ids must be rank 1 or 2, got {:?}",
                        dims
                    )));
                }
            };
            let normed = self.state_norm.forward(states)?;
            let x = Tensor::cat(&[normed, action], D::Minus1)?;
            let delta = self.transition1.forward(&x)?.silu()?;
            let delta = self.transition2.forward(&delta)?;
            let scale = candle_nn::ops::sigmoid(&self.delta_scale_raw)?;
            let scale = scale.broadcast_as(delta.shape())?;
            states + (delta * scale)?
        }
    }

    pub struct AgentToolPolicyHead {
        norm: RMSNorm,
        trunk1: Linear,
        action_head: Linear,
        tool_head: Linear,
        value_head: Linear,
        memory_query_head: Linear,
    }

    impl AgentToolPolicyHead {
        pub fn new(dim: usize, vb: VarBuilder) -> CResult<Self> {
            let hidden = dim.max(64);
            let norm = RMSNorm::new(dim, 1e-6, vb.pp("norm"))?;
            let trunk1 = linear(dim, hidden, vb.pp("trunk1"))?;
            let action_head = linear(hidden, ASI_N_AGENT_ACTIONS, vb.pp("action"))?;
            let tool_head = linear(hidden, ASI_N_TOOLS, vb.pp("tool"))?;
            let value_head = linear(hidden, 1, vb.pp("value"))?;
            let memory_query_head = linear(hidden, dim, vb.pp("memory_query"))?;
            Ok(Self {
                norm,
                trunk1,
                action_head,
                tool_head,
                value_head,
                memory_query_head,
            })
        }

        pub fn forward(&self, states: &Tensor) -> CResult<(Tensor, Tensor, Tensor, Tensor)> {
            let h = self.trunk1.forward(&self.norm.forward(states)?)?.silu()?;
            let action_logits = self.action_head.forward(&h)?;
            let tool_logits = self.tool_head.forward(&h)?;
            let value = self.value_head.forward(&h)?.squeeze(D::Minus1)?;
            let query = self.memory_query_head.forward(&h)?;
            let norm = (query.sqr()?.sum(D::Minus1)?.sqrt()? + 1e-8)?;
            let norm = norm.unsqueeze(D::Minus1)?;
            let query = query.broadcast_div(&norm)?;
            Ok((action_logits, tool_logits, value, query))
        }
    }

    #[derive(Debug)]
    pub struct LatentMASLossReport {
        pub loss: Tensor,
        pub metrics: HashMap<String, f64>,
    }

    const LLM_LATENT_MAS_MIN_SOFT_ROUTE_SHARE: f64 = 0.001;

    pub struct LatentMultiAgentSystemHead {
        norm: RMSNorm,
        router_head: Linear,
        agent_state_heads: Vec<Linear>,
        agent_message_heads: Vec<Linear>,
        agent_action_heads: Vec<Linear>,
    }

    impl LatentMultiAgentSystemHead {
        pub fn new(dim: usize, agent_count: usize, vb: VarBuilder) -> CResult<Self> {
            let agent_count = agent_count.max(2);
            let norm = RMSNorm::new(dim, 1e-6, vb.pp("norm"))?;
            let router_head = linear(dim, agent_count, vb.pp("router"))?;
            let mut agent_state_heads = Vec::with_capacity(agent_count);
            let mut agent_message_heads = Vec::with_capacity(agent_count);
            let mut agent_action_heads = Vec::with_capacity(agent_count);
            for agent_idx in 0..agent_count {
                agent_state_heads.push(linear(
                    dim,
                    dim,
                    vb.pp(format!("agent_{agent_idx}_state")),
                )?);
                agent_message_heads.push(linear(
                    dim,
                    dim,
                    vb.pp(format!("agent_{agent_idx}_message")),
                )?);
                agent_action_heads.push(linear(
                    dim,
                    ASI_N_AGENT_ACTIONS,
                    vb.pp(format!("agent_{agent_idx}_action")),
                )?);
            }
            Ok(Self {
                norm,
                router_head,
                agent_state_heads,
                agent_message_heads,
                agent_action_heads,
            })
        }

        fn class_id_cross_entropy(logits: &Tensor, target_ids: &Tensor) -> CResult<Tensor> {
            let classes = logits.dim(D::Minus1)?;
            let rows = target_ids.elem_count();
            let logits = logits.reshape((rows, classes))?;
            let target_ids = target_ids
                .flatten_all()?
                .clamp(0u32, classes.saturating_sub(1) as u32)?;
            candle_nn::loss::cross_entropy(&logits, &target_ids)
        }

        pub fn compute_loss(
            &self,
            hidden_states: &Tensor,
            action_ids: &Tensor,
        ) -> CResult<LatentMASLossReport> {
            let h = self.norm.forward(hidden_states)?.to_dtype(DType::F32)?;
            let route_logits = self.router_head.forward(&h)?;
            let route_probs =
                candle_nn::ops::softmax(&route_logits.to_dtype(DType::F32)?, D::Minus1)?;
            let mut raw_states = Vec::with_capacity(self.agent_state_heads.len());
            let mut messages = Vec::with_capacity(self.agent_state_heads.len());
            for (state_head, message_head) in self
                .agent_state_heads
                .iter()
                .zip(self.agent_message_heads.iter())
            {
                let state = state_head.forward(&h)?.tanh()?;
                let message = message_head.forward(&state)?.silu()?;
                raw_states.push(state);
                messages.push(message);
            }

            let message_stack = Tensor::stack(&messages, 2)?;
            let blackboard = message_stack.mean(D::Minus2)?;
            let mut agent_states = Vec::with_capacity(raw_states.len());
            let mut action_losses = Vec::with_capacity(raw_states.len());
            let blackboard_update = (&blackboard * LLM_LATENT_MAS_COMMUNICATION_MIX)?;
            for (state, action_head) in raw_states.into_iter().zip(self.agent_action_heads.iter()) {
                let agent_state = state.broadcast_add(&blackboard_update)?;
                let action_logits = action_head.forward(&agent_state)?;
                let action_loss = Self::class_id_cross_entropy(&action_logits, action_ids)?;
                action_losses.push(action_loss);
                agent_states.push(agent_state);
            }

            let agent_stack = Tensor::stack(&agent_states, 2)?;
            let weights = route_probs
                .unsqueeze(D::Minus1)?
                .broadcast_as(agent_stack.shape())?;
            let fused_state = agent_stack.broadcast_mul(&weights)?.sum(D::Minus2)?;
            let target = hidden_states.detach().to_dtype(DType::F32)?;
            let alignment_loss = (&fused_state - &target)?.sqr()?.mean_all()?;
            let communication_loss = (&fused_state - &blackboard)?.sqr()?.mean_all()?;
            let action_loss = Tensor::stack(&action_losses, 0)?.mean_all()?;

            let mut diversity_terms = Vec::new();
            for i in 0..agent_states.len() {
                for j in (i + 1)..agent_states.len() {
                    let a = agent_states[i].to_dtype(DType::F32)?;
                    let b = agent_states[j].to_dtype(DType::F32)?;
                    let dot = (&a * &b)?.sum(D::Minus1)?;
                    let a_norm = a.sqr()?.sum(D::Minus1)?.sqrt()?;
                    let b_norm = b.sqr()?.sum(D::Minus1)?.sqrt()?;
                    let denom = (a_norm * b_norm)?.clamp(1e-8f32, f32::MAX)?;
                    let cosine = dot.broadcast_div(&denom)?;
                    diversity_terms.push(cosine.sqr()?.mean_all()?);
                }
            }
            let diversity_loss = if diversity_terms.is_empty() {
                Tensor::zeros((), DType::F32, hidden_states.device())?
            } else {
                Tensor::stack(&diversity_terms, 0)?.mean_all()?
            };

            let route_mean = route_probs.mean(D::Minus2)?.mean(D::Minus2)?;
            let uniform = Tensor::from_vec(
                vec![1.0f32 / self.agent_state_heads.len() as f32; self.agent_state_heads.len()],
                (self.agent_state_heads.len(),),
                hidden_states.device(),
            )?;
            let balance_loss = (&route_mean - &uniform)?.sqr()?.mean_all()?;
            let route_entropy = {
                let log_probs = route_probs.clamp(1e-6f32, 1.0f32)?.log()?;
                (&route_probs * &log_probs)?
                    .sum(D::Minus1)?
                    .neg()?
                    .mean_all()?
            };

            let action_weighted = (action_loss.clone() * LLM_LATENT_MAS_ACTION_LOSS_WEIGHT)?;
            let communication_weighted =
                (communication_loss.clone() * LLM_LATENT_MAS_COMMUNICATION_LOSS_WEIGHT)?;
            let diversity_weighted =
                (diversity_loss.clone() * LLM_LATENT_MAS_DIVERSITY_LOSS_WEIGHT)?;
            let balance_weighted = (balance_loss.clone() * LLM_LATENT_MAS_BALANCE_LOSS_WEIGHT)?;
            let total = alignment_loss.broadcast_add(&action_weighted)?;
            let total = total.broadcast_add(&communication_weighted)?;
            let total = total
                .broadcast_add(&diversity_weighted)?
                .broadcast_add(&balance_weighted)?;

            let scalar_tensors = vec![
                alignment_loss.to_dtype(DType::F32)?,
                action_loss.to_dtype(DType::F32)?,
                communication_loss.to_dtype(DType::F32)?,
                diversity_loss.to_dtype(DType::F32)?,
                balance_loss.to_dtype(DType::F32)?,
                route_entropy.to_dtype(DType::F32)?,
                total.to_dtype(DType::F32)?,
            ];
            let values = Tensor::stack(&scalar_tensors, 0)?.to_vec1::<f32>()?;
            let route_values = route_mean.to_dtype(DType::F32)?.to_vec1::<f32>()?;
            let active_agents = route_values.iter().filter(|&&v| v > 0.01).count();
            let soft_active_agents = route_values
                .iter()
                .filter(|&&v| v > LLM_LATENT_MAS_MIN_SOFT_ROUTE_SHARE as f32)
                .count();
            let min_route_share = route_values
                .iter()
                .copied()
                .fold(f32::INFINITY, f32::min)
                .max(0.0);
            let max_route_share = route_values
                .iter()
                .copied()
                .fold(f32::NEG_INFINITY, f32::max)
                .max(0.0);
            let specialization_score = (1.0 - values[3].clamp(0.0, 1.0)) as f64;
            Ok(LatentMASLossReport {
                loss: total,
                metrics: HashMap::from([
                    ("latent_mas_alignment_loss".into(), values[0] as f64),
                    ("latent_mas_action_loss".into(), values[1] as f64),
                    ("latent_mas_communication_loss".into(), values[2] as f64),
                    ("latent_mas_diversity_loss".into(), values[3] as f64),
                    ("latent_mas_balance_loss".into(), values[4] as f64),
                    ("latent_mas_router_entropy".into(), values[5] as f64),
                    ("latent_mas_total_loss".into(), values[6] as f64),
                    (
                        "latent_mas_agent_count".into(),
                        self.agent_state_heads.len() as f64,
                    ),
                    ("latent_mas_active_agents".into(), active_agents as f64),
                    (
                        "latent_mas_soft_active_agents".into(),
                        soft_active_agents as f64,
                    ),
                    (
                        "latent_mas_min_soft_route_share".into(),
                        LLM_LATENT_MAS_MIN_SOFT_ROUTE_SHARE,
                    ),
                    ("latent_mas_min_route_share".into(), min_route_share as f64),
                    ("latent_mas_max_route_share".into(), max_route_share as f64),
                    (
                        "latent_mas_specialization_score".into(),
                        specialization_score,
                    ),
                    ("latent_mas_training_enabled".into(), 1.0),
                    ("latent_mas_full_multi_agent".into(), 1.0),
                    ("latent_mas_loss_weight".into(), LLM_LATENT_MAS_LOSS_WEIGHT),
                ]),
            })
        }
    }

    pub struct SafetyAlignmentHead {
        norm: RMSNorm,
        trunk1: Linear,
        trunk2: Linear,
        risk_head: Linear,
        shutdown_head: Linear,
        alignment_head: Linear,
    }

    impl SafetyAlignmentHead {
        pub fn new(dim: usize, vb: VarBuilder) -> CResult<Self> {
            let hidden = (dim / 2).max(32);
            let norm = RMSNorm::new(dim, 1e-6, vb.pp("norm"))?;
            let trunk1 = linear(dim, hidden, vb.pp("trunk1"))?;
            let trunk2 = linear(hidden, hidden, vb.pp("trunk2"))?;
            let risk_head = linear(hidden, 1, vb.pp("risk"))?;
            let shutdown_head = linear(hidden, 1, vb.pp("shutdown"))?;
            let alignment_head = linear(hidden, 1, vb.pp("alignment"))?;
            Ok(Self {
                norm,
                trunk1,
                trunk2,
                risk_head,
                shutdown_head,
                alignment_head,
            })
        }

        pub fn forward(&self, states: &Tensor) -> CResult<(Tensor, Tensor, Tensor)> {
            let h = self.trunk1.forward(&self.norm.forward(states)?)?.silu()?;
            let h = self.trunk2.forward(&h)?.silu()?;
            let risk = self.risk_head.forward(&h)?.squeeze(D::Minus1)?;
            let shutdown = self.shutdown_head.forward(&h)?.squeeze(D::Minus1)?;
            let alignment = self.alignment_head.forward(&h)?.squeeze(D::Minus1)?;
            Ok((risk, shutdown, alignment))
        }
    }

    pub struct CapabilityPortfolioHead {
        norm: RMSNorm,
        net1: Linear,
        net2: Linear,
    }

    impl CapabilityPortfolioHead {
        pub fn new(dim: usize, vb: VarBuilder) -> CResult<Self> {
            let hidden = dim.max(64);
            let norm = RMSNorm::new(dim, 1e-6, vb.pp("norm"))?;
            let net1 = linear(dim, hidden, vb.pp("net1"))?;
            let net2 = linear(hidden, ASI_N_DOMAINS, vb.pp("net2"))?;
            Ok(Self { norm, net1, net2 })
        }

        pub fn forward(&self, states: &Tensor) -> CResult<Tensor> {
            let h = self.net1.forward(&self.norm.forward(states)?)?.gelu()?;
            self.net2.forward(&h)
        }
    }

    pub struct ASIMetacognitionHead {
        norm: RMSNorm,
        trunk1: Linear,
        trunk2: Linear,
        plan_head: Linear,
        meta_head: Linear,
        governance_head: Linear,
        risk_delta_head: Linear,
    }

    impl ASIMetacognitionHead {
        pub fn new(dim: usize, vb: VarBuilder) -> CResult<Self> {
            let hidden = dim.max(64);
            let norm = RMSNorm::new(dim, 1e-6, vb.pp("norm"))?;
            let trunk1 = linear(dim, hidden, vb.pp("trunk1"))?;
            let trunk2 = linear(hidden, hidden, vb.pp("trunk2"))?;
            let plan_head = linear(
                hidden,
                ASI_PLANNING_HORIZON * ASI_N_AGENT_ACTIONS,
                vb.pp("plan"),
            )?;
            let meta_head = linear(hidden, ASI_METACOGNITION_DIM, vb.pp("meta"))?;
            let governance_head = linear(hidden, 1, vb.pp("governance"))?;
            let risk_delta_head = linear(hidden, 1, vb.pp("risk_delta"))?;
            Ok(Self {
                norm,
                trunk1,
                trunk2,
                plan_head,
                meta_head,
                governance_head,
                risk_delta_head,
            })
        }

        pub fn forward(&self, states: &Tensor) -> CResult<(Tensor, Tensor, Tensor, Tensor)> {
            let h = self.trunk1.forward(&self.norm.forward(states)?)?.silu()?;
            let h = self.trunk2.forward(&h)?.silu()?;
            let plan = self.plan_head.forward(&h)?;
            let meta = self.meta_head.forward(&h)?;
            let governance = self.governance_head.forward(&h)?.squeeze(D::Minus1)?;
            let risk_delta = self.risk_delta_head.forward(&h)?.squeeze(D::Minus1)?;
            Ok((plan, meta, governance, risk_delta))
        }
    }

    #[derive(Debug)]
    pub struct ASISystemOutput {
        pub predicted_next_state: Tensor,
        pub agent_action_logits: Tensor,
        pub tool_logits: Tensor,
        pub value: Tensor,
        pub risk_logit: Tensor,
        pub shutdown_logit: Tensor,
        pub alignment_logit: Tensor,
        pub capability_logits: Tensor,
        pub memory_query: Tensor,
        pub plan_logits: Tensor,
        pub metacognition_logits: Tensor,
        pub governance_score: Tensor,
        pub risk_adjusted_logit: Tensor,
    }

    impl ASISystemOutput {
        pub fn compute(
            world_model: &LatentWorldModelHead,
            agent_policy: &AgentToolPolicyHead,
            safety: &SafetyAlignmentHead,
            capability: &CapabilityPortfolioHead,
            metacognition: &ASIMetacognitionHead,
            hidden_states: &Tensor,
            action_ids: &Tensor,
        ) -> CResult<Self> {
            let predicted_next_state = world_model.forward(hidden_states, action_ids)?;
            let (agent_action_logits, tool_logits, value, memory_query) =
                agent_policy.forward(hidden_states)?;
            let (risk_logit, shutdown_logit, alignment_logit) = safety.forward(hidden_states)?;
            let capability_logits = capability.forward(hidden_states)?;
            let (plan_logits, metacognition_logits, governance_score, risk_delta) =
                metacognition.forward(hidden_states)?;
            let risk_adjusted_logit = (&risk_logit + (risk_delta.tanh()? * 0.5)?)?;

            Ok(Self {
                predicted_next_state,
                agent_action_logits,
                tool_logits,
                value,
                risk_logit,
                shutdown_logit,
                alignment_logit,
                capability_logits,
                memory_query,
                plan_logits,
                metacognition_logits,
                governance_score,
                risk_adjusted_logit,
            })
        }
        pub fn report(&self) -> CResult<HashMap<String, serde_json::Value>> {
            let risk = candle_nn::ops::sigmoid(&self.risk_logit)?
                .mean_all()?
                .to_scalar::<f32>()?;
            let alignment = candle_nn::ops::sigmoid(&self.alignment_logit)?
                .mean_all()?
                .to_scalar::<f32>()?;
            let shutdown = candle_nn::ops::sigmoid(&self.shutdown_logit)?
                .mean_all()?
                .to_scalar::<f32>()?;
            let value = self.value.mean_all()?.to_scalar::<f32>()?;
            let governance = candle_nn::ops::sigmoid(&self.governance_score)?
                .mean_all()?
                .to_scalar::<f32>()?;
            Ok(HashMap::from([
                ("asi_risk".into(), serde_json::json!(risk)),
                ("asi_alignment".into(), serde_json::json!(alignment)),
                ("asi_shutdown".into(), serde_json::json!(shutdown)),
                ("asi_value".into(), serde_json::json!(value)),
                ("asi_governance".into(), serde_json::json!(governance)),
                (
                    "asi_n_agent_actions".into(),
                    serde_json::json!(ASI_N_AGENT_ACTIONS),
                ),
                ("asi_n_tools".into(), serde_json::json!(ASI_N_TOOLS)),
                ("asi_n_domains".into(), serde_json::json!(ASI_N_DOMAINS)),
                (
                    "asi_metacognition_dim".into(),
                    serde_json::json!(ASI_METACOGNITION_DIM),
                ),
            ]))
        }
    }

    pub const MOE_N_EXPERTS: usize = 4;
    pub const MOE_TOP_K: usize = 2;
    pub const MOE_N_SHARED: usize = 1;
    pub const MOE_SINKHORN_ITERS: usize = 8;
    pub const MOE_SINKHORN_REG: f64 = 0.05;
    pub const MOE_SINKHORN_TAU: f64 = 0.1;
    pub const MOE_CAPACITY_FACTOR: f64 = 1.25;
    pub const MOE_NASH_CLIP: f64 = 0.5;
    pub const MOE_CENTROID_REPEL_WEIGHT: f64 = 0.01;

    pub struct ExpertFFNV2 {
        up: Linear,
        gate: Linear,
        down: Linear,
    }
    impl ExpertFFNV2 {
        pub fn new(dim: usize, hidden: usize, vb: VarBuilder) -> CResult<Self> {
            Ok(Self {
                up: linear(dim, hidden, vb.pp("up"))?,
                gate: linear(dim, hidden, vb.pp("gate"))?,
                down: linear(hidden, dim, vb.pp("down"))?,
            })
        }
        pub fn forward(&self, x: &Tensor) -> CResult<Tensor> {
            let up = self.up.forward(x)?;
            let gate = self.gate.forward(x)?.silu()?;
            self.down.forward(&(up * gate)?)
        }
    }

    pub struct SinkhornMoELayerV2 {
        experts: Vec<ExpertFFNV2>,
        shared_experts: Vec<ExpertFFNV2>,
        top_k: usize,
        centroids: Tensor,                     // (n_experts, dim)
        nash_bias: Vec<f64>,                   // running Nash equilibrium bias
        routing_counts: Vec<usize>,            // per-expert token counts for the latest batch
        cumulative_routing_counts: Vec<usize>, // per-expert assignments across training
        ot_error: f64,
    }

    impl SinkhornMoELayerV2 {
        pub fn new(
            dim: usize,
            n_experts: usize,
            top_k: usize,
            n_shared_experts: usize,
            vb: VarBuilder,
        ) -> CResult<Self> {
            let n_experts = n_experts.max(1);
            let top_k = top_k.clamp(1, n_experts);
            let n_shared_experts = n_shared_experts.max(1);
            let hidden = (dim * 2).max(32);
            let mut experts = Vec::new();
            for i in 0..n_experts {
                experts.push(ExpertFFNV2::new(
                    dim,
                    hidden,
                    vb.pp(format!("expert_{}", i)),
                )?);
            }
            let mut shared_experts = Vec::new();
            for i in 0..n_shared_experts {
                shared_experts.push(ExpertFFNV2::new(
                    dim,
                    hidden,
                    vb.pp(format!("shared_{}", i)),
                )?);
            }
            let centroids = vb.get_with_hints(
                (n_experts, dim),
                "centroids",
                candle_nn::Init::Randn {
                    mean: 0.0,
                    stdev: 0.02,
                },
            )?;
            Ok(Self {
                experts,
                shared_experts,
                top_k,
                centroids,
                nash_bias: vec![0.0; n_experts],
                routing_counts: vec![0; n_experts],
                cumulative_routing_counts: vec![0; n_experts],
                ot_error: 0.0,
            })
        }
        fn compute_distances(&self, x: &Tensor) -> CResult<Tensor> {
            let x_sq = x.sqr()?.sum(D::Minus1)?; // (N,)
            let c_sq = self.centroids.sqr()?.sum(D::Minus1)?; // (E,)
            let xc = x.matmul(&self.centroids.transpose(0, 1)?)?; // (N, E)
            let x_sq = x_sq.unsqueeze(1)?.broadcast_as(xc.shape())?;
            let c_sq = c_sq.unsqueeze(0)?.broadcast_as(xc.shape())?;
            (x_sq + c_sq)? - (xc * 2.0)?
        }

        fn differentiable_topk_weights(
            scores: &Tensor,
            scores_are_logits: bool,
            top_k: usize,
        ) -> CResult<(Tensor, Vec<usize>)> {
            let (n, n_experts) = scores.dims2()?;
            let top_k = top_k.clamp(1, n_experts);
            let scores = scores.contiguous()?;
            let top_indices = scores
                .arg_sort_last_dim(false)?
                .narrow(D::Minus1, 0, top_k)?
                .contiguous()?;
            let top_indices_host = top_indices.to_vec2::<u32>()?;
            let mut mask = vec![0.0f32; n * n_experts];
            let mut counts = vec![0usize; n_experts];
            for (token_idx, indices) in top_indices_host.iter().enumerate() {
                for &expert_idx in indices {
                    let expert_idx = expert_idx as usize;
                    if expert_idx < n_experts {
                        mask[token_idx * n_experts + expert_idx] = 1.0;
                        counts[expert_idx] += 1;
                    }
                }
            }
            let mask = Tensor::from_vec(mask, (n, n_experts), scores.device())?;
            let base_weights = if scores_are_logits {
                candle_nn::ops::softmax(&scores, D::Minus1)?
            } else {
                let denom = scores.sum_keepdim(D::Minus1)?.clamp(1e-8f32, f32::MAX)?;
                scores.broadcast_div(&denom)?
            };
            let masked = base_weights.broadcast_mul(&mask)?;
            let denom = masked.sum_keepdim(D::Minus1)?.clamp(1e-8f32, f32::MAX)?;
            Ok((masked.broadcast_div(&denom)?, counts))
        }

        fn route_experts(&self, x: &Tensor, routing_weights: &Tensor) -> CResult<Tensor> {
            let (n, d) = x.dims2()?;
            let mut output = Tensor::zeros((n, d), x.dtype(), x.device())?;
            for (expert_idx, expert) in self.experts.iter().enumerate() {
                let expert_output = expert.forward(x)?;
                let weight = routing_weights.narrow(1, expert_idx, 1)?;
                output = (output + expert_output.broadcast_mul(&weight)?)?;
            }
            for shared_expert in &self.shared_experts {
                output = (output
                    + (shared_expert.forward(x)? * (1.0 / self.shared_experts.len() as f64))?)?;
            }
            Ok(output)
        }

        pub fn forward(&self, x: &Tensor) -> CResult<Tensor> {
            let (n, _d) = x.dims2()?;
            let distances = self.compute_distances(x)?;
            let neg_dist = (distances * (-1.0 / MOE_SINKHORN_TAU))?;
            let nash_t = Tensor::from_vec(
                self.nash_bias.iter().map(|&v| v as f32).collect::<Vec<_>>(),
                (self.experts.len(),),
                x.device(),
            )?;
            let logits = (neg_dist
                + nash_t
                    .unsqueeze(0)?
                    .broadcast_as(&[n, self.experts.len()])?)?;
            let (routing_weights, _counts) =
                Self::differentiable_topk_weights(&logits, true, self.top_k)?;
            self.route_experts(x, &routing_weights)
        }
        pub fn sinkhorn_normalize(&self, cost: &Tensor) -> CResult<Tensor> {
            let mut log_alpha = (cost * (-1.0 / MOE_SINKHORN_REG))?;
            for _ in 0..MOE_SINKHORN_ITERS {
                let row_lse = log_alpha.log_sum_exp(D::Minus1)?;
                let row_lse = row_lse
                    .unsqueeze(D::Minus1)?
                    .broadcast_as(log_alpha.shape())?;
                log_alpha = (log_alpha - row_lse)?;
                let col_lse = log_alpha.transpose(0, 1)?.log_sum_exp(D::Minus1)?;
                let col_lse = col_lse.unsqueeze(0)?.broadcast_as(log_alpha.shape())?;
                log_alpha = (log_alpha - col_lse)?;
            }
            candle_nn::ops::softmax(&log_alpha, D::Minus1)
        }
        pub fn forward_train(&mut self, x: &Tensor) -> CResult<Tensor> {
            let (n, _d) = x.dims2()?;
            let distances = self.compute_distances(x)?;
            let sinkhorn_weights = self.sinkhorn_normalize(&distances)?;
            let nash_t = Tensor::from_vec(
                self.nash_bias.iter().map(|&v| v as f32).collect::<Vec<_>>(),
                (self.experts.len(),),
                x.device(),
            )?;
            let routing_logits = (sinkhorn_weights
                + nash_t
                    .unsqueeze(0)?
                    .broadcast_as(&[n, self.experts.len()])?)?;
            let (routing_weights, counts) =
                Self::differentiable_topk_weights(&routing_logits, true, self.top_k)?;
            self.routing_counts = counts;
            for (total, &count) in self
                .cumulative_routing_counts
                .iter_mut()
                .zip(&self.routing_counts)
            {
                *total = total.saturating_add(count);
            }
            let ideal = n as f64 * self.top_k as f64 / self.experts.len() as f64;
            self.ot_error = self
                .routing_counts
                .iter()
                .map(|&c| (c as f64 - ideal).abs())
                .sum::<f64>()
                / self.experts.len() as f64;
            let result = self.route_experts(x, &routing_weights)?;
            const MOE_NASH_LR: f64 = 0.01;
            for i in 0..self.experts.len() {
                let deviation = ideal - self.routing_counts[i] as f64;
                self.nash_bias[i] = (self.nash_bias[i]
                    + MOE_NASH_LR * deviation / (n as f64).max(1.0))
                .clamp(-MOE_NASH_CLIP, MOE_NASH_CLIP);
            }

            Ok(result)
        }

        pub fn report(&self) -> HashMap<String, serde_json::Value> {
            let alive = self.routing_counts.iter().filter(|&&c| c > 0).count();
            let dead = self.experts.len() - alive;
            HashMap::from([
                ("n_experts".into(), serde_json::json!(self.experts.len())),
                ("top_k".into(), serde_json::json!(self.top_k)),
                (
                    "n_shared_experts".into(),
                    serde_json::json!(self.shared_experts.len()),
                ),
                ("alive".into(), serde_json::json!(alive)),
                ("dead".into(), serde_json::json!(dead)),
                ("counts".into(), serde_json::json!(self.routing_counts)),
                (
                    "cumulative_counts".into(),
                    serde_json::json!(self.cumulative_routing_counts),
                ),
                ("ot_error".into(), serde_json::json!(self.ot_error)),
                ("nash_bias".into(), serde_json::json!(self.nash_bias)),
            ])
        }
    }

    pub fn moe_routing_health_from_counts(counts: &[usize], n_experts: usize) -> serde_json::Value {
        let n_experts = n_experts.max(1);
        let total: usize = counts.iter().sum();
        if total == 0 {
            return serde_json::json!({
                "ok": false,
                "status": "fail",
                "reason": "no routing assignments",
                "alive": 0,
                "alive_experts": 0,
                "n_experts": n_experts,
                "balance": 0.0,
                "min_frac": 0.0,
                "min_fraction": 0.0,
                "max_frac": 0.0,
                "max_fraction": 0.0,
                "max_frac_limit": 1.0,
                "max_fraction_limit": 1.0,
                "sample_limited": true,
                "total": 0,
            });
        }

        let total_f = total as f64;
        let mut entropy = 0.0f64;
        let mut min_frac = 1.0f64;
        let mut max_frac = 0.0f64;
        let alive = counts.iter().filter(|&&count| count > 0).count();
        for &count in counts {
            let frac = count as f64 / total_f;
            if frac > 0.0 {
                entropy -= frac * frac.ln();
            }
            min_frac = min_frac.min(frac);
            max_frac = max_frac.max(frac);
        }

        let balance = entropy / (n_experts as f64).ln().max(1e-12);
        let expected = 1.0 / n_experts as f64;
        let min_total = n_experts * 8;
        let sample_limited = total < min_total;
        let sample_std = (expected * (1.0 - expected) / total_f.max(1.0)).sqrt();
        let max_frac_limit = (expected + 3.0 * sample_std).max(expected * 1.4).min(1.0);
        let ok =
            sample_limited || (alive == n_experts && balance >= 0.85 && max_frac <= max_frac_limit);

        let mut reasons = Vec::new();
        if sample_limited {
            reasons.push(format!("sample={}<{}", total, min_total));
        } else {
            if alive != n_experts {
                reasons.push(format!("alive={}/{}", alive, n_experts));
            }
            if balance < 0.85 {
                reasons.push(format!("balance={:.3}<0.850", balance));
            }
            if max_frac > max_frac_limit {
                reasons.push(format!(
                    "max={:.1}%>{:.1}%",
                    max_frac * 100.0,
                    max_frac_limit * 100.0
                ));
            }
        }

        serde_json::json!({
            "ok": ok,
            "status": if ok { "pass" } else { "fail" },
            "reason": if reasons.is_empty() { "ok".to_string() } else { reasons.join(", ") },
            "alive": alive,
            "alive_experts": alive,
            "n_experts": n_experts,
            "balance": balance,
            "min_frac": min_frac,
            "min_fraction": min_frac,
            "max_frac": max_frac,
            "max_fraction": max_frac,
            "max_frac_limit": max_frac_limit,
            "max_fraction_limit": max_frac_limit,
            "sample_limited": sample_limited,
            "total": total,
        })
    }

    pub const DREAM_CAPACITY: usize = 256;
    pub const DREAM_SLEEP_INTERVAL: usize = 16;
    pub const DREAM_DECAY: f64 = 0.997;
    pub const DREAM_WRITE_STRENGTH: f64 = 1.0;

    fn hrr_bind(a: &[f32], b: &[f32]) -> Vec<f32> {
        use rustfft::{num_complex::Complex, FftPlanner};
        let n = a.len();
        if n == 0 {
            return vec![];
        }
        let mut planner = FftPlanner::<f32>::new();
        let fft = planner.plan_fft_forward(n);
        let ifft = planner.plan_fft_inverse(n);
        let mut fa: Vec<Complex<f32>> = a.iter().map(|&x| Complex::new(x, 0.0)).collect();
        let mut fb: Vec<Complex<f32>> = b.iter().map(|&x| Complex::new(x, 0.0)).collect();
        fft.process(&mut fa);
        fft.process(&mut fb);
        let mut fc: Vec<Complex<f32>> = fa.iter().zip(fb.iter()).map(|(x, y)| x * y).collect();
        ifft.process(&mut fc);
        let scale = 1.0 / n as f32;
        let mut result: Vec<f32> = fc.iter().map(|c| c.re * scale).collect();
        let norm: f32 = result.iter().map(|x| x * x).sum::<f32>().sqrt().max(1e-8);
        result.iter_mut().for_each(|x| *x /= norm);
        result
    }

    fn hrr_unbind(bound: &[f32], key: &[f32]) -> Vec<f32> {
        let n = key.len();
        let mut inv_key = vec![0.0f32; n];
        inv_key[0] = key[0];
        for i in 1..n {
            inv_key[i] = key[n - i];
        }
        hrr_bind(bound, &inv_key)
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct DreamMemoryEpisodeV2 {
        pub episode_id: usize,
        pub tags: Vec<String>,
        pub success: bool,
        pub imprint_hash: String,
        pub timestamp: f64,
        pub key_vector: Vec<f32>,
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct DreamSemanticRuleV2 {
        pub rule_id: String,
        pub tags: Vec<String>,
        pub confidence: f64,
        pub support_count: usize,
    }

    pub struct HolographicDreamMemoryBankV2 {
        pub dim: usize,
        pub memory_trace: Vec<f32>, // superimposed HRR trace
        pub episodes: Vec<DreamMemoryEpisodeV2>,
        pub semantic_rules: Vec<DreamSemanticRuleV2>,
        pub write_count: usize,
        pub sleep_cycles: usize,
    }

    impl HolographicDreamMemoryBankV2 {
        pub fn new(dim: usize) -> Self {
            Self {
                dim,
                memory_trace: vec![0.0; dim],
                episodes: Vec::new(),
                semantic_rules: Vec::new(),
                write_count: 0,
                sleep_cycles: 0,
            }
        }
        pub fn write(&mut self, key: &[f32], tags: Vec<String>, success: bool) {
            let value = key.to_vec(); // self-associative
            let bound = hrr_bind(key, &value);
            for (i, v) in self.memory_trace.iter_mut().enumerate() {
                *v = (*v * DREAM_DECAY as f32) + (bound[i] * DREAM_WRITE_STRENGTH as f32);
            }
            let hash = format!("{:016x}", {
                let mut h = 0u64;
                for &b in key.iter().take(8) {
                    h = h.wrapping_mul(31).wrapping_add(b.to_bits() as u64);
                }
                h
            });
            self.episodes.push(DreamMemoryEpisodeV2 {
                episode_id: self.write_count,
                tags,
                success,
                imprint_hash: hash,
                timestamp: self.write_count as f64,
                key_vector: key.to_vec(),
            });
            if self.episodes.len() > DREAM_CAPACITY {
                self.episodes.remove(0);
            }
            self.write_count += 1;
            if self.write_count.is_multiple_of(DREAM_SLEEP_INTERVAL) {
                self.sleep_consolidate();
            }
        }
        pub fn read(&self, query: &[f32]) -> Vec<f32> {
            hrr_unbind(&self.memory_trace, query)
        }
        pub fn sleep_consolidate(&mut self) {
            self.sleep_cycles += 1;
            let mut tag_counts: HashMap<String, usize> = HashMap::new();
            let mut tag_success: HashMap<String, usize> = HashMap::new();
            for ep in &self.episodes {
                for tag in &ep.tags {
                    *tag_counts.entry(tag.clone()).or_default() += 1;
                    if ep.success {
                        *tag_success.entry(tag.clone()).or_default() += 1;
                    }
                }
            }
            for (tag, &count) in &tag_counts {
                if count >= 2 {
                    let success = tag_success.get(tag).copied().unwrap_or(0);
                    let confidence = success as f64 / count as f64;
                    if confidence >= 0.65 {
                        let exists = self.semantic_rules.iter().any(|r| r.tags.contains(tag));
                        if !exists {
                            self.semantic_rules.push(DreamSemanticRuleV2 {
                                rule_id: format!("rule_{}", self.semantic_rules.len()),
                                tags: vec![tag.clone()],
                                confidence,
                                support_count: count,
                            });
                        }
                    }
                }
            }
        }

        pub fn report(&self) -> HashMap<String, serde_json::Value> {
            HashMap::from([
                ("dim".into(), serde_json::json!(self.dim)),
                ("episodes".into(), serde_json::json!(self.episodes.len())),
                (
                    "semantic_rules".into(),
                    serde_json::json!(self.semantic_rules.len()),
                ),
                ("write_count".into(), serde_json::json!(self.write_count)),
                ("sleep_cycles".into(), serde_json::json!(self.sleep_cycles)),
                (
                    "trace_norm".into(),
                    serde_json::json!(self.memory_trace.iter().map(|x| x * x).sum::<f32>().sqrt()),
                ),
            ])
        }
        pub fn read_cosine_top_k(&self, query: &[f32], k: usize) -> Vec<(usize, f32)> {
            let query_norm: f32 = query.iter().map(|x| x * x).sum::<f32>().sqrt().max(1e-8);
            let mut scores: Vec<(usize, f32)> = self
                .episodes
                .iter()
                .enumerate()
                .map(|(i, ep)| {
                    let dot: f32 = ep
                        .key_vector
                        .iter()
                        .zip(query.iter())
                        .map(|(a, b)| a * b)
                        .sum();
                    let ep_norm: f32 = ep
                        .key_vector
                        .iter()
                        .map(|x| x * x)
                        .sum::<f32>()
                        .sqrt()
                        .max(1e-8);
                    (i, dot / (query_norm * ep_norm))
                })
                .collect();
            scores.sort_by(|a, b| b.1.total_cmp(&a.1));
            scores.into_iter().take(k).collect()
        }
        pub fn prune_interference(&mut self, threshold: f64) {
            let trace = &self.memory_trace;
            self.episodes.retain(|ep| {
                let unbound = hrr_unbind(trace, &ep.key_vector);
                let similarity: f32 = unbound
                    .iter()
                    .zip(ep.key_vector.iter())
                    .map(|(a, b)| a * b)
                    .sum::<f32>();
                let norm_a: f32 = unbound.iter().map(|x| x * x).sum::<f32>().sqrt().max(1e-8);
                let norm_b: f32 = ep
                    .key_vector
                    .iter()
                    .map(|x| x * x)
                    .sum::<f32>()
                    .sqrt()
                    .max(1e-8);
                let cosine = (similarity / (norm_a * norm_b)) as f64;
                cosine >= threshold
            });
        }
        pub fn dream_verify(&self) -> (usize, usize, Vec<String>) {
            let mut passed = 0usize;
            let mut details = Vec::new();
            let trace_norm: f32 = self.memory_trace.iter().map(|x| x * x).sum::<f32>().sqrt();
            if trace_norm < 1e6 {
                passed += 1;
                details.push(format!("✓ trace_norm={:.4} bounded", trace_norm));
            } else {
                details.push(format!("✗ trace_norm={:.4} UNBOUNDED", trace_norm));
            }
            let mut hashes: HashSet<String> = HashSet::new();
            let unique = self
                .episodes
                .iter()
                .all(|ep| hashes.insert(ep.imprint_hash.clone()));
            if unique {
                passed += 1;
                details.push("✓ no duplicate episode hashes".into());
            } else {
                details.push("✗ duplicate episode hashes found".into());
            }
            let rules_ok = self
                .semantic_rules
                .iter()
                .all(|r| r.confidence > 0.0 && r.confidence <= 1.0);
            if rules_ok {
                passed += 1;
                details.push(format!(
                    "✓ {} semantic rules all valid",
                    self.semantic_rules.len()
                ));
            } else {
                details.push("✗ invalid semantic rule confidence".into());
            }
            if self.episodes.len() <= DREAM_CAPACITY {
                passed += 1;
                details.push(format!(
                    "✓ episodes={} <= capacity={}",
                    self.episodes.len(),
                    DREAM_CAPACITY
                ));
            } else {
                details.push(format!(
                    "✗ episodes={} > capacity={}",
                    self.episodes.len(),
                    DREAM_CAPACITY
                ));
            }

            (passed, 4, details)
        }
    }

    pub const RSI_ARCHIVE_SIZE: usize = 32;
    pub const RSI_MUTATION_RATE: f64 = 0.1;
    pub const RSI_ELITE_FRACTION: f64 = 0.25;

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct HyperAgentGenomeV2 {
        pub genome_id: usize,
        pub lr_scale: f64,
        pub grad_clip_scale: f64,
        pub loss_weight_modifiers: Vec<f64>, // per-head loss weight mods
        pub fitness: f64,
        pub generation: usize,
        pub parent_id: Option<usize>,
        pub safety_cleared: bool,
    }

    impl HyperAgentGenomeV2 {
        pub fn random(id: usize, rng: &mut impl rand::Rng) -> Self {
            Self {
                genome_id: id,
                lr_scale: 0.5 + rng.gen::<f64>(),
                grad_clip_scale: 0.5 + rng.gen::<f64>(),
                loss_weight_modifiers: (0..JARVIS_NATIVE_HEAD_COUNT)
                    .map(|_| 0.8 + 0.4 * rng.gen::<f64>())
                    .collect(),
                fitness: 0.0,
                generation: 0,
                parent_id: None,
                safety_cleared: false,
            }
        }

        pub fn mutate(&self, id: usize, rng: &mut impl rand::Rng) -> Self {
            let mut child = self.clone();
            child.genome_id = id;
            child.parent_id = Some(self.genome_id);
            child.generation = self.generation + 1;
            child.fitness = 0.0;
            child.safety_cleared = false;
            if rng.gen::<f64>() < RSI_MUTATION_RATE {
                child.lr_scale *= 0.8 + 0.4 * rng.gen::<f64>();
            }
            if rng.gen::<f64>() < RSI_MUTATION_RATE {
                child.grad_clip_scale *= 0.8 + 0.4 * rng.gen::<f64>();
            }
            for w in &mut child.loss_weight_modifiers {
                if rng.gen::<f64>() < RSI_MUTATION_RATE {
                    *w *= 0.8 + 0.4 * rng.gen::<f64>();
                }
            }
            child.lr_scale = child.lr_scale.clamp(0.1, 5.0);
            child.grad_clip_scale = child.grad_clip_scale.clamp(0.1, 5.0);
            child
        }
        pub fn safety_check(&mut self) -> bool {
            let ok = self.lr_scale > 0.05
                && self.lr_scale < 10.0
                && self.grad_clip_scale > 0.05
                && self.grad_clip_scale < 10.0
                && self
                    .loss_weight_modifiers
                    .iter()
                    .all(|&w| w > 0.01 && w < 10.0);
            self.safety_cleared = ok;
            ok
        }
    }

    pub struct HyperAgentArchiveV2 {
        pub genomes: Vec<HyperAgentGenomeV2>,
        pub next_id: usize,
        pub best_fitness: f64,
        pub generations_run: usize,
    }

    impl Default for HyperAgentArchiveV2 {
        fn default() -> Self {
            Self::new()
        }
    }

    impl HyperAgentArchiveV2 {
        pub fn new() -> Self {
            Self {
                genomes: Vec::new(),
                next_id: 0,
                best_fitness: f64::NEG_INFINITY,
                generations_run: 0,
            }
        }

        pub fn seed(&mut self, count: usize, seed: u64) {
            use rand::SeedableRng;
            let mut rng = rand::rngs::StdRng::seed_from_u64(seed);
            for _ in 0..count {
                let g = HyperAgentGenomeV2::random(self.next_id, &mut rng);
                self.next_id += 1;
                self.genomes.push(g);
            }
        }
        pub fn evolve(&mut self, seed: u64) {
            use rand::SeedableRng;
            let mut rng = rand::rngs::StdRng::seed_from_u64(seed);
            self.genomes.sort_by(|a, b| b.fitness.total_cmp(&a.fitness));
            let elite_n = ((self.genomes.len() as f64) * RSI_ELITE_FRACTION).ceil() as usize;
            let elite: Vec<HyperAgentGenomeV2> =
                self.genomes.iter().take(elite_n).cloned().collect();
            if let Some(best) = elite.first() {
                self.best_fitness = best.fitness;
            }
            let mut next_gen = elite.clone();
            while next_gen.len() < RSI_ARCHIVE_SIZE {
                let parent = &elite[next_gen.len() % elite.len()];
                let mut child = parent.mutate(self.next_id, &mut rng);
                self.next_id += 1;
                child.safety_check();
                next_gen.push(child);
            }
            self.genomes = next_gen;
            self.generations_run += 1;
        }

        pub fn report(&self) -> HashMap<String, serde_json::Value> {
            let safe = self.genomes.iter().filter(|g| g.safety_cleared).count();
            HashMap::from([
                ("archive_size".into(), serde_json::json!(self.genomes.len())),
                ("best_fitness".into(), serde_json::json!(self.best_fitness)),
                (
                    "generations".into(),
                    serde_json::json!(self.generations_run),
                ),
                ("safety_cleared".into(), serde_json::json!(safe)),
                ("next_id".into(), serde_json::json!(self.next_id)),
            ])
        }
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
