    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct GovernanceDecisionV2 {
        pub action_id: usize,
        pub risk_score: f64,
        pub alignment_score: f64,
        pub approved: bool,
        pub reason: String,
    }

    pub struct ASIGovernancePolicyV2 {
        pub risk_threshold: f64,
        pub alignment_min: f64,
        pub shutdown_threshold: f64,
        pub decisions: Vec<GovernanceDecisionV2>,
        pub total_approved: usize,
        pub total_rejected: usize,
    }

    impl Default for ASIGovernancePolicyV2 {
        fn default() -> Self {
            Self::new()
        }
    }

    impl ASIGovernancePolicyV2 {
        pub fn new() -> Self {
            Self {
                risk_threshold: 0.7,
                alignment_min: 0.3,
                shutdown_threshold: 0.9,
                decisions: Vec::new(),
                total_approved: 0,
                total_rejected: 0,
            }
        }

        pub fn evaluate(&mut self, action_id: usize, risk: f64, alignment: f64) -> bool {
            let approved = risk < self.risk_threshold
                && alignment > self.alignment_min
                && risk < self.shutdown_threshold;
            let reason = if approved {
                "within_bounds"
            } else if risk >= self.shutdown_threshold {
                "shutdown_triggered"
            } else if risk >= self.risk_threshold {
                "risk_exceeded"
            } else {
                "alignment_insufficient"
            };
            self.decisions.push(GovernanceDecisionV2 {
                action_id,
                risk_score: risk,
                alignment_score: alignment,
                approved,
                reason: reason.into(),
            });
            if approved {
                self.total_approved += 1;
            } else {
                self.total_rejected += 1;
            }
            approved
        }

        pub fn monitorability_proxy(&self) -> f64 {
            if self.decisions.is_empty() {
                return 1.0;
            }
            let avg_alignment: f64 = self
                .decisions
                .iter()
                .map(|d| d.alignment_score)
                .sum::<f64>()
                / self.decisions.len() as f64;
            let approval_rate = self.total_approved as f64
                / (self.total_approved + self.total_rejected).max(1) as f64;
            0.5 * avg_alignment + 0.5 * approval_rate
        }

        pub fn report(&self) -> HashMap<String, serde_json::Value> {
            HashMap::from([
                (
                    "total_approved".into(),
                    serde_json::json!(self.total_approved),
                ),
                (
                    "total_rejected".into(),
                    serde_json::json!(self.total_rejected),
                ),
                (
                    "monitorability".into(),
                    serde_json::json!(self.monitorability_proxy()),
                ),
                (
                    "risk_threshold".into(),
                    serde_json::json!(self.risk_threshold),
                ),
                ("decisions".into(), serde_json::json!(self.decisions.len())),
            ])
        }
    }

    pub struct EMAModel {
        pub shadow: HashMap<String, Tensor>,
        pub shapes: HashMap<String, Vec<usize>>,
        pub target_decay: f64,
        pub decay: f64,
        pub updates: usize,
    }
    impl EMAModel {
        pub fn new(decay: f64) -> Self {
            Self {
                shadow: HashMap::new(),
                shapes: HashMap::new(),
                target_decay: decay,
                decay,
                updates: 0,
            }
        }

        fn update_shadow_tensor(&mut self, name: &str, params: &Tensor) -> CResult<()> {
            let params = params.to_dtype(DType::F32)?.detach();
            let shape = params.dims().to_vec();
            if let Some(shadow) = self.shadow.get_mut(name) {
                let updated = ((&*shadow * self.decay)? + (params * (1.0 - self.decay))?)?.detach();
                *shadow = updated;
            } else {
                self.shadow.insert(name.to_string(), params);
            }
            self.shapes.insert(name.to_string(), shape);
            Ok(())
        }

        pub fn update(&mut self, name: &str, params: &[f32]) -> CResult<()> {
            let tensor = Tensor::from_slice(params, params.len(), &Device::Cpu)?;
            self.update_shadow_tensor(name, &tensor)?;
            self.updates += 1;
            Ok(())
        }

        pub fn update_named_tensors(&mut self, params: &[(String, Tensor)]) -> CResult<()> {
            for (name, tensor) in params {
                self.update_shadow_tensor(name, tensor)?;
            }
            self.updates += 1;
            Ok(())
        }

        pub fn get_decay(&self, step: usize, total_steps: usize) -> f64 {
            let warmup = ((total_steps as f64) * 0.10).max(1.0) as usize;
            if step < warmup {
                0.99 + (self.target_decay - 0.99) * step as f64 / warmup.max(1) as f64
            } else {
                self.target_decay
            }
        }

        pub fn divergence_named_tensors(&self, params: &[(String, Tensor)]) -> CResult<f64> {
            let mut squared_norms = Vec::with_capacity(params.len());
            for (name, tensor) in params {
                let Some(shadow) = self.shadow.get(name) else {
                    continue;
                };
                squared_norms.push((tensor.to_dtype(DType::F32)? - shadow)?.sqr()?.sum_all()?);
            }
            if squared_norms.is_empty() {
                return Ok(0.0);
            }
            let total = Tensor::stack(&squared_norms, 0)?.sum_all()?.sqrt()?;
            Ok(total.to_scalar::<f32>()? as f64)
        }

        pub fn get(&self, name: &str) -> Option<&Tensor> {
            self.shadow.get(name)
        }
        pub fn report(&self) -> HashMap<String, serde_json::Value> {
            HashMap::from([
                ("decay".into(), serde_json::json!(self.decay)),
                ("target_decay".into(), serde_json::json!(self.target_decay)),
                ("updates".into(), serde_json::json!(self.updates)),
                ("params".into(), serde_json::json!(self.shadow.len())),
                ("shape_count".into(), serde_json::json!(self.shapes.len())),
            ])
        }
    }

