    impl EMAModel {
        pub fn deploy_safetensors(&self, path: &str) -> Result<(), String> {
            const CHECKPOINT_DECIMAL_PLACES: i32 = 5;
            let mut tensors: HashMap<String, Tensor> = HashMap::new();
            for (name, tensor) in &self.shadow {
                let tensor = tensor
                    .to_device(&Device::Cpu)
                    .and_then(|tensor| tensor.to_dtype(DType::F32))
                    .and_then(|tensor| tensor.round_to(CHECKPOINT_DECIMAL_PLACES))
                    .map_err(|e| format!("Failed to materialize EMA tensor {}: {}", name, e))?;
                tensors.insert(name.clone(), tensor);
            }
            candle_core::safetensors::save(&tensors, path)
                .map_err(|e| format!("Failed to write EMA safetensors: {}", e))?;
            let data = serde_json::json!({
                "ema_decay": self.decay,
                "ema_updates": self.updates,
                "param_count": self.shadow.len(),
                "shape_count": self.shapes.len(),
                "deploy_path": path,
                "deterministic_canonicalization": {
                    "dtype": "f32",
                    "decimal_places": CHECKPOINT_DECIMAL_PLACES,
                    "purpose": "remove sub-micro floating reduction jitter from portable checkpoint bytes",
                },
            });
            let json_path = format!("{}.meta.json", path);
            let meta_bytes = serde_json::to_vec_pretty(&data)
                .map_err(|e| format!("Failed to encode EMA meta: {}", e))?;
            framework_atomic_write_bytes(Path::new(&json_path), &meta_bytes)
                .map_err(|e| format!("Failed to write EMA meta: {}", e))?;
            Ok(())
        }
    }

    pub struct RotorPositionEncoding {
        pub dim: usize,
        pub max_len: usize,
        pub cos_cache: Vec<f32>,
        pub sin_cache: Vec<f32>,
    }
    impl RotorPositionEncoding {
        pub fn new(dim: usize, max_len: usize, base: f64) -> Self {
            let half = dim / 2;
            let mut cos_cache = vec![0.0f32; max_len * half];
            let mut sin_cache = vec![0.0f32; max_len * half];
            for pos in 0..max_len {
                for i in 0..half {
                    let theta = (pos as f64) / base.powf(2.0 * i as f64 / dim as f64);
                    cos_cache[pos * half + i] = theta.cos() as f32;
                    sin_cache[pos * half + i] = theta.sin() as f32;
                }
            }
            Self {
                dim,
                max_len,
                cos_cache,
                sin_cache,
            }
        }
        pub fn apply(&self, x: &[f32], pos: usize) -> Vec<f32> {
            let half = self.dim / 2;
            let mut out = x.to_vec();
            if pos < self.max_len {
                for i in 0..half.min(x.len() / 2) {
                    let c = self.cos_cache[pos * half + i];
                    let s = self.sin_cache[pos * half + i];
                    let x0 = x[2 * i];
                    let x1 = x[2 * i + 1];
                    out[2 * i] = x0 * c - x1 * s;
                    out[2 * i + 1] = x0 * s + x1 * c;
                }
            }
            out
        }
    }

    pub struct GeometricKVCache {
        pub key_cache: Vec<Vec<f32>>,
        pub value_cache: Vec<Vec<f32>>,
        pub max_len: usize,
        pub head_dim: usize,
        pub n_heads: usize,
    }
    impl GeometricKVCache {
        pub fn new(max_len: usize, n_heads: usize, head_dim: usize) -> Self {
            Self {
                key_cache: Vec::new(),
                value_cache: Vec::new(),
                max_len,
                head_dim,
                n_heads,
            }
        }
        pub fn append(&mut self, key: Vec<f32>, value: Vec<f32>) {
            self.key_cache.push(key);
            self.value_cache.push(value);
            if self.key_cache.len() > self.max_len {
                self.key_cache.remove(0);
                self.value_cache.remove(0);
            }
        }
        pub fn len(&self) -> usize {
            self.key_cache.len()
        }
        pub fn is_empty(&self) -> bool {
            self.key_cache.is_empty()
        }
        pub fn clear(&mut self) {
            self.key_cache.clear();
            self.value_cache.clear();
        }
    }

    pub struct JarvisLayerKVCache {
        pub key: Option<Tensor>,
        pub value: Option<Tensor>,
    }

    pub struct JarvisTensorKVCache {
        pub layers: Vec<JarvisLayerKVCache>,
        token_frames: Vec<Tensor>,
        max_len: usize,
    }

    impl JarvisTensorKVCache {
        pub fn new(n_layers: usize, max_len: usize) -> Self {
            let layers = (0..n_layers)
                .map(|_| JarvisLayerKVCache {
                    key: None,
                    value: None,
                })
                .collect();
            Self {
                layers,
                token_frames: Vec::new(),
                max_len: max_len.max(1),
            }
        }

        pub fn append_token_frame(&mut self, frame: &Tensor) {
            self.token_frames.push(frame.clone());
            if self.token_frames.len() > self.max_len {
                self.token_frames.remove(0);
            }
        }

        pub fn set_layer_kv(&mut self, layer_idx: usize, key: Tensor, value: Tensor) {
            if let Some(layer) = self.layers.get_mut(layer_idx) {
                layer.key = Some(key);
                layer.value = Some(value);
            }
        }

        pub fn len(&self) -> usize {
            self.token_frames.len()
        }

        pub fn is_empty(&self) -> bool {
            self.token_frames.is_empty()
        }

        pub fn clear(&mut self) {
            self.token_frames.clear();
            for layer in &mut self.layers {
                layer.key = None;
                layer.value = None;
            }
        }

        pub fn sequence_tensor(&self) -> CResult<Option<Tensor>> {
            if self.token_frames.is_empty() {
                return Ok(None);
            }
            Ok(Some(Tensor::cat(&self.token_frames, 1)?))
        }
    }

