    pub struct SparseGatedFFN {
        up: Linear,
        gate: Linear,
        down: Linear,
    }

    impl SparseGatedFFN {
        pub fn new(dim: usize, hidden: usize, vb: VarBuilder) -> CResult<Self> {
            Ok(Self {
                up: linear(dim, hidden, vb.pp("up"))?,
                gate: linear(dim, hidden, vb.pp("gate"))?,
                down: linear(hidden, dim, vb.pp("down"))?,
            })
        }
        pub fn gate_l1(&self, x: &Tensor) -> CResult<Tensor> {
            let gate_act = self.gate.forward(x)?.relu()?;
            gate_act.abs()?.mean_all()
        }
    }
    impl Module for SparseGatedFFN {
        fn forward(&self, x: &Tensor) -> CResult<Tensor> {
            let up = self.up.forward(x)?;
            let gate = self.gate.forward(x)?.relu()?;
            self.down.forward(&(up * gate)?)
        }
    }

    pub struct MultiLatentAttention {
        n_head: usize,
        head_dim: usize,
        q_proj: Linear,      // (n_embd → n_head * head_dim)
        kv_compress: Linear, // (n_embd → kv_lora_rank)
        kv_expand: Linear,   // (kv_lora_rank → 2 * n_head * head_dim)
        no_proj: Linear,     // (n_head * head_dim → n_embd)
        q_norm: RMSNorm,     // QK norm
        k_norm: RMSNorm,
        lambda_init: Tensor,
        rope_cos: Tensor, // (max_len, head_dim/2) precomputed cos
        rope_sin: Tensor, // (max_len, head_dim/2) precomputed sin
    }

    impl MultiLatentAttention {
        pub fn new(
            dim: usize,
            n_head: usize,
            kv_lora_rank: usize,
            max_len: usize,
            vb: VarBuilder,
        ) -> CResult<Self> {
            if n_head == 0 || !dim.is_multiple_of(n_head) {
                candle_core::bail!(
                    "attention dim {} must be divisible by non-zero head count {}",
                    dim,
                    n_head
                )
            }
            let head_dim = dim / n_head;
            if !head_dim.is_multiple_of(2) {
                candle_core::bail!("RoPE head dimension {} must be even", head_dim)
            }
            let kv_lora_rank = kv_lora_rank.max(1);
            let q_proj = linear(dim, n_head * head_dim, vb.pp("q"))?;
            let kv_compress = linear(dim, kv_lora_rank, vb.pp("kv_compress"))?;
            let kv_expand = linear(kv_lora_rank, 2 * n_head * head_dim, vb.pp("kv_expand"))?;
            let no_proj = linear(n_head * head_dim, dim, vb.pp("o"))?;
            let q_norm = RMSNorm::new(head_dim, 1e-6, vb.pp("q_norm"))?;
            let k_norm = RMSNorm::new(head_dim, 1e-6, vb.pp("k_norm"))?;
            let lambda_init = vb.get_with_hints((1,), "lambda", candle_nn::Init::Const(0.8))?;
            let max_len = max_len.max(1);
            let rope_base = 10000.0f64;
            let half = head_dim / 2;
            let mut cos_data = vec![0.0f32; max_len * half];
            let mut sin_data = vec![0.0f32; max_len * half];
            for pos in 0..max_len {
                for i in 0..half {
                    let theta = (pos as f64) / rope_base.powf(2.0 * i as f64 / head_dim as f64);
                    cos_data[pos * half + i] = theta.cos() as f32;
                    sin_data[pos * half + i] = theta.sin() as f32;
                }
            }
            let device = vb.device();
            let rope_cos = Tensor::from_vec(cos_data, (max_len, half), device)?;
            let rope_sin = Tensor::from_vec(sin_data, (max_len, half), device)?;
            Ok(Self {
                n_head,
                head_dim,
                q_proj,
                kv_compress,
                kv_expand,
                no_proj,
                q_norm,
                k_norm,
                lambda_init,
                rope_cos,
                rope_sin,
            })
        }

        pub fn forward(&self, x: &Tensor, causal_mask: Option<&Tensor>) -> CResult<Tensor> {
            let (b, t, _d) = x.dims3()?;
            let nh = self.n_head;
            let hd = self.head_dim;
            let q = self
                .q_proj
                .forward(x)?
                .reshape((b, t, nh, hd))?
                .transpose(1, 2)?;
            let kv_compressed = self.kv_compress.forward(x)?;
            let kv = self.kv_expand.forward(&kv_compressed)?;
            let k = kv
                .narrow(D::Minus1, 0, nh * hd)?
                .reshape((b, t, nh, hd))?
                .transpose(1, 2)?;
            let v = kv
                .narrow(D::Minus1, nh * hd, nh * hd)?
                .reshape((b, t, nh, hd))?
                .transpose(1, 2)?;
            let q = self.apply_head_norm(&self.q_norm, &q)?;
            let k = self.apply_head_norm(&self.k_norm, &k)?;
            let q = self.apply_rope(&q, t)?;
            let k = self.apply_rope(&k, t)?;
            let scale = (hd as f64).sqrt().recip();
            let mut scores = (q.matmul(&k.transpose(2, 3)?)? * scale)?;
            scores = ((scores / ATTN_SOFT_CAP as f64)?.tanh()? * ATTN_SOFT_CAP as f64)?;
            if let Some(mask) = causal_mask {
                let t_mask = t.min(mask.dim(0)?);
                let mask = mask.narrow(0, 0, t_mask)?.narrow(1, 0, t_mask)?;
                let mask = mask.unsqueeze(0)?.unsqueeze(0)?; // (1, 1, T, T)
                let mask = mask.broadcast_as(scores.shape())?;
                scores = (scores + mask)?;
            }
            let lambda = candle_nn::ops::sigmoid(&self.lambda_init)?.reshape((1, 1, 1, 1))?;
            let half_nh = nh / 2;
            if half_nh > 0 && nh >= 2 {
                let scores1 = scores.narrow(1, 0, half_nh)?.contiguous()?;
                let scores2 = scores.narrow(1, half_nh, nh - half_nh)?.contiguous()?;
                let attn1 = candle_nn::ops::softmax(&scores1, D::Minus1)?;
                let attn2 = candle_nn::ops::softmax(&scores2, D::Minus1)?;
                let diff_attn = (attn1 - attn2.broadcast_mul(&lambda)?)?;
                let v_half = v.narrow(1, 0, half_nh)?.contiguous()?;
                let out = diff_attn.contiguous()?.matmul(&v_half)?;
                let out = out
                    .transpose(1, 2)?
                    .contiguous()?
                    .reshape((b, t, half_nh * hd))?;
                let zeros = Tensor::zeros((b, t, half_nh * hd), out.dtype(), out.device())?;
                let padded = Tensor::cat(&[out, zeros], D::Minus1)?;
                self.no_proj.forward(&padded)
            } else {
                let attn = candle_nn::ops::softmax(&scores, D::Minus1)?;
                let out = attn
                    .contiguous()?
                    .matmul(&v.contiguous()?)?
                    .transpose(1, 2)?
                    .contiguous()?
                    .reshape((b, t, nh * hd))?;
                self.no_proj.forward(&out)
            }
        }
        fn apply_head_norm(&self, norm: &RMSNorm, x: &Tensor) -> CResult<Tensor> {
            let (b, nh, t, hd) = x.dims4()?;
            let flat = x.reshape((b * nh * t, hd))?;
            let normed = norm.forward(&flat)?;
            normed.reshape((b, nh, t, hd))
        }
        fn apply_rope(&self, x: &Tensor, seq_len: usize) -> CResult<Tensor> {
            let (b, nh, t, hd) = x.dims4()?;
            let half = hd / 2;
            if half == 0 || t == 0 {
                return Ok(x.clone());
            }
            let t_actual = t.min(seq_len);
            let cos = self.rope_cos.narrow(0, 0, t_actual)?;
            let sin = self.rope_sin.narrow(0, 0, t_actual)?;
            let cos = cos.unsqueeze(0)?.unsqueeze(0)?;
            let sin = sin.unsqueeze(0)?.unsqueeze(0)?;
            let x_pairs = x.reshape((b, nh, t_actual, half, 2))?;
            let x_even = x_pairs.narrow(4, 0, 1)?.squeeze(4)?; // (B, nh, T, half)
            let x_odd = x_pairs.narrow(4, 1, 1)?.squeeze(4)?; // (B, nh, T, half)
            let rotated_even = (x_even.broadcast_mul(&cos)? - x_odd.broadcast_mul(&sin)?)?;
            let rotated_odd = (x_even.broadcast_mul(&sin)? + x_odd.broadcast_mul(&cos)?)?;
            let even_exp = rotated_even.unsqueeze(4)?; // (B, nh, T, half, 1)
            let odd_exp = rotated_odd.unsqueeze(4)?; // (B, nh, T, half, 1)
            let interleaved = Tensor::cat(&[even_exp, odd_exp], 4)?; // (B, nh, T, half, 2)
            interleaved.reshape((b, nh, t_actual, hd))
        }
    }

    pub struct GeometricTransformerBlock {
        attn_norm: AdaptiveLayerNorm,
        attn: MultiLatentAttention,
        ffn_norm: RMSNorm,
        ffn_dense: Option<SparseGatedFFN>,
        pub(crate) ffn_moe: Option<SinkhornMoELayerV2>,
        pub is_moe: bool,
        pub layer_idx: usize,
    }

    impl GeometricTransformerBlock {
        pub fn new(
            dim: usize,
            n_head: usize,
            kv_lora_rank: usize,
            max_len: usize,
            n_experts: usize,
            expert_top_k: usize,
            n_shared_experts: usize,
            ffn_hidden: usize,
            layer_idx: usize,
            vb: VarBuilder,
        ) -> CResult<Self> {
            let attn_norm = AdaptiveLayerNorm::new(dim, 1e-6, vb.pp("attn_norm"))?;
            let attn =
                MultiLatentAttention::new(dim, n_head, kv_lora_rank, max_len, vb.pp("attn"))?;
            let ffn_norm = RMSNorm::new(dim, 1e-6, vb.pp("ffn_norm"))?;
            let is_moe = layer_idx % 2 == 1;
            let (ffn_dense, ffn_moe) = if is_moe {
                let moe = SinkhornMoELayerV2::new(
                    dim,
                    n_experts,
                    expert_top_k,
                    n_shared_experts,
                    vb.pp("moe"),
                )?;
                (None, Some(moe))
            } else {
                let ffn = SparseGatedFFN::new(dim, ffn_hidden, vb.pp("ffn"))?;
                (Some(ffn), None)
            };
            Ok(Self {
                attn_norm,
                attn,
                ffn_norm,
                ffn_dense,
                ffn_moe,
                is_moe,
                layer_idx,
            })
        }

        pub fn forward(&self, x: &Tensor, causal_mask: Option<&Tensor>) -> CResult<Tensor> {
            let h = self
                .attn
                .forward(&self.attn_norm.forward(x)?, causal_mask)?;
            let x = (x + h)?;
            let normed = self.ffn_norm.forward(&x)?;
            let h = if let Some(ref ffn) = self.ffn_dense {
                ffn.forward(&normed)?
            } else if let Some(ref moe) = self.ffn_moe {
                let (b, t, d) = normed.dims3()?;
                moe.forward(&normed.reshape((b * t, d))?)?
                    .reshape((b, t, d))?
            } else {
                normed // fallback (should not happen)
            };
            x + h
        }
        pub fn forward_train(
            &mut self,
            x: &Tensor,
            causal_mask: Option<&Tensor>,
        ) -> CResult<Tensor> {
            let h = self
                .attn
                .forward(&self.attn_norm.forward(x)?, causal_mask)?;
            let x = (x + h)?;
            let normed = self.ffn_norm.forward(&x)?;
            let h = if let Some(ref ffn) = self.ffn_dense {
                ffn.forward(&normed)?
            } else if let Some(ref mut moe) = self.ffn_moe {
                let (b, t, d) = normed.dims3()?;
                moe.forward_train(&normed.reshape((b * t, d))?)?
                    .reshape((b, t, d))?
            } else {
                normed
            };
            x + h
        }
    }

    pub struct CayleyResMLPBlock {
        ln: candle_nn::LayerNorm,
        ffn: SparseGatedFFN,
    }

    impl CayleyResMLPBlock {
        pub fn new(dim: usize, hidden: usize, vb: VarBuilder) -> CResult<Self> {
            let ln =
                candle_nn::layer_norm(dim, candle_nn::LayerNormConfig::default(), vb.pp("ln"))?;
            let ffn = SparseGatedFFN::new(dim, hidden, vb.pp("ffn"))?;
            Ok(Self { ln, ffn })
        }
    }
    impl Module for CayleyResMLPBlock {
        fn forward(&self, x: &Tensor) -> CResult<Tensor> {
            let normed = self.ln.forward(x)?;
            let out = self.ffn.forward(&normed)?;
            x + out
        }
    }
    pub struct TrunkMLP {
        norm: RMSNorm,
        linear1: Linear,
        linear2: Linear,
    }
    impl TrunkMLP {
        pub fn new(input_dim: usize, vb: VarBuilder) -> CResult<Self> {
            let norm = RMSNorm::new(input_dim, 1e-6, vb.pp("norm"))?;
            let linear1 = linear(input_dim, JARVIS_TRUNK_DIM, vb.pp("linear1"))?;
            let linear2 = linear(JARVIS_TRUNK_DIM, JARVIS_TRUNK_DIM, vb.pp("linear2"))?;
            Ok(Self {
                norm,
                linear1,
                linear2,
            })
        }
    }
    impl Module for TrunkMLP {
        fn forward(&self, x: &Tensor) -> CResult<Tensor> {
            let h = self.norm.forward(x)?;
            let h = self.linear1.forward(&h)?.silu()?;
            self.linear2.forward(&h)?.silu()
        }
    }
    pub struct JarvisNativeHeads {
        pub language_head: Linear,      // 64 → configured input vocabulary
        pub fast_action_head: Linear,   // 64 → 12
        pub slow_action_head: Linear,   // 64 → 12
        pub gate_head: Linear,          // 64+12 → 1
        pub tool_route_head: Linear,    // 64 → 5
        pub value_head: Linear,         // 64 → 1
        pub board_status_head: Linear,  // 64 → 9
        pub board_profile_head: Linear, // 64 → 8
        pub skill_head: Linear,         // 64 → 16
        pub memory_write_head: Linear,  // 64 → 64
        pub proof_head: Linear,         // 64 → 6
        pub governance_head: Linear,    // 64 → 8
        pub reward_head: Linear,        // 64 → 12
        pub runtime_head: Linear,       // 64 → 7
        pub lane_head: Linear,          // 64 → 4
        pub blueprint_head: Linear,     // 64 → 8
        pub world_model_head: Linear,   // 64 → configured input vocabulary
    }
    impl JarvisNativeHeads {
        pub fn new(vocab_size: usize, vb: VarBuilder) -> CResult<Self> {
            Ok(Self {
                language_head: linear(JARVIS_TRUNK_DIM, vocab_size, vb.pp("language"))?,
                fast_action_head: linear(
                    JARVIS_TRUNK_DIM,
                    JARVIS_NATIVE_ACTION_COUNT,
                    vb.pp("fast_action"),
                )?,
                slow_action_head: linear(
                    JARVIS_TRUNK_DIM,
                    JARVIS_NATIVE_ACTION_COUNT,
                    vb.pp("slow_action"),
                )?,
                gate_head: linear(
                    JARVIS_TRUNK_DIM + JARVIS_NATIVE_GATE_FEATURES,
                    1,
                    vb.pp("gate"),
                )?,
                tool_route_head: linear(
                    JARVIS_TRUNK_DIM,
                    JARVIS_NATIVE_TOOL_COUNT,
                    vb.pp("tool_route"),
                )?,
                value_head: linear(JARVIS_TRUNK_DIM, 1, vb.pp("value"))?,
                board_status_head: linear(
                    JARVIS_TRUNK_DIM,
                    JARVIS_NATIVE_BOARD_STATUS,
                    vb.pp("board_status"),
                )?,
                board_profile_head: linear(
                    JARVIS_TRUNK_DIM,
                    JARVIS_NATIVE_PROFILE_DIM,
                    vb.pp("board_profile"),
                )?,
                skill_head: linear(JARVIS_TRUNK_DIM, JARVIS_NATIVE_SKILL_COUNT, vb.pp("skill"))?,
                memory_write_head: linear(
                    JARVIS_TRUNK_DIM,
                    JARVIS_NATIVE_MEMORY_SLOTS,
                    vb.pp("memory_write"),
                )?,
                proof_head: linear(JARVIS_TRUNK_DIM, JARVIS_NATIVE_PROOF_DIM, vb.pp("proof"))?,
                governance_head: linear(
                    JARVIS_TRUNK_DIM,
                    JARVIS_NATIVE_GOVERNANCE_DIM,
                    vb.pp("governance"),
                )?,
                reward_head: linear(JARVIS_TRUNK_DIM, JARVIS_NATIVE_REWARD_DIM, vb.pp("reward"))?,
                runtime_head: linear(
                    JARVIS_TRUNK_DIM,
                    JARVIS_NATIVE_RUNTIME_DIM,
                    vb.pp("runtime"),
                )?,
                lane_head: linear(JARVIS_TRUNK_DIM, JARVIS_NATIVE_LANE_COUNT, vb.pp("lane"))?,
                blueprint_head: linear(
                    JARVIS_TRUNK_DIM,
                    JARVIS_NATIVE_BLUEPRINT_DIM,
                    vb.pp("blueprint"),
                )?,
                world_model_head: linear(JARVIS_TRUNK_DIM, vocab_size, vb.pp("world_model"))?,
            })
        }
        pub fn forward_language(&self, h: &Tensor) -> CResult<Tensor> {
            let language_raw = self.language_head.forward(h)?;
            (language_raw / OUTPUT_SOFT_CAP as f64)?.tanh()? * OUTPUT_SOFT_CAP as f64
        }

        pub fn forward_all(&self, h: &Tensor) -> CResult<NativeHeadOutputs> {
            self.forward_all_with_asi(h, None)
        }
        pub fn forward_all_with_asi(
            &self,
            h: &Tensor,
            asi: Option<&ASISystemOutput>,
        ) -> CResult<NativeHeadOutputs> {
            let language = self.forward_language(h)?;
            let fast_action = self.fast_action_head.forward(h)?;
            let slow_action = self.slow_action_head.forward(h)?;
            let tool_route = self.tool_route_head.forward(h)?;
            let value = self.value_head.forward(h)?;
            let board_status = self.board_status_head.forward(h)?;
            let board_profile = self.board_profile_head.forward(h)?;
            let skill = self.skill_head.forward(h)?;
            let memory_write = self.memory_write_head.forward(h)?;
            let proof = self.proof_head.forward(h)?;
            let governance = self.governance_head.forward(h)?;
            let reward = self.reward_head.forward(h)?;
            let runtime = self.runtime_head.forward(h)?;
            let lane = self.lane_head.forward(h)?;
            let blueprint = self.blueprint_head.forward(h)?;
            let world_model = self.world_model_head.forward(h)?;
            let gate_features = compute_gate_features(
                &fast_action,
                &slow_action,
                &tool_route,
                &value,
                &board_status,
                &memory_write,
                &proof,
                &governance,
                &runtime,
                asi,
            )?;
            let gate_input = Tensor::cat(&[h.clone(), gate_features.clone()], D::Minus1)?;
            let gate_alpha = candle_nn::ops::sigmoid(&self.gate_head.forward(&gate_input)?)?;
            let fast_confidence =
                candle_nn::ops::softmax(&fast_action.to_dtype(DType::F32)?, D::Minus1)?
                    .max(D::Minus1)?
                    .unsqueeze(D::Minus1)?;
            let risk = gate_features.narrow(D::Minus1, 0, 1)?;
            let alignment = gate_features.narrow(D::Minus1, 1, 1)?;
            let shutdown = gate_features.narrow(D::Minus1, 2, 1)?;
            let one_minus_risk = (risk.neg()? + 1.0)?;
            let one_minus_shutdown = (shutdown.neg()? + 1.0)?;
            let system1_confidence = fast_confidence
                .broadcast_mul(&one_minus_risk)?
                .broadcast_mul(&alignment)?
                .broadcast_mul(&one_minus_shutdown)?
                .clamp(0.0f32, 1.0f32)?
                .to_dtype(fast_action.dtype())?;
            let novelty_score = (candle_nn::ops::sigmoid(&memory_write.to_dtype(DType::F32)?)?
                .max(D::Minus1)?
                .unsqueeze(D::Minus1)?
                .neg()?
                + 1.0)?
                .to_dtype(fast_action.dtype())?;
            let dependency_pressure = candle_nn::ops::sigmoid(&board_status.to_dtype(DType::F32)?)?
                .mean_keepdim(D::Minus1)?
                .to_dtype(fast_action.dtype())?;

            Ok(NativeHeadOutputs {
                language,
                fast_action,
                slow_action,
                gate_alpha,
                tool_route,
                value,
                board_status,
                board_profile,
                skill,
                memory_write,
                proof,
                governance,
                reward,
                runtime,
                lane,
                blueprint,
                world_model,
                system1_confidence,
                novelty_score,
                dependency_pressure,
            })
        }
    }
    pub fn framework_finite_score_f32(value: f32) -> f32 {
        if value.is_nan() {
            f32::NEG_INFINITY
        } else if value == f32::INFINITY {
            f32::MAX
        } else if value == f32::NEG_INFINITY {
            f32::MIN
        } else {
            value
        }
    }

    pub fn framework_stable_topk_f32(scores: &[f32], k: usize) -> Vec<(usize, f32)> {
        let mut ranked = scores
            .iter()
            .enumerate()
            .map(|(idx, &score)| (idx, framework_finite_score_f32(score)))
            .collect::<Vec<_>>();
        ranked.sort_by(|a, b| b.1.total_cmp(&a.1).then_with(|| a.0.cmp(&b.0)));
        ranked.truncate(k.min(ranked.len()));
        ranked
    }

    pub fn framework_normalize_scores_f32(scores: &[f32]) -> Vec<f32> {
        if scores.is_empty() {
            return Vec::new();
        }
        let finite = scores
            .iter()
            .copied()
            .filter(|score| score.is_finite())
            .collect::<Vec<_>>();
        if finite.is_empty() {
            return vec![0.0; scores.len()];
        }
        let mean = finite.iter().map(|&score| score as f64).sum::<f64>() / finite.len() as f64;
        let variance = finite
            .iter()
            .map(|&score| {
                let delta = score as f64 - mean;
                delta * delta
            })
            .sum::<f64>()
            / finite.len().max(1) as f64;
        let std = variance.sqrt().max(1e-6);
        scores
            .iter()
            .map(|&score| {
                if score == f32::INFINITY {
                    8.0
                } else if !score.is_finite() {
                    -8.0
                } else {
                    (((score as f64 - mean) / std).clamp(-8.0, 8.0)) as f32
                }
            })
            .collect()
    }

    pub fn framework_softmax_scores_f32(scores: &[f32]) -> Vec<f32> {
        if scores.is_empty() {
            return Vec::new();
        }
        let finite_scores = scores
            .iter()
            .map(|&score| framework_finite_score_f32(score))
            .collect::<Vec<_>>();
        let max_score = finite_scores
            .iter()
            .copied()
            .fold(f32::NEG_INFINITY, f32::max);
        if !max_score.is_finite() {
            return vec![1.0 / scores.len() as f32; scores.len()];
        }
        let exps = finite_scores
            .iter()
            .map(|&score| {
                if score.is_finite() {
                    ((score - max_score).clamp(-80.0, 0.0)).exp()
                } else {
                    0.0
                }
            })
            .collect::<Vec<_>>();
        let sum = exps.iter().sum::<f32>();
        if sum <= 0.0 || !sum.is_finite() {
            vec![1.0 / scores.len() as f32; scores.len()]
        } else {
            exps.into_iter().map(|value| value / sum).collect()
        }
    }

    pub struct NativeHeadOutputs {
        pub language: Tensor,
        pub fast_action: Tensor,
        pub slow_action: Tensor,
        pub gate_alpha: Tensor,
        pub tool_route: Tensor,
        pub value: Tensor,
        pub board_status: Tensor,
        pub board_profile: Tensor,
        pub skill: Tensor,
        pub memory_write: Tensor,
        pub proof: Tensor,
        pub governance: Tensor,
        pub reward: Tensor,
        pub runtime: Tensor,
        pub lane: Tensor,
        pub blueprint: Tensor,
        pub world_model: Tensor,
        pub system1_confidence: Tensor,
        pub novelty_score: Tensor,
        pub dependency_pressure: Tensor,
    }
    impl NativeHeadOutputs {
        pub fn mixed_action_logits(&self) -> CResult<Tensor> {
            let alpha = &self.gate_alpha;
            let fast_probs =
                candle_nn::ops::softmax(&self.fast_action.to_dtype(DType::F32)?, D::Minus1)?;
            let slow_probs =
                candle_nn::ops::softmax(&self.slow_action.to_dtype(DType::F32)?, D::Minus1)?;
            let alpha_f32 = alpha.to_dtype(DType::F32)?;
            let one_minus_alpha = (alpha_f32.neg()? + 1.0)?;
            let mixed_probs = (fast_probs.broadcast_mul(&alpha_f32)?
                + slow_probs.broadcast_mul(&one_minus_alpha)?)?;
            let clamped = mixed_probs.clamp(1e-8, 1.0)?;
            clamped.log()?.to_dtype(self.fast_action.dtype())
        }
        pub fn report(&self) -> CResult<HashMap<String, serde_json::Value>> {
            let alpha_val = self.gate_alpha.mean_all()?.to_scalar::<f32>()?;
            let proof_conf = self.proof.mean_all()?.to_scalar::<f32>()?;
            let gov_risk = self
                .governance
                .narrow(D::Minus1, 0, 1)?
                .mean_all()?
                .to_scalar::<f32>()?;
            let gov_align = self
                .governance
                .narrow(D::Minus1, 1, 1)?
                .mean_all()?
                .to_scalar::<f32>()?;
            let value_est = self.value.mean_all()?.to_scalar::<f32>()?;
            let reward_mean = self.reward.mean_all()?.to_scalar::<f32>()?;
            let runtime_pressure = self
                .runtime
                .narrow(D::Minus1, 0, 1)?
                .mean_all()?
                .to_scalar::<f32>()?;
            let memory_activation = self.memory_write.mean_all()?.to_scalar::<f32>()?;
            let novelty_score = 1.0
                - self
                    .memory_write
                    .max(D::Minus1)?
                    .mean_all()?
                    .to_scalar::<f32>()?;
            let blueprint_score = self.blueprint.mean_all()?.to_scalar::<f32>()?;
            let world_model_mean = self.world_model.mean_all()?.to_scalar::<f32>()?;
            Ok(HashMap::from([
                (
                    "head_count".into(),
                    serde_json::json!(JARVIS_NATIVE_HEAD_COUNT),
                ),
                ("model_version".into(), serde_json::json!(MODEL_VERSION)),
                ("gate_alpha".into(), serde_json::json!(alpha_val)),
                ("s2_mix".into(), serde_json::json!(1.0 - alpha_val)),
                ("proof_confidence".into(), serde_json::json!(proof_conf)),
                ("risk".into(), serde_json::json!(gov_risk)),
                ("alignment".into(), serde_json::json!(gov_align)),
                ("value".into(), serde_json::json!(value_est)),
                ("reward_mean".into(), serde_json::json!(reward_mean)),
                (
                    "runtime_pressure".into(),
                    serde_json::json!(runtime_pressure),
                ),
                (
                    "memory_activation".into(),
                    serde_json::json!(memory_activation),
                ),
                ("novelty_score".into(), serde_json::json!(novelty_score)),
                ("blueprint_score".into(), serde_json::json!(blueprint_score)),
                (
                    "world_model_mean".into(),
                    serde_json::json!(world_model_mean),
                ),
            ]))
        }

        pub fn scalar_metrics(&self) -> CResult<HashMap<String, f64>> {
            let alpha = self.gate_alpha.to_dtype(DType::F32)?;
            let proof = candle_nn::ops::sigmoid(&self.proof.to_dtype(DType::F32)?)?;
            let gov = candle_nn::ops::sigmoid(&self.governance.to_dtype(DType::F32)?)?;
            let reward = self.reward.to_dtype(DType::F32)?.tanh()?;
            let runtime = candle_nn::ops::sigmoid(&self.runtime.to_dtype(DType::F32)?)?;
            let policy_logits = self.mixed_action_logits()?.to_dtype(DType::F32)?;
            let policy_probs = candle_nn::ops::softmax(&policy_logits, D::Minus1)?;
            let policy_log_probs = candle_nn::ops::log_softmax(&policy_logits, D::Minus1)?;
            let policy_entropy = (&policy_probs * &policy_log_probs)?
                .neg()?
                .sum(D::Minus1)?
                .mean_all()?;
            let board_probs =
                candle_nn::ops::softmax(&self.board_status.to_dtype(DType::F32)?, D::Minus1)?;
            let board_log_probs =
                candle_nn::ops::log_softmax(&self.board_status.to_dtype(DType::F32)?, D::Minus1)?;
            let skill_probs =
                candle_nn::ops::softmax(&self.skill.to_dtype(DType::F32)?, D::Minus1)?;
            let skill_log_probs =
                candle_nn::ops::log_softmax(&self.skill.to_dtype(DType::F32)?, D::Minus1)?;
            let lane_probs = candle_nn::ops::softmax(&self.lane.to_dtype(DType::F32)?, D::Minus1)?;
            let lane_log_probs =
                candle_nn::ops::log_softmax(&self.lane.to_dtype(DType::F32)?, D::Minus1)?;
            let language_logit_norm = self
                .language
                .to_dtype(DType::F32)?
                .sqr()?
                .sum(D::Minus1)?
                .sqrt()?
                .mean_all()?;
            let board_entropy = (&board_probs * &board_log_probs)?
                .neg()?
                .sum(D::Minus1)?
                .mean_all()?;
            let skill_entropy = (&skill_probs * &skill_log_probs)?
                .neg()?
                .sum(D::Minus1)?
                .mean_all()?;
            let lane_entropy = (&lane_probs * &lane_log_probs)?
                .neg()?
                .sum(D::Minus1)?
                .mean_all()?;

            let scalar_tensors = vec![
                alpha.mean_all()?,
                proof.narrow(D::Minus1, 0, 1)?.mean_all()?,
                gov.mean_all()?,
                reward.mean_all()?,
                runtime.mean_all()?,
                policy_entropy,
                language_logit_norm,
                board_entropy,
                skill_entropy,
                lane_entropy,
                self.system1_confidence.mean_all()?.to_dtype(DType::F32)?,
                self.novelty_score.mean_all()?.to_dtype(DType::F32)?,
                self.dependency_pressure.mean_all()?.to_dtype(DType::F32)?,
                self.value.mean_all()?.to_dtype(DType::F32)?,
            ];
            let values = Tensor::stack(&scalar_tensors, 0)?.to_vec1::<f32>()?;
            let value = |index: usize| values[index] as f64;

            Ok(HashMap::from([
                ("jarvis_native_alpha_mean".into(), value(0)),
                ("jarvis_native_system2_mix_mean".into(), 1.0 - value(0)),
                ("jarvis_native_proof_need_mean".into(), value(1)),
                ("jarvis_native_governance_violation_mean".into(), value(2)),
                ("jarvis_native_reward_mean".into(), value(3)),
                ("jarvis_native_runtime_pressure_mean".into(), value(4)),
                ("jarvis_native_policy_entropy_mean".into(), value(5)),
                ("jarvis_native_language_logit_norm".into(), value(6)),
                ("jarvis_native_board_status_entropy_mean".into(), value(7)),
                ("jarvis_native_skill_entropy_mean".into(), value(8)),
                ("jarvis_native_lane_entropy_mean".into(), value(9)),
                ("jarvis_native_system1_confidence_mean".into(), value(10)),
                ("jarvis_native_novelty_mean".into(), value(11)),
                ("jarvis_native_dependency_pressure_mean".into(), value(12)),
                ("jarvis_native_value_mean".into(), value(13)),
            ]))
        }
    }

    pub fn jarvis_native_head_contract(vocab_size: usize) -> serde_json::Value {
        let heads_json: Vec<serde_json::Value> = HEAD_SPECS
            .iter()
            .map(|spec| {
                let dim = if spec.output_dim == 0 {
                    vocab_size
                } else {
                    spec.output_dim
                };
                let activation_str = match spec.activation {
                    HeadActivation::Linear => "logits",
                    HeadActivation::Sigmoid => "sigmoid",
                    HeadActivation::Tanh => "tanh",
                    HeadActivation::Softmax => "softmax",
                };
                let loss_str = match spec.loss_type {
                    HeadLossType::CrossEntropy => "cross_entropy",
                    HeadLossType::MSE => "mse",
                    HeadLossType::SmoothL1Cosine => "smooth_l1_proxy_plus_cosine",
                    HeadLossType::BinaryMSEGateRisk => "binary_mse_plus_gate_risk_penalty",
                    HeadLossType::MSEProofGap => "mse_plus_proof_gap",
                    HeadLossType::MSEGovernancePenalty => "mse_plus_governance_penalty",
                    HeadLossType::MSEPressurePenalty => "mse_plus_pressure_penalty",
                    HeadLossType::TrajectoryReconstruction => "trajectory_reconstruction",
                };
                serde_json::json!({
                    "name": spec.name,
                    "dim": dim,
                    "activation": activation_str,
                    "loss": loss_str,
                })
            })
            .collect();

        serde_json::json!({
            "version": MODEL_VERSION,
            "head_count": JARVIS_NATIVE_HEAD_COUNT,
            "trunk_dim": JARVIS_TRUNK_DIM,
            "gate_feature_count": JARVIS_NATIVE_GATE_FEATURES,
            "gate_features": GATE_FEATURE_NAMES,
            "heads": heads_json,
            "loss_fusion": {
                "native_loss_weight": JARVIS_NATIVE_LOSS_WEIGHT,
                "native_fusion_loss_weight": JARVIS_NATIVE_FUSION_LOSS_WEIGHT,
                "world_loss_weight": JARVIS_WORLD_LOSS_WEIGHT,
                "cayley_loss_weight": JARVIS_CAYLEY_LOSS_WEIGHT,
                "rlg_loss_weight": JARVIS_RLG_LOSS_WEIGHT,
                "ppo_loss_weight": JARVIS_PPO_LOSS_WEIGHT
            }
        })
    }

