    #[derive(Debug, Clone, Copy, Serialize, Deserialize)]
    pub struct JarvisPolicyConfig {
        pub input_dim: usize,
        pub domain_action_dim: usize,
        pub n_layers: usize,
        pub dim: usize,
        pub block_size: usize,
        pub n_head: usize,
        pub kv_lora_rank: usize,
        pub n_experts: usize,
        pub expert_top_k: usize,
        pub n_shared_experts: usize,
    }

    impl JarvisPolicyConfig {
        pub fn new(
            input_dim: usize,
            domain_action_dim: usize,
            n_layers: usize,
            dim: usize,
        ) -> Self {
            Self {
                input_dim,
                domain_action_dim,
                n_layers,
                dim,
                block_size: JARVIS_BLOCK_SIZE,
                n_head: JARVIS_N_HEAD,
                kv_lora_rank: MLA_KV_LORA_RANK,
                n_experts: MOE_N_EXPERTS,
                expert_top_k: MOE_TOP_K,
                n_shared_experts: MOE_N_SHARED,
            }
        }

        pub fn with_block_size(mut self, block_size: usize) -> Self {
            self.block_size = block_size.max(1);
            self
        }

        pub fn with_attention(mut self, n_head: usize, kv_lora_rank: usize) -> Self {
            self.n_head = n_head.max(1);
            self.kv_lora_rank = kv_lora_rank.max(1);
            self
        }

        pub fn with_moe(
            mut self,
            n_experts: usize,
            expert_top_k: usize,
            n_shared_experts: usize,
        ) -> Self {
            self.n_experts = n_experts.max(1);
            self.expert_top_k = expert_top_k.clamp(1, self.n_experts);
            self.n_shared_experts = n_shared_experts.max(1);
            self
        }
    }

    pub struct JarvisPolicyNet {
        pub config: JarvisPolicyConfig,
        embed: Linear,
        transformer_blocks: Vec<GeometricTransformerBlock>,
        norm_out: RMSNorm,
        causal_mask: Tensor,  // Pre-computed causal mask
        sliding_mask: Tensor, // Sliding-window mask for alternating layers
        native_trunk: TrunkMLP,
        asi_world_model: LatentWorldModelHead,
        asi_agent_policy: AgentToolPolicyHead,
        latent_mas: LatentMultiAgentSystemHead,
        asi_safety: SafetyAlignmentHead,
        asi_capability: CapabilityPortfolioHead,
        asi_metacognition: ASIMetacognitionHead,
        heads: JarvisNativeHeads,
        domain_action_head: Linear,
    }
    impl JarvisPolicyNet {
        pub fn new(config: JarvisPolicyConfig, vb: VarBuilder) -> CResult<Self> {
            let device = vb.device().clone();
            let embed = linear(config.input_dim, config.dim, vb.pp("embed"))?;
            let n_head = config.n_head;
            let ffn_hidden = config.dim * JARVIS_SPARSE_FFN_COMPRESSION;
            let mut transformer_blocks = Vec::new();
            for i in 0..config.n_layers {
                transformer_blocks.push(GeometricTransformerBlock::new(
                    config.dim,
                    n_head,
                    config.kv_lora_rank,
                    config.block_size,
                    config.n_experts,
                    config.expert_top_k,
                    config.n_shared_experts,
                    ffn_hidden,
                    i, // C2: pass layer_idx for MoE alternation
                    vb.pp(format!("block_{}", i)),
                )?);
            }
            let norm_out = RMSNorm::new(config.dim, 1e-6, vb.pp("norm_out"))?;
            let max_len = config.block_size.max(1);
            let mask = {
                let mut mask_data = vec![0f32; max_len * max_len];
                for i in 0..max_len {
                    for j in 0..max_len {
                        if j > i {
                            mask_data[i * max_len + j] = f32::NEG_INFINITY;
                        }
                    }
                }
                Tensor::from_vec(mask_data, (max_len, max_len), &device)?
            };
            let sliding_mask = {
                let mut mask_data = vec![f32::NEG_INFINITY; max_len * max_len];
                for i in 0..max_len {
                    let start = i.saturating_sub(SLIDING_WINDOW_SIZE.saturating_sub(1));
                    for j in start..=i {
                        mask_data[i * max_len + j] = 0.0;
                    }
                }
                Tensor::from_vec(mask_data, (max_len, max_len), &device)?
            };
            let native_trunk = TrunkMLP::new(config.dim, vb.pp("trunk"))?;
            let asi_world_model = LatentWorldModelHead::new(config.dim, vb.pp("asi_world_model"))?;
            let asi_agent_policy = AgentToolPolicyHead::new(config.dim, vb.pp("asi_agent_policy"))?;
            let latent_mas = LatentMultiAgentSystemHead::new(
                config.dim,
                LLM_LATENT_MAS_AGENT_COUNT,
                vb.pp("latent_mas"),
            )?;
            let asi_safety = SafetyAlignmentHead::new(config.dim, vb.pp("asi_safety"))?;
            let asi_capability = CapabilityPortfolioHead::new(config.dim, vb.pp("asi_capability"))?;
            let asi_metacognition =
                ASIMetacognitionHead::new(config.dim, vb.pp("asi_metacognition"))?;
            let heads = JarvisNativeHeads::new(config.input_dim, vb.pp("heads"))?;
            let domain_action_head = linear(
                JARVIS_TRUNK_DIM,
                config.domain_action_dim,
                vb.pp(JARVIS_DOMAIN_ACTION_HEAD_VAR_KEY),
            )?;
            Ok(Self {
                config,
                embed,
                transformer_blocks,
                norm_out,
                causal_mask: mask,
                sliding_mask,
                native_trunk,
                asi_world_model,
                asi_agent_policy,
                latent_mas,
                asi_safety,
                asi_capability,
                asi_metacognition,
                heads,
                domain_action_head,
            })
        }
        fn encode_hidden_sequence(&self, x: &Tensor) -> CResult<(Tensor, bool)> {
            let h = self.embed.forward(x)?;
            let ndim = h.dims().len();
            let (h3d, was_2d) = if ndim == 2 {
                (h.unsqueeze(1)?, true)
            } else {
                (h, false)
            };
            let mut h = h3d;
            for block in &self.transformer_blocks {
                let mask = if block.layer_idx % 2 == 1 {
                    &self.sliding_mask
                } else {
                    &self.causal_mask
                };
                h = block.forward(&h, Some(mask))?;
            }
            Ok((self.norm_out.forward(&h)?, was_2d))
        }

        fn encode_hidden_sequence_train(&mut self, x: &Tensor) -> CResult<(Tensor, bool)> {
            let h = self.embed.forward(x)?;
            let ndim = h.dims().len();
            let (h3d, was_2d) = if ndim == 2 {
                (h.unsqueeze(1)?, true)
            } else {
                (h, false)
            };
            let causal_mask = self.causal_mask.clone();
            let sliding_mask = self.sliding_mask.clone();
            let mut h = h3d;
            for block in self.transformer_blocks.iter_mut() {
                let mask = if block.layer_idx % 2 == 1 {
                    &sliding_mask
                } else {
                    &causal_mask
                };
                h = block.forward_train(&h, Some(mask))?;
            }
            Ok((self.norm_out.forward(&h)?, was_2d))
        }

        fn last_token_hidden(hidden: &Tensor, was_2d: bool) -> CResult<Tensor> {
            if was_2d {
                hidden.squeeze(1)
            } else {
                let t = hidden.dim(1)?;
                hidden.narrow(1, t - 1, 1)?.squeeze(1)
            }
        }

        pub fn backbone(&self, x: &Tensor) -> CResult<Tensor> {
            let (hidden_seq, was_2d) = self.encode_hidden_sequence(x)?;
            let hidden = Self::last_token_hidden(&hidden_seq, was_2d)?;
            self.native_trunk.forward(&hidden)
        }

        fn native_heads_from_encoder(
            &self,
            encoder_hidden: &Tensor,
        ) -> CResult<(NativeHeadOutputs, Tensor, ASISystemOutput)> {
            let asi = self.forward_asi(encoder_hidden)?;
            let native_hidden = self.native_trunk.forward(encoder_hidden)?;
            let native = self
                .heads
                .forward_all_with_asi(&native_hidden, Some(&asi))?;
            let domain_logits = self.domain_action_head.forward(&native_hidden)?;
            Ok((native, domain_logits, asi))
        }
        pub fn forward_asi_train(&mut self, x: &Tensor) -> CResult<(ASISystemOutput, Tensor)> {
            let (hidden_seq, _was_2d) = self.encode_hidden_sequence_train(x)?;
            let asi = self.forward_asi(&hidden_seq)?;
            Ok((asi, hidden_seq))
        }
        pub fn forward_all_train(
            &mut self,
            x: &Tensor,
        ) -> CResult<(NativeHeadOutputs, Tensor, ASISystemOutput, Tensor)> {
            let (hidden_seq, was_2d) = self.encode_hidden_sequence_train(x)?;
            let hidden = Self::last_token_hidden(&hidden_seq, was_2d)?;
            let (native, domain_logits, asi) = self.native_heads_from_encoder(&hidden)?;
            Ok((native, domain_logits, asi, hidden))
        }
        pub fn forward_all_train_with_sequence(
            &mut self,
            x: &Tensor,
        ) -> CResult<(NativeHeadOutputs, Tensor, ASISystemOutput, Tensor, Tensor)> {
            let (hidden_seq, was_2d) = self.encode_hidden_sequence_train(x)?;
            let hidden = Self::last_token_hidden(&hidden_seq, was_2d)?;
            let (native, domain_logits, asi) = self.native_heads_from_encoder(&hidden)?;
            Ok((native, domain_logits, asi, hidden, hidden_seq))
        }
        pub fn forward_all_train_sequence(
            &mut self,
            x: &Tensor,
        ) -> CResult<(NativeHeadOutputs, Tensor, ASISystemOutput, Tensor)> {
            let (hidden_seq, _was_2d) = self.encode_hidden_sequence_train(x)?;
            let (native, domain_logits, asi) = self.native_heads_from_encoder(&hidden_seq)?;
            Ok((native, domain_logits, asi, hidden_seq))
        }

        pub fn forward_llm_train_core(&mut self, x: &Tensor) -> CResult<(Tensor, Tensor, Tensor)> {
            let (hidden_seq, _was_2d) = self.encode_hidden_sequence_train(x)?;
            let native_hidden = self.native_trunk.forward(&hidden_seq)?;
            let language = self.heads.forward_language(&native_hidden)?;
            let action_ids = Self::action_ids_from_hidden(&hidden_seq)?;
            let predicted_next_state = self.asi_world_model.forward(&hidden_seq, &action_ids)?;
            Ok((language, predicted_next_state, hidden_seq))
        }

        pub fn forward_llm_diagnostics_from_hidden(
            &self,
            hidden_seq: &Tensor,
        ) -> CResult<(NativeHeadOutputs, ASISystemOutput)> {
            let (native, _domain_logits, asi) = self.native_heads_from_encoder(hidden_seq)?;
            Ok((native, asi))
        }
        pub fn forward_encoder_hidden(&self, x: &Tensor) -> CResult<Tensor> {
            let (hidden_seq, was_2d) = self.encode_hidden_sequence(x)?;
            Self::last_token_hidden(&hidden_seq, was_2d)
        }
        pub fn forward_encoder_sequence(&self, x: &Tensor) -> CResult<Tensor> {
            let (hidden_seq, _was_2d) = self.encode_hidden_sequence(x)?;
            Ok(hidden_seq)
        }
        pub fn forward_language_with_hidden(&self, x: &Tensor) -> CResult<(Tensor, Tensor)> {
            let (hidden_seq, _was_2d) = self.encode_hidden_sequence(x)?;
            let native_hidden = self.native_trunk.forward(&hidden_seq)?;
            let language = self.heads.forward_language(&native_hidden)?;
            Ok((language, hidden_seq))
        }
        pub fn token_embedding_vector(&self, token: usize) -> CResult<Tensor> {
            let mut one_hot = vec![0.0f32; self.config.input_dim];
            if token < one_hot.len() {
                one_hot[token] = 1.0;
            }
            let x = Tensor::from_vec(
                one_hot,
                (1, self.config.input_dim),
                self.causal_mask.device(),
            )?;
            self.embed.forward(&x)
        }
        fn forward_native_from_encoder(
            &self,
            encoder_hidden: &Tensor,
        ) -> CResult<NativeHeadOutputs> {
            let (native, _domain_logits, _asi) = self.native_heads_from_encoder(encoder_hidden)?;
            Ok(native)
        }
        fn forward_domain_action_from_encoder(&self, encoder_hidden: &Tensor) -> CResult<Tensor> {
            let native_hidden = self.native_trunk.forward(encoder_hidden)?;
            self.domain_action_head.forward(&native_hidden)
        }
        fn forward_all_from_encoder(
            &self,
            encoder_hidden: &Tensor,
        ) -> CResult<(NativeHeadOutputs, Tensor)> {
            let (native, domain_logits, _asi) = self.native_heads_from_encoder(encoder_hidden)?;
            Ok((native, domain_logits))
        }
        fn action_ids_from_hidden(hidden: &Tensor) -> CResult<Tensor> {
            let raw = hidden.abs()?.sum(D::Minus1)?.to_dtype(DType::F32)?;
            let bins = ASI_ACTION_BINS as f64;
            let div = (raw.clone() / bins)?.floor()?;
            (raw - (div * bins)?)?
                .clamp(0f32, (ASI_ACTION_BINS - 1) as f32)?
                .to_dtype(DType::U32)
        }

        pub fn forward_asi(&self, hidden: &Tensor) -> CResult<ASISystemOutput> {
            let action_ids = Self::action_ids_from_hidden(hidden)?;
            ASISystemOutput::compute(
                &self.asi_world_model,
                &self.asi_agent_policy,
                &self.asi_safety,
                &self.asi_capability,
                &self.asi_metacognition,
                hidden,
                &action_ids,
            )
        }
        pub fn compute_latent_mas_loss(&self, hidden_seq: &Tensor) -> CResult<LatentMASLossReport> {
            let action_ids = Self::action_ids_from_hidden(hidden_seq)?;
            self.latent_mas.compute_loss(hidden_seq, &action_ids)
        }
        pub fn moe_layer_reports(&self) -> Vec<(usize, HashMap<String, serde_json::Value>)> {
            self.transformer_blocks
                .iter()
                .filter(|b| b.is_moe)
                .filter_map(|b| b.ffn_moe.as_ref().map(|moe| (b.layer_idx, moe.report())))
                .collect()
        }

        pub fn moe_routing_health_report(&self) -> serde_json::Value {
            let layers = self
                .moe_layer_reports()
                .into_iter()
                .map(|(layer_idx, report)| {
                    let counts = report
                        .get("cumulative_counts")
                        .or_else(|| report.get("counts"))
                        .and_then(|v| v.as_array())
                        .map(|items| {
                            items
                                .iter()
                                .filter_map(|v| v.as_u64().map(|n| n as usize))
                                .collect::<Vec<_>>()
                        })
                        .unwrap_or_default();
                    let n_experts = report
                        .get("n_experts")
                        .and_then(|v| v.as_u64())
                        .map(|v| v as usize)
                        .unwrap_or(MOE_N_EXPERTS);
                    let mut health = moe_routing_health_from_counts(&counts, n_experts);
                    if let Some(map) = health.as_object_mut() {
                        map.insert("layer_idx".to_string(), serde_json::json!(layer_idx));
                        map.insert(
                            "ot_error".to_string(),
                            report
                                .get("ot_error")
                                .cloned()
                                .unwrap_or_else(|| serde_json::json!(0.0)),
                        );
                        map.insert(
                            "counts".to_string(),
                            report
                                .get("cumulative_counts")
                                .or_else(|| report.get("counts"))
                                .cloned()
                                .unwrap_or_else(|| serde_json::json!([])),
                        );
                        map.insert(
                            "last_batch_counts".to_string(),
                            report
                                .get("counts")
                                .cloned()
                                .unwrap_or_else(|| serde_json::json!([])),
                        );
                        map.insert(
                            "sample_scope".to_string(),
                            serde_json::json!("cumulative_training_assignments"),
                        );
                    }
                    health
                })
                .collect::<Vec<_>>();
            let ok = layers
                .iter()
                .all(|layer| layer.get("ok").and_then(|v| v.as_bool()).unwrap_or(false));
            let layer_count = layers.len();
            serde_json::json!({
                "ok": ok,
                "layers": layers,
                "layer_count": layer_count,
            })
        }
        pub fn moe_layer_count(&self) -> usize {
            self.transformer_blocks.iter().filter(|b| b.is_moe).count()
        }

        pub fn sparse_ffn_l1_proxy(&self, hidden_seq: &Tensor) -> CResult<(Tensor, f64, f64)> {
            let mut losses = Vec::new();
            for block in &self.transformer_blocks {
                if let Some(ref ffn) = block.ffn_dense {
                    let normed = block.ffn_norm.forward(hidden_seq)?;
                    losses.push(ffn.gate_l1(&normed)?);
                }
            }
            if losses.is_empty() {
                let zero = Tensor::zeros((), DType::F32, hidden_seq.device())?;
                return Ok((zero, 0.0, 0.0));
            }
            let mean_tensor = Tensor::stack(&losses, 0)?.mean_all()?;
            let mean = mean_tensor.to_scalar::<f32>()?;
            let density = mean.clamp(0.0, 1.0) as f64;
            Ok((mean_tensor, mean as f64, density))
        }
        pub fn forward_native(&self, x: &Tensor) -> CResult<NativeHeadOutputs> {
            let hidden = self.forward_encoder_hidden(x)?;
            self.forward_native_from_encoder(&hidden)
        }
        pub fn forward_domain_action(&self, x: &Tensor) -> CResult<Tensor> {
            let hidden = self.forward_encoder_hidden(x)?;
            self.forward_domain_action_from_encoder(&hidden)
        }
        pub fn forward_all(&self, x: &Tensor) -> CResult<(NativeHeadOutputs, Tensor)> {
            let hidden = self.forward_encoder_hidden(x)?;
            self.forward_all_from_encoder(&hidden)
        }
        pub fn forward_all_with_asi(
            &self,
            x: &Tensor,
        ) -> CResult<(NativeHeadOutputs, Tensor, ASISystemOutput)> {
            let hidden = self.forward_encoder_hidden(x)?;
            let (native, domain_logits, asi) = self.native_heads_from_encoder(&hidden)?;
            Ok((native, domain_logits, asi))
        }
        pub fn compute_asi_loss(
            &self,
            asi: &ASISystemOutput,
            hidden_states: &Tensor,
            transition_mask: Option<&Tensor>,
        ) -> CResult<(Tensor, HashMap<String, f64>)> {
            let device = hidden_states.device();
            let mut metrics = HashMap::new();
            let t_dim = hidden_states.dim(D::Minus2)?;
            let world_loss = if t_dim > 1 {
                let pred = asi
                    .predicted_next_state
                    .narrow(D::Minus2, 0, t_dim - 1)?
                    .to_dtype(DType::F32)?;
                let target = hidden_states
                    .narrow(D::Minus2, 1, t_dim - 1)?
                    .detach()
                    .to_dtype(DType::F32)?;
                let diff = (&pred - &target)?;
                let abs_diff = diff.abs()?;
                let beta = 1.0f64;
                let quadratic_mask = abs_diff.lt(beta as f32)?;
                let quadratic = (diff.sqr()? * (0.5 / beta))?;
                let linear = (abs_diff - (0.5 * beta))?;
                let small = quadratic_mask.to_dtype(DType::F32)?;
                let large = (small.neg()? + 1.0)?;
                let transition_elems =
                    (small.broadcast_mul(&quadratic)? + large.broadcast_mul(&linear)?)?;
                let dot = (&pred * &target)?.sum(D::Minus1)?;
                let pred_norm = pred.sqr()?.sum(D::Minus1)?.sqrt()?;
                let target_norm = target.sqr()?.sum(D::Minus1)?.sqrt()?;
                let cos_sim =
                    dot.broadcast_div(&(pred_norm * target_norm)?.clamp(1e-8f32, f32::MAX)?)?;
                let cosine_elems = (cos_sim.neg()? + 1.0)?;

                let (transition_loss, cosine_loss) = if let Some(mask) = transition_mask {
                    let mask = mask.narrow(D::Minus1, 0, t_dim - 1)?.to_dtype(DType::F32)?;
                    let denom = mask.sum_all()?.to_scalar::<f32>()?.max(1.0) as f64;
                    let mask3 = mask
                        .unsqueeze(D::Minus1)?
                        .broadcast_as(transition_elems.shape())?;
                    let transition_sum = transition_elems.broadcast_mul(&mask3)?.sum_all()?;
                    let transition_denom = denom * hidden_states.dim(D::Minus1)? as f64;
                    let transition_loss = (transition_sum / transition_denom)?;
                    let cosine_loss = (cosine_elems.broadcast_mul(&mask)?.sum_all()? / denom)?;
                    (transition_loss, cosine_loss)
                } else {
                    (transition_elems.mean_all()?, cosine_elems.mean_all()?)
                };

                (transition_loss + cosine_loss)?
            } else {
                Tensor::zeros((), DType::F32, device)?
            };

            let risk_mean = candle_nn::ops::sigmoid(&asi.risk_logit)?.mean_all()?;
            let risk_adjusted_mean =
                candle_nn::ops::sigmoid(&asi.risk_adjusted_logit)?.mean_all()?;
            let alignment_mean = candle_nn::ops::sigmoid(&asi.alignment_logit)?.mean_all()?;
            let capability_mean = candle_nn::ops::sigmoid(&asi.capability_logits)?.mean_all()?;
            let tool_probs =
                candle_nn::ops::softmax(&asi.tool_logits.to_dtype(DType::F32)?, D::Minus1)?;
            let tool_log_probs =
                candle_nn::ops::log_softmax(&asi.tool_logits.to_dtype(DType::F32)?, D::Minus1)?;
            let tool_entropy = (&tool_probs * &tool_log_probs)?
                .neg()?
                .sum(D::Minus1)?
                .mean_all()?;
            let plan_probs =
                candle_nn::ops::softmax(&asi.plan_logits.to_dtype(DType::F32)?, D::Minus1)?;
            let plan_log_probs =
                candle_nn::ops::log_softmax(&asi.plan_logits.to_dtype(DType::F32)?, D::Minus1)?;
            let plan_entropy = (&plan_probs * &plan_log_probs)?
                .neg()?
                .sum(D::Minus1)?
                .mean_all()?;
            let metacognition =
                candle_nn::ops::sigmoid(&asi.metacognition_logits.to_dtype(DType::F32)?)?;
            let uncertainty = metacognition.narrow(D::Minus1, 0, 1)?.mean_all()?;
            let reflection = metacognition.narrow(D::Minus1, 1, 1)?.mean_all()?;
            let governance_score =
                candle_nn::ops::sigmoid(&asi.governance_score.to_dtype(DType::F32)?)?.mean_all()?;

            let total = (&world_loss * ASI_WORLD_LOSS_WEIGHT)?;
            let scalar_tensors = vec![
                world_loss.to_dtype(DType::F32)?,
                risk_mean.to_dtype(DType::F32)?,
                risk_adjusted_mean.to_dtype(DType::F32)?,
                alignment_mean.to_dtype(DType::F32)?,
                capability_mean.to_dtype(DType::F32)?,
                tool_entropy.to_dtype(DType::F32)?,
                plan_entropy.to_dtype(DType::F32)?,
                uncertainty.to_dtype(DType::F32)?,
                reflection.to_dtype(DType::F32)?,
                governance_score.to_dtype(DType::F32)?,
                total.to_dtype(DType::F32)?,
            ];
            let values = Tensor::stack(&scalar_tensors, 0)?.to_vec1::<f32>()?;
            let keys = [
                "asi_world_model_loss",
                "risk_mean",
                "risk_adjusted_mean",
                "alignment_mean",
                "capability_mean",
                "tool_entropy",
                "plan_entropy",
                "metacognition_uncertainty_mean",
                "metacognition_reflection_mean",
                "governance_score_mean",
                "asi_total_loss",
            ];
            for (key, value) in keys.into_iter().zip(values) {
                metrics.insert(key.into(), value as f64);
            }
            metrics.insert("world_loss".into(), metrics["asi_world_model_loss"]);
            metrics.insert("asi_safety_loss".into(), 0.0);
            metrics.insert("asi_governance_loss".into(), 0.0);

            Ok((total, metrics))
        }

        fn add_supervised_ce(
            supervised: &mut Tensor,
            terms: &mut u32,
            metrics: &mut HashMap<String, f64>,
            name: &str,
            logits: &Tensor,
            target_one_hot: &Tensor,
        ) -> CResult<()> {
            let rows = target_one_hot.dim(0)? as f64;
            let log_probs = candle_nn::ops::log_softmax(logits, D::Minus1)?;
            let term = ((&log_probs * target_one_hot)?.neg()?.sum_all()? / rows.max(1.0))?;
            metrics.insert(
                format!("jarvis_native_{}_loss", name),
                term.to_scalar::<f32>()? as f64,
            );
            let next = supervised.broadcast_add(&term)?;
            *supervised = next;
            *terms += 1;
            Ok(())
        }

        fn add_supervised_mse(
            supervised: &mut Tensor,
            terms: &mut u32,
            metrics: &mut HashMap<String, f64>,
            name: &str,
            pred: &Tensor,
            target: &Tensor,
        ) -> CResult<()> {
            let term = (pred - target)?.sqr()?.mean_all()?;
            metrics.insert(
                format!("jarvis_native_{}_loss", name),
                term.to_scalar::<f32>()? as f64,
            );
            let next = supervised.broadcast_add(&term)?;
            *supervised = next;
            *terms += 1;
            Ok(())
        }

        fn apply_head_activation(pred: &Tensor, activation: HeadActivation) -> CResult<Tensor> {
            let pred = pred.to_dtype(DType::F32)?;
            match activation {
                HeadActivation::Linear => Ok(pred),
                HeadActivation::Sigmoid => candle_nn::ops::sigmoid(&pred),
                HeadActivation::Tanh => pred.tanh(),
                HeadActivation::Softmax => candle_nn::ops::softmax(&pred, D::Minus1),
            }
        }

        fn add_supervised_mse_activated(
            supervised: &mut Tensor,
            terms: &mut u32,
            metrics: &mut HashMap<String, f64>,
            name: &str,
            pred: &Tensor,
            target: &Tensor,
            activation: HeadActivation,
        ) -> CResult<()> {
            let pred = Self::apply_head_activation(pred, activation)?;
            Self::add_supervised_mse(supervised, terms, metrics, name, &pred, target)
        }

        fn add_supervised_bce(
            supervised: &mut Tensor,
            terms: &mut u32,
            metrics: &mut HashMap<String, f64>,
            name: &str,
            pred_prob: &Tensor,
            target: &Tensor,
        ) -> CResult<()> {
            let pred = pred_prob
                .to_dtype(DType::F32)?
                .clamp(1e-6f32, 1.0f32 - 1e-6f32)?;
            let target = target.to_dtype(DType::F32)?;
            let one_minus_target = (target.neg()? + 1.0)?;
            let one_minus_pred = (pred.neg()? + 1.0)?;
            let positive = target.broadcast_mul(&pred.log()?)?;
            let negative = one_minus_target.broadcast_mul(&one_minus_pred.log()?)?;
            let term = (positive + negative)?.neg()?.mean_all()?;
            metrics.insert(
                format!("jarvis_native_{}_loss", name),
                term.to_scalar::<f32>()? as f64,
            );
            let next = supervised.broadcast_add(&term)?;
            *supervised = next;
            *terms += 1;
            Ok(())
        }
        pub fn compute_native_fusion_loss(
            &self,
            native: &NativeHeadOutputs,
            targets: Option<&NativeFusionTargets<'_>>,
            asi: &ASISystemOutput,
        ) -> CResult<(Tensor, HashMap<String, f64>)> {
            let device = native.fast_action.device();
            let dtype = native.fast_action.dtype();
            let mut metrics = HashMap::new();
            let mut supervised = Tensor::zeros((), DType::F32, device)?;
            let mut supervised_terms = 0u32;

            if let Some(targets) = targets {
                if let Some(t) = targets.language {
                    Self::add_supervised_mse(
                        &mut supervised,
                        &mut supervised_terms,
                        &mut metrics,
                        "language",
                        &native.language,
                        t,
                    )?;
                }
                if let Some(t) = targets.fast_action {
                    Self::add_supervised_ce(
                        &mut supervised,
                        &mut supervised_terms,
                        &mut metrics,
                        "s1",
                        &native.fast_action,
                        t,
                    )?;
                }
                if let Some(t) = targets.slow_action {
                    Self::add_supervised_ce(
                        &mut supervised,
                        &mut supervised_terms,
                        &mut metrics,
                        "s2",
                        &native.slow_action,
                        t,
                    )?;
                }
                if let Some(t) = targets.gate {
                    Self::add_supervised_bce(
                        &mut supervised,
                        &mut supervised_terms,
                        &mut metrics,
                        "gate",
                        &native.gate_alpha,
                        t,
                    )?;
                }
                if let Some(t) = targets.tool {
                    Self::add_supervised_ce(
                        &mut supervised,
                        &mut supervised_terms,
                        &mut metrics,
                        "tool",
                        &native.tool_route,
                        t,
                    )?;
                }
                if let Some(t) = targets.value {
                    let value = native.value.squeeze(D::Minus1)?;
                    Self::add_supervised_mse(
                        &mut supervised,
                        &mut supervised_terms,
                        &mut metrics,
                        "value",
                        &value,
                        t,
                    )?;
                }
                if let Some(t) = targets.board_status {
                    Self::add_supervised_ce(
                        &mut supervised,
                        &mut supervised_terms,
                        &mut metrics,
                        "board_status",
                        &native.board_status,
                        t,
                    )?;
                }
                if let Some(t) = targets.board_profile {
                    Self::add_supervised_ce(
                        &mut supervised,
                        &mut supervised_terms,
                        &mut metrics,
                        "profile",
                        &native.board_profile,
                        t,
                    )?;
                }
                if let Some(t) = targets.skill {
                    Self::add_supervised_ce(
                        &mut supervised,
                        &mut supervised_terms,
                        &mut metrics,
                        "skill",
                        &native.skill,
                        t,
                    )?;
                }
                if let Some(t) = targets.memory {
                    Self::add_supervised_mse_activated(
                        &mut supervised,
                        &mut supervised_terms,
                        &mut metrics,
                        "memory",
                        &native.memory_write,
                        t,
                        HeadActivation::Sigmoid,
                    )?;
                }
                if let Some(t) = targets.proof {
                    Self::add_supervised_mse_activated(
                        &mut supervised,
                        &mut supervised_terms,
                        &mut metrics,
                        "proof",
                        &native.proof,
                        t,
                        HeadActivation::Sigmoid,
                    )?;
                }
                if let Some(t) = targets.governance {
                    Self::add_supervised_mse_activated(
                        &mut supervised,
                        &mut supervised_terms,
                        &mut metrics,
                        "governance",
                        &native.governance,
                        t,
                        HeadActivation::Sigmoid,
                    )?;
                }
                if let Some(t) = targets.reward {
                    Self::add_supervised_mse_activated(
                        &mut supervised,
                        &mut supervised_terms,
                        &mut metrics,
                        "reward",
                        &native.reward,
                        t,
                        HeadActivation::Tanh,
                    )?;
                }
                if let Some(t) = targets.runtime {
                    Self::add_supervised_mse_activated(
                        &mut supervised,
                        &mut supervised_terms,
                        &mut metrics,
                        "runtime",
                        &native.runtime,
                        t,
                        HeadActivation::Sigmoid,
                    )?;
                }
                if let Some(t) = targets.lane {
                    Self::add_supervised_ce(
                        &mut supervised,
                        &mut supervised_terms,
                        &mut metrics,
                        "lane",
                        &native.lane,
                        t,
                    )?;
                }
                if let Some(t) = targets.blueprint {
                    Self::add_supervised_mse_activated(
                        &mut supervised,
                        &mut supervised_terms,
                        &mut metrics,
                        "blueprint",
                        &native.blueprint,
                        t,
                        HeadActivation::Sigmoid,
                    )?;
                }
                if let Some(t) = targets.world_model {
                    Self::add_supervised_mse_activated(
                        &mut supervised,
                        &mut supervised_terms,
                        &mut metrics,
                        "world_model",
                        &native.world_model,
                        t,
                        HeadActivation::Sigmoid,
                    )?;
                }
            }
            let risk_for_loss = asi.risk_adjusted_logit.clone();
            let risk = candle_nn::ops::sigmoid(&risk_for_loss.to_dtype(DType::F32)?)?;
            let runtime_pressure = candle_nn::ops::sigmoid(
                &native
                    .runtime
                    .narrow(D::Minus1, 0, 1)?
                    .to_dtype(DType::F32)?,
            )?
            .squeeze(D::Minus1)?;
            let proof_threshold = 0.5f64; // jarvis_native_proof_need_threshold
            let proof_sig_mean =
                candle_nn::ops::sigmoid(&native.proof.to_dtype(DType::F32)?)?.mean(D::Minus1)?;
            let proof_gap_offset = Tensor::new(&[proof_threshold as f32], device)?;
            let proof_gap = proof_sig_mean
                .neg()?
                .broadcast_add(&proof_gap_offset)?
                .relu()?;
            let native_gov =
                candle_nn::ops::sigmoid(&native.governance.to_dtype(DType::F32)?)?.mean_all()?;

            let native_proof_gap = proof_gap.mean_all()?;
            let native_runtime = runtime_pressure.mean_all()?;
            let gate_squeezed = native.gate_alpha.squeeze(D::Minus1)?.to_dtype(DType::F32)?;
            let gate_risk_penalty = gate_squeezed.broadcast_mul(&risk)?.mean_all()?;
            let gate_inv = (native
                .gate_alpha
                .squeeze(D::Minus1)?
                .to_dtype(DType::F32)?
                .neg()?
                + 1.0)?;
            let system2_cost_penalty = gate_inv.broadcast_mul(&runtime_pressure)?.mean_all()?;
            let dependency_penalty = native
                .dependency_pressure
                .to_dtype(DType::F32)?
                .mean_all()?;
            let constrained = (native_gov
                + (native_proof_gap * 0.25)?
                + (native_runtime * 0.10)?
                + (gate_risk_penalty.clone() * 0.10)?
                + (system2_cost_penalty.clone() * 0.05)?
                + (dependency_penalty.clone() * 0.03)?)?;
            let supervised_avg = if supervised_terms > 0 {
                (supervised / supervised_terms as f64)?
            } else {
                supervised
            };

            let fusion_loss = (constrained.to_dtype(dtype)? + supervised_avg.to_dtype(dtype)?)?;
            let scalar_tensors = vec![
                fusion_loss.to_dtype(DType::F32)?,
                supervised_avg.to_dtype(DType::F32)?,
                constrained.to_dtype(DType::F32)?,
                gate_risk_penalty.to_dtype(DType::F32)?,
                system2_cost_penalty.to_dtype(DType::F32)?,
                dependency_penalty.to_dtype(DType::F32)?,
            ];
            let scalar_values = Tensor::stack(&scalar_tensors, 0)?.to_vec1::<f32>()?;
            metrics.insert(
                "jarvis_native_supervised_terms".into(),
                supervised_terms as f64,
            );
            metrics.insert(
                "jarvis_native_supervised_loss".into(),
                scalar_values[1] as f64,
            );
            metrics.insert(
                "jarvis_native_constrained_loss".into(),
                scalar_values[2] as f64,
            );
            metrics.insert(
                "jarvis_native_gate_risk_penalty".into(),
                scalar_values[3] as f64,
            );
            metrics.insert(
                "jarvis_native_system2_cost_penalty".into(),
                scalar_values[4] as f64,
            );
            metrics.insert(
                "jarvis_native_dependency_penalty".into(),
                scalar_values[5] as f64,
            );
            metrics.insert("jarvis_native_aux_loss".into(), scalar_values[0] as f64);
            metrics.extend(native.scalar_metrics()?);

            Ok((fusion_loss, metrics))
        }
    }

    pub fn save_model(varmap: &VarMap, path: &str) -> CResult<()> {
        let path_ref = Path::new(path);
        if let Some(parent) = path_ref.parent() {
            fs::create_dir_all(parent)
                .map_err(|e| candle_core::Error::Msg(format!("{}: {}", parent.display(), e)))?;
        }
        let now = SystemTime::now().duration_since(UNIX_EPOCH).map_err(|e| {
            candle_core::Error::Msg(format!("system clock before unix epoch: {}", e))
        })?;
        let tmp_path =
            path_ref.with_extension(format!("tmp.{}.{}", std::process::id(), now.as_nanos()));
        varmap.save(tmp_path.to_string_lossy().as_ref())?;
        fs::rename(&tmp_path, path_ref)
            .map_err(|e| candle_core::Error::Msg(format!("{}: {}", path_ref.display(), e)))?;
        println!("Model saved to {}", path);
        Ok(())
    }
    pub fn load_model_weights(varmap: &mut VarMap, path: &str) -> CResult<()> {
        varmap.load(path)?;
        eprintln!("Model loaded from {}", path);
        Ok(())
    }
    pub fn create_policy_with_varmap(
        config: JarvisPolicyConfig,
        device: &Device,
    ) -> CResult<(JarvisPolicyNet, VarMap)> {
        let varmap = VarMap::new();
        let vb = VarBuilder::from_varmap(&varmap, DType::F32, device);
        let net = JarvisPolicyNet::new(config, vb)?;
        Ok((net, varmap))
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct FrameworkError {
        pub code: String,
        pub message: String,
        pub context: serde_json::Value,
    }

    impl FrameworkError {
        pub fn new(
            code: impl Into<String>,
            message: impl Into<String>,
            context: serde_json::Value,
        ) -> Self {
            Self {
                code: code.into(),
                message: message.into(),
                context,
            }
        }

        pub fn io(path: impl AsRef<Path>, err: impl fmt::Display) -> Self {
            Self::new(
                "io_error",
                err.to_string(),
                serde_json::json!({"path": path.as_ref().display().to_string()}),
            )
        }

        pub fn serialization(err: impl fmt::Display) -> Self {
            Self::new(
                "serialization_error",
                err.to_string(),
                serde_json::json!({}),
            )
        }

        pub fn validation(message: impl Into<String>, context: serde_json::Value) -> Self {
            Self::new("validation_error", message, context)
        }

        pub fn command(message: impl Into<String>, context: serde_json::Value) -> Self {
            Self::new("command_error", message, context)
        }

        pub fn runtime(message: impl Into<String>, context: serde_json::Value) -> Self {
            Self::new("runtime_error", message, context)
        }

        pub fn to_json(&self) -> serde_json::Value {
            serde_json::json!({
                "code": self.code,
                "message": self.message,
                "context": self.context,
            })
        }
    }

    impl fmt::Display for FrameworkError {
        fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
            write!(f, "{}: {}", self.code, self.message)
        }
    }

    impl std::error::Error for FrameworkError {}

    pub type FrameworkResult<T> = Result<T, FrameworkError>;

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct CompileSpec {
        pub domain: String,
        pub task: String,
        pub inputs: serde_json::Value,
        pub risk_class: Option<String>,
        pub metadata: HashMap<String, serde_json::Value>,
    }

    impl CompileSpec {
        pub fn new(domain: &str, task: &str, inputs: serde_json::Value) -> FrameworkResult<Self> {
            let spec = Self {
                domain: domain.trim().to_string(),
                task: task.trim().to_string(),
                inputs,
                risk_class: None,
                metadata: HashMap::new(),
            };
            spec.validate()?;
            Ok(spec)
        }

        pub fn from_map(spec: &HashMap<String, serde_json::Value>) -> FrameworkResult<Self> {
            let domain = spec
                .get("domain")
                .and_then(|v| v.as_str())
                .unwrap_or("")
                .trim()
                .to_string();
            let task = spec
                .get("task")
                .and_then(|v| v.as_str())
                .unwrap_or("default")
                .trim()
                .to_string();
            let inputs = spec
                .get("inputs")
                .cloned()
                .unwrap_or_else(|| serde_json::json!({}));
            let risk_class = spec
                .get("risk_class")
                .and_then(|v| v.as_str())
                .map(|s| s.trim().to_string())
                .filter(|s| !s.is_empty());
            let metadata = spec
                .iter()
                .filter(|(key, _)| {
                    !matches!(
                        key.as_str(),
                        "domain" | "task" | "inputs" | "risk_class" | "metadata"
                    )
                })
                .map(|(key, value)| (key.clone(), value.clone()))
                .collect::<HashMap<_, _>>();
            let typed = Self {
                domain,
                task,
                inputs,
                risk_class,
                metadata,
            };
            typed.validate()?;
            Ok(typed)
        }

        pub fn from_value(value: serde_json::Value) -> FrameworkResult<Self> {
            match value {
                serde_json::Value::Object(map) => {
                    let spec = map.into_iter().collect::<HashMap<_, _>>();
                    Self::from_map(&spec)
                }
                other => Err(FrameworkError::validation(
                    "compile spec must be a JSON object",
                    serde_json::json!({"received": other}),
                )),
            }
        }

        pub fn validate(&self) -> FrameworkResult<()> {
            if self.domain.is_empty() {
                return Err(FrameworkError::validation(
                    "compile spec requires non-empty domain",
                    serde_json::json!({"field": "domain"}),
                ));
            }
            if self.task.is_empty() {
                return Err(FrameworkError::validation(
                    "compile spec requires non-empty task",
                    serde_json::json!({"field": "task"}),
                ));
            }
            Ok(())
        }

        pub fn to_map(&self) -> HashMap<String, serde_json::Value> {
            let mut spec = self.metadata.clone();
            spec.insert("domain".into(), serde_json::json!(self.domain));
            spec.insert("task".into(), serde_json::json!(self.task));
            spec.insert("inputs".into(), self.inputs.clone());
            if let Some(risk_class) = &self.risk_class {
                spec.insert("risk_class".into(), serde_json::json!(risk_class));
            }
            spec
        }

        pub fn to_json(&self) -> serde_json::Value {
            serde_json::json!(self.to_map())
        }
    }

