    pub fn build_workspace_readiness_report(
        workspace: impl AsRef<Path>,
        artifact_root: Option<&Path>,
        device_report: Option<serde_json::Value>,
    ) -> FrameworkDoctorReport {
        let workspace = workspace.as_ref();
        let artifact_root = artifact_root.map(PathBuf::from).unwrap_or_else(|| {
            framework_option_path(None, "JARVIS_FRAMEWORK_ARTIFACT_ROOT", || {
                PathBuf::from("/dev/shm/jarvis-runs")
            })
        });
        let disk = framework_disk_report(&artifact_root);
        let cargo_target_dir = framework_env_string("CARGO_TARGET_DIR")
            .map(PathBuf::from)
            .unwrap_or_else(|| workspace.join("target"));
        let cargo_target_disk = framework_disk_report(&cargo_target_dir);
        let device_report = device_report.unwrap_or_else(|| {
            framework_resolve_candle_device(
                "auto",
                "JARVIS_CUDA",
                "JARVIS_DEVICE",
                "JARVIS_WRAPPER_CUDA_STATUS",
                "jarvis-rust-0 wrapper did not provide wrapper CUDA status",
                JARVIS_CUDA_BUILD_HINT,
                "jarvis-rust-0",
            )
            .map(|(_, report)| report)
            .unwrap_or_else(|err| {
                let probe = CudaProbe::detect();
                let wrapper = framework_wrapper_cuda_status(
                    "JARVIS_WRAPPER_CUDA_STATUS",
                    "jarvis-rust-0 wrapper did not provide wrapper CUDA status",
                );
                framework_device_report_for(
                    "auto",
                    "unavailable",
                    Some(&err),
                    &probe,
                    "JARVIS_CUDA",
                    "JARVIS_DEVICE",
                    JARVIS_CUDA_BUILD_HINT,
                    &wrapper,
                )
            })
        });

        let cargo_toml = workspace.join("Cargo.toml");
        let combined_source = workspace.join("llm-javis.rs");
        let jarvis_source = if combined_source.is_file() {
            combined_source
        } else {
            workspace.join("jarvis_rust_0.rs")
        };
        let root_python_source = workspace.join("jarvis-Hermes-OS-7.py");
        let python_source = if root_python_source.is_file() {
            root_python_source
        } else {
            workspace.join("py").join("jarvis-Hermes-OS-7.py")
        };
        let source_artifacts = jarvis_source_artifact_report_for_workspace(workspace);
        let source_artifacts_exist = framework_source_artifacts_exist(&source_artifacts);
        let provenance = jarvis_provenance_report_for_workspace(workspace, None, &source_artifacts);
        let cargo_target_free_mb = cargo_target_disk
            .get("free_mb")
            .and_then(|v| v.as_u64())
            .unwrap_or(0);
        let checks = vec![
            FrameworkCheck::new(
                "workspace_exists",
                workspace.is_dir(),
                true,
                serde_json::json!({"path": workspace}),
            ),
            FrameworkCheck::new(
                "cargo_manifest_exists",
                cargo_toml.is_file(),
                true,
                serde_json::json!({"path": cargo_toml}),
            ),
            FrameworkCheck::new(
                "jarvis_rust_source_exists",
                jarvis_source.is_file(),
                true,
                serde_json::json!({"path": jarvis_source}),
            ),
            FrameworkCheck::new(
                "jarvis_python_source_exists",
                python_source.is_file(),
                false,
                serde_json::json!({"path": python_source}),
            ),
            FrameworkCheck::new(
                "artifact_root_disk_probe",
                disk.get("error").is_none(),
                true,
                disk.clone(),
            ),
            FrameworkCheck::new(
                "cargo_target_disk_preflight",
                cargo_target_disk.get("error").is_none()
                    && cargo_target_free_mb >= JARVIS_TARGET_MIN_FREE_MB,
                true,
                serde_json::json!({
                    "path": cargo_target_dir.display().to_string(),
                    "required_free_mb": JARVIS_TARGET_MIN_FREE_MB,
                    "disk": cargo_target_disk.clone(),
                }),
            ),
            FrameworkCheck::new(
                "device_report_shape",
                device_report
                    .get("selected")
                    .and_then(|v| v.as_str())
                    .is_some()
                    && device_report.get("cuda_status").is_some()
                    && device_report.get("cuda_policy").is_some(),
                true,
                device_report.clone(),
            ),
        ];
        let mut issues = Vec::new();
        let mut warnings = Vec::new();
        for check in &checks {
            if !check.ok && check.required {
                issues.push(format!("{} failed", check.name));
            } else if !check.ok {
                warnings.push(format!("{} failed", check.name));
            }
        }
        let ok = issues.is_empty();
        FrameworkDoctorReport {
            ok,
            status: report_status(ok).into(),
            verdict: report_verdict(ok, "workspace_ready", "workspace_not_ready").into(),
            schema_version: JARVIS_ARTIFACT_SCHEMA_VERSION.into(),
            command: "doctor".into(),
            run_id: serde_json::Value::Null,
            model_version: JARVIS_MODEL_VERSION.into(),
            workspace: workspace.display().to_string(),
            artifact_root: artifact_root.display().to_string(),
            cargo_target_dir: cargo_target_dir.display().to_string(),
            disk,
            cargo_target_disk,
            artifact_contract: artifact_contract_for("JARVIS_CUDA", "JARVIS_DEVICE"),
            runner_sources: source_artifacts.clone(),
            provenance,
            source_artifacts: source_artifacts.clone(),
            source_artifacts_exist,
            device_policy: device_report
                .get("device_policy")
                .cloned()
                .unwrap_or(serde_json::Value::Null),
            cuda_policy: device_report
                .get("cuda_policy")
                .cloned()
                .unwrap_or(serde_json::Value::Null),
            cuda_probe: device_report
                .get("cuda_probe")
                .cloned()
                .unwrap_or(serde_json::Value::Null),
            cuda_status: device_report
                .get("cuda_status")
                .cloned()
                .unwrap_or(serde_json::Value::Null),
            wrapper_cuda_status: device_report
                .get("wrapper_cuda_status")
                .cloned()
                .unwrap_or(serde_json::Value::Null),
            device_report,
            checks,
            issues,
            warnings,
            framework_architecture: build_production_framework_architecture_report(),
        }
    }

    pub fn framework_atomic_write_bytes(
        path: impl AsRef<Path>,
        data: &[u8],
    ) -> FrameworkResult<PathBuf> {
        let path = path.as_ref();
        let parent = path.parent().unwrap_or_else(|| Path::new("."));
        fs::create_dir_all(parent).map_err(|e| FrameworkError::io(parent, e))?;

        let stem = path
            .file_name()
            .and_then(|v| v.to_str())
            .unwrap_or("artifact");
        let now = SystemTime::now().duration_since(UNIX_EPOCH).map_err(|e| {
            FrameworkError::runtime(
                format!("system clock before unix epoch: {}", e),
                serde_json::json!({"path": path.display().to_string()}),
            )
        })?;
        let tmp_path = parent.join(format!(
            ".{}.{}.{}.tmp",
            stem,
            std::process::id(),
            now.as_nanos()
        ));

        {
            let mut file = fs::OpenOptions::new()
                .write(true)
                .create_new(true)
                .open(&tmp_path)
                .map_err(|e| FrameworkError::io(&tmp_path, e))?;
            file.write_all(data)
                .map_err(|e| FrameworkError::io(&tmp_path, e))?;
            file.sync_all()
                .map_err(|e| FrameworkError::io(&tmp_path, e))?;
        }

        fs::rename(&tmp_path, path).map_err(|e| FrameworkError::io(path, e))?;
        if let Ok(parent_file) = fs::File::open(parent) {
            parent_file
                .sync_all()
                .map_err(|e| FrameworkError::io(parent, e))?;
        }
        Ok(path.to_path_buf())
    }

    pub fn framework_atomic_write_json(
        path: impl AsRef<Path>,
        payload: &serde_json::Value,
    ) -> FrameworkResult<PathBuf> {
        let mut encoded =
            serde_json::to_vec_pretty(payload).map_err(FrameworkError::serialization)?;
        encoded.push(b'\n');
        framework_atomic_write_bytes(path, &encoded)
    }

    pub fn framework_append_json_line(
        path: impl AsRef<Path>,
        payload: &serde_json::Value,
    ) -> FrameworkResult<PathBuf> {
        let path = path.as_ref();
        let parent = path.parent().unwrap_or_else(|| Path::new("."));
        fs::create_dir_all(parent).map_err(|e| FrameworkError::io(parent, e))?;
        let mut encoded = serde_json::to_vec(payload).map_err(FrameworkError::serialization)?;
        encoded.push(b'\n');
        let mut file = fs::OpenOptions::new()
            .create(true)
            .append(true)
            .open(path)
            .map_err(|e| FrameworkError::io(path, e))?;
        file.write_all(&encoded)
            .map_err(|e| FrameworkError::io(path, e))?;
        file.sync_all().map_err(|e| FrameworkError::io(path, e))?;
        Ok(path.to_path_buf())
    }

    pub fn framework_error_payload(err: &FrameworkError) -> serde_json::Value {
        serde_json::json!({
            "ok": false,
            "status": report_status(false),
            "verdict": "framework_error",
            "schema_version": JARVIS_ARTIFACT_SCHEMA_VERSION,
            "error": err.to_json(),
        })
    }

    pub fn framework_external_compatibility_gates() -> Vec<serde_json::Value> {
        vec![
            serde_json::json!({
                "surface": "Torch checkpoint compatibility",
                "status": "external_compatibility_gate",
                "rust_contract": "CheckpointContract with hashes, non-strict diagnostics, and atomic checkpoint references",
                "production_behavior": "direct Torch state mutation is rejected unless translated through the contract"
            }),
            serde_json::json!({
                "surface": "EVO controller source mutation loop",
                "status": "external_compatibility_gate",
                "rust_contract": "HyperAgentArchive safety gate plus compiler manifest proof",
                "production_behavior": "source mutation remains disabled without explicit governance approval"
            }),
            serde_json::json!({
                "surface": "CUDA profiler wrapper",
                "status": "external_compatibility_gate",
                "rust_contract": "runtime_device_contract plus cuda/device env policy",
                "production_behavior": "CPU portable path is authoritative unless CUDA build/runtime preflight passes"
            }),
        ]
    }

