    pub trait FrameworkDomainAdapter: FrameworkComponent {
        fn domain_key(&self) -> &'static str;
        fn domain_display_name(&self) -> &'static str {
            self.domain_key()
        }
        fn domain_source_path(&self) -> &'static str;
        fn domain_plugin_registry(&self) -> DomainPluginRegistry;
        fn domain_runtime_seed(&self) -> u64 {
            0
        }

        fn supported_domain_specs(&self) -> Vec<String> {
            self.domain_plugin_registry().supported_domains()
        }

        fn supports_domain(&self, full_domain: &str) -> bool {
            self.domain_plugin_registry().is_supported(full_domain)
        }

        fn adapter_contract(&self, framework: &JarvisProductionFramework) -> serde_json::Value {
            let registry = self.domain_plugin_registry();
            let supported_domains = registry.supported_domains();
            let framework_manifest = framework.compiler.manifest(Some(&registry));
            let framework_health = framework.health();
            let framework_ok = framework_health
                .get("ok")
                .and_then(|v| v.as_bool())
                .unwrap_or(false);
            let ok = !supported_domains.is_empty() && framework_ok;
            serde_json::json!({
                "ok": ok,
                "status": report_status(ok),
                "adapter": self.component_name(),
                "adapter_version": self.component_version(),
                "domain_key": self.domain_key(),
                "domain_display_name": self.domain_display_name(),
                "domain_source_path": self.domain_source_path(),
                "framework_component": framework.component_name(),
                "framework_version": framework.component_version(),
                "framework_source_path": concat!(env!("CARGO_MANIFEST_DIR"), "/jarvis_rust_0.rs"),
                "runtime_context": "ProductionRunContext",
                "compiler_entrypoint": "JarvisProductionFramework::compile_domain_adapter_spec",
                "manifest_entrypoint": "JarvisProductionFramework::domain_adapter_manifest",
                "artifact_entrypoint": "JarvisProductionFramework::domain_adapter_report",
                "supported_domains": supported_domains,
                "manifest_hash": stable_json_hash(&serde_json::json!(framework_manifest)),
                "separation": {
                    "framework_owns": [
                        "VM execution and AIR proof",
                        "compiler native lowering",
                        "runtime/artifact contracts",
                        "device policy",
                        "model/tool service contracts"
                    ],
                    "domain_owns": [
                        "domain state geometry",
                        "domain CLI",
                        "domain data loaders and reports",
                        "domain plugin lowering inputs",
                        "domain policy adapter"
                    ],
                    "domain_calls_framework": true,
                    "framework_imports_domain": false
                }
            })
        }

        fn domain_health(&self, framework: &JarvisProductionFramework) -> FrameworkHealth {
            let contract = self.adapter_contract(framework);
            let supported_domains = contract
                .get("supported_domains")
                .and_then(|v| v.as_array())
                .map(|items| !items.is_empty())
                .unwrap_or(false);
            let framework_ok = framework
                .health()
                .get("ok")
                .and_then(|v| v.as_bool())
                .unwrap_or(false);
            FrameworkHealth::new(
                HashMap::from([
                    ("domain_plugins_registered".into(), supported_domains),
                    ("framework_health_ok".into(), framework_ok),
                    (
                        "domain_source_declared".into(),
                        !self.domain_source_path().trim().is_empty(),
                    ),
                ]),
                serde_json::json!({
                    "contract": contract,
                    "domain_runtime_seed": self.domain_runtime_seed(),
                }),
            )
        }
    }

