        pub fn try_doctor_report(&self) -> FrameworkResult<serde_json::Value> {
            Ok(build_workspace_readiness_report(
                env!("CARGO_MANIFEST_DIR"),
                Some(&self.runtime.artifact_root()),
                Some(self.default_device_report()),
            )
            .to_json())
        }

        pub fn try_dispatch_command(
            &self,
            request: &CommandRequest,
        ) -> FrameworkResult<serde_json::Value> {
            match request.command.as_str() {
                "brt-manifest" => Ok(brt_manifest_report()),
                "brt-compile" | "brt-audit" => Err(FrameworkError::command(
                    format!(
                        "{} requires the typed CLI path and confined file capabilities",
                        request.command
                    ),
                    serde_json::json!({"command": request.command}),
                )),
                "manifest" => self.try_manifest_report(),
                "head-contract" => {
                    let vocab_size = request.vocab_size.unwrap_or(28);
                    if vocab_size == 0 {
                        return Err(FrameworkError::validation(
                            "vocab_size must be greater than zero",
                            serde_json::json!({"field": "vocab_size"}),
                        ));
                    }
                    Ok(serde_json::json!({
                        "ok": true,
                        "vocab_size": vocab_size,
                        "head_contract": self.model.head_contract(vocab_size),
                        "framework_architecture": self.architecture_report(),
                        "deferred_scope": practical_parity_deferred_scope(),
                    }))
                }
                "compile" => {
                    let spec = request.spec.as_ref().ok_or_else(|| {
                        FrameworkError::validation(
                            "compile command requires typed spec",
                            serde_json::json!({"command": request.command}),
                        )
                    })?;
                    let report = self.try_compile_spec(spec)?;
                    Ok(serde_json::json!({
                        "ok": false,
                        "analysis_ok": report.ok,
                        "production_authority": false,
                        "quarantined": true,
                        "required_upgrade_path": "brt-compile",
                        "report": report,
                        "typed_spec": spec,
                        "framework_architecture": self.architecture_report(),
                        "deferred_scope": practical_parity_deferred_scope(),
                    }))
                }
                "scale-contract" => {
                    let contract = request.scale_contract.as_ref().ok_or_else(|| {
                        FrameworkError::validation(
                            "scale-contract command requires zero-shot transfer contract",
                            serde_json::json!({"command": request.command}),
                        )
                    })?;
                    let report = verify_zero_shot_transfer_contract(contract);
                    Ok(serde_json::json!({
                        "ok": report.ok,
                        "report": report,
                        "framework_architecture": self.architecture_report(),
                        "deferred_scope": practical_parity_deferred_scope(),
                    }))
                }
                "audit" => {
                    let audit = build_compiler_native_runtime_audit_report(None);
                    let ok = audit
                        .get("ok")
                        .and_then(|value| value.as_bool())
                        .unwrap_or(false);
                    Ok(serde_json::json!({
                        "ok": ok,
                        "audit": audit,
                        "framework_architecture": self.architecture_report(),
                        "deferred_scope": practical_parity_deferred_scope(),
                    }))
                }
                "self-test" => self.try_self_test_report(),
                "doctor" => self.try_doctor_report(),
                "asi-os-cycle" => Ok(serde_json::json!(build_asi_os_cycle_report(
                    self,
                    request.asi_os_config.clone().unwrap_or_default(),
                )?)),
                "setk-i2-x1" => build_setk_i2_x1_safety_case_report(self),
                "ugc" => build_ugc_safety_case_report(self),
                other => Err(FrameworkError::command(
                    format!("unknown framework command {}", other),
                    serde_json::json!({"command": other}),
                )),
            }
        }

        pub fn try_write_report(
            &self,
            payload: &serde_json::Value,
            report_output: Option<&str>,
        ) -> FrameworkResult<()> {
            if let Some(raw) = report_output {
                let path = framework_confined_report_path(raw)?;
                framework_output_path_preflight(&path, JARVIS_REPORT_MIN_FREE_MB)?;
                framework_atomic_write_json(&path, payload)?;
                println!("Report written to {}", path.display());
            } else {
                let encoded =
                    serde_json::to_string_pretty(payload).map_err(FrameworkError::serialization)?;
                println!("{}", encoded);
            }
            Ok(())
        }

