    pub const MANIFOLD_VERSION: &str = "rubik-manifold-candle-os7-v1";

    pub struct ActivationManifoldFitter {
        pub n_components: usize,
        pub mean: Option<Tensor>,
        pub pca_v: Option<Tensor>,
        pub projected: Option<Tensor>,
        pub device: Device,
    }
    impl ActivationManifoldFitter {
        pub fn new(n_components: usize, device: &Device) -> Self {
            Self {
                n_components,
                mean: None,
                pca_v: None,
                projected: None,
                device: device.clone(),
            }
        }
        pub fn fit(&mut self, data: &Tensor) -> CResult<()> {
            let mean = data.mean(0)?;
            let centered = data.broadcast_sub(&mean)?;
            let n = data.dim(0)?;
            let k = self.n_components.min(n).min(data.dim(1)?);
            let cov = centered.t()?.matmul(&centered)?;
            let scale = 1.0 / n as f64;
            let cov = (cov * scale)?;
            let dim = data.dim(1)?;
            let mut v_list = Vec::new();
            let mut residual = cov.clone();
            for _ in 0..k {
                let mut v = Tensor::randn(0.0f32, 1.0, dim, &self.device)?;
                for _ in 0..50 {
                    v = residual.matmul(&v.unsqueeze(1)?)?.squeeze(1)?;
                    let norm_val = v.sqr()?.sum_all()?.sqrt()?.to_scalar::<f32>()?;
                    if norm_val > 1e-8 {
                        v = (v / norm_val as f64)?;
                    }
                }
                let vt = v.unsqueeze(0)?;
                let vv = v.unsqueeze(1)?;
                let eigenval = vt
                    .matmul(&residual.matmul(&vv)?)?
                    .squeeze(0)?
                    .squeeze(0)?
                    .to_scalar::<f32>()? as f64;
                let outer = vv.matmul(&vt)?;
                residual = (residual - (outer * eigenval)?)?;
                v_list.push(v);
            }
            let pca_v = Tensor::stack(&v_list, 0)?; // [k, dim]
            let projected = centered.matmul(&pca_v.t()?)?; // [n, k]
            self.mean = Some(mean);
            self.pca_v = Some(pca_v);
            self.projected = Some(projected);
            Ok(())
        }
        pub fn get_spline_point(&self, t: f32) -> CResult<Tensor> {
            let projected = self
                .projected
                .as_ref()
                .ok_or_else(|| candle_core::Error::Msg("not fitted".into()))?;
            let pca_v = self.pca_v.as_ref().unwrap();
            let mean = self.mean.as_ref().unwrap();
            let n = projected.dim(0)?;
            if n < 2 {
                return Ok(mean.clone());
            }
            let idx_f = t * (n - 1) as f32;
            let idx0 = (idx_f.floor() as usize).min(n - 2);
            let idx1 = idx0 + 1;
            let frac = idx_f - idx0 as f32;
            let p0 = projected.get(idx0)?;
            let p1 = projected.get(idx1)?;
            let interp = ((p0 * (1.0 - frac as f64))? + (p1 * frac as f64)?)?;
            let reconstructed = interp.unsqueeze(0)?.matmul(&pca_v.clone())?.squeeze(0)?;
            reconstructed + mean
        }
        pub fn steer_bonus(&self, state_vec: &Tensor, t: f32) -> CResult<f32> {
            let target = self.get_spline_point(t)?;
            let dot = (state_vec * &target)?.sum_all()?.to_scalar::<f32>()?;
            let norm_a = state_vec.sqr()?.sum_all()?.sqrt()?.to_scalar::<f32>()?;
            let norm_b = target.sqr()?.sum_all()?.sqrt()?.to_scalar::<f32>()?;
            let denom = norm_a * norm_b;
            Ok(if denom > 1e-8 { dot / denom } else { 0.0 })
        }
    }
    pub struct BehaviorManifoldFitter {
        pub act_fitter: ActivationManifoldFitter,
    }
    impl BehaviorManifoldFitter {
        pub fn new(device: &Device) -> Self {
            Self {
                act_fitter: ActivationManifoldFitter::new(8, device),
            }
        }
        pub fn fit(&mut self, prob_data: &Tensor) -> CResult<()> {
            self.act_fitter.fit(prob_data)
        }
        pub fn get_spline_point(&self, t: f32) -> CResult<Tensor> {
            self.act_fitter.get_spline_point(t)
        }
    }

