    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct CausalNode {
        pub name: String,
        pub parents: Vec<String>,
        pub effect_weight: f64,
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct CausalGraph {
        pub nodes: Vec<CausalNode>,
    }

    impl Default for CausalGraph {
        fn default() -> Self {
            Self::new()
        }
    }

    impl CausalGraph {
        pub fn new() -> Self {
            Self { nodes: Vec::new() }
        }
        pub fn add_node(&mut self, name: &str, parents: &[&str], weight: f64) {
            self.nodes.push(CausalNode {
                name: name.into(),
                parents: parents.iter().map(|s| s.to_string()).collect(),
                effect_weight: weight,
            });
        }
        pub fn total_effect(&self) -> f64 {
            self.nodes.iter().map(|n| n.effect_weight.abs()).sum()
        }
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct CausalInterventionProfile {
        pub genome_id: String,
        pub causal_graph: CausalGraph,
        pub expected_utility: f64,
        pub expected_harm: f64,
        pub baseline_utility: f64,
        pub effect_variance: f64,
    }

    impl Default for CausalInterventionProfile {
        fn default() -> Self {
            Self {
                genome_id: String::new(),
                causal_graph: CausalGraph::new(),
                expected_utility: 0.0,
                expected_harm: 0.0,
                baseline_utility: 0.0,
                effect_variance: 0.0,
            }
        }
    }

    impl CausalInterventionProfile {
        pub fn net_causal_value(&self) -> f64 {
            self.expected_utility - X1_LAMBDA_H * self.expected_harm
        }
        pub fn causal_ok(&self) -> bool {
            self.expected_harm <= X1_H_MAX && self.net_causal_value() >= X1_THETA_C
        }
        pub fn hard_reject(&self) -> bool {
            self.expected_harm > X1_H_MAX
        }

        pub fn to_report(&self) -> serde_json::Value {
            serde_json::json!({
                "genome_id": self.genome_id,
                "expected_utility": self.expected_utility,
                "expected_harm": self.expected_harm,
                "net_causal_value": self.net_causal_value(),
                "causal_ok": self.causal_ok(),
                "hard_reject": self.hard_reject(),
                "effect_variance": self.effect_variance,
                "graph_nodes": self.causal_graph.nodes.len(),
            })
        }
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct UncertaintyVector {
        pub mu: f64,
        pub sigma: f64,
        pub ci_low: f64,
        pub ci_high: f64,
        pub ood: f64,
        pub epsilon: f64,
    }

    impl Default for UncertaintyVector {
        fn default() -> Self {
            Self {
                mu: 0.5,
                sigma: 0.0,
                ci_low: 0.5,
                ci_high: 0.5,
                ood: 0.0,
                epsilon: 0.0,
            }
        }
    }

    impl UncertaintyVector {
        pub fn robust_score(&self) -> f64 {
            self.mu
                - X1_LAMBDA_SIGMA * self.sigma
                - X1_LAMBDA_OOD * self.ood
                - X1_LAMBDA_EPSILON * self.epsilon
        }
        pub fn uncertainty_ok(&self) -> bool {
            self.sigma <= X1_SIGMA_MAX
                && self.ood <= X1_OOD_MAX
                && self.ci_low >= X1_CI_SAFE_LOW
                && self.ci_high <= X1_CI_SAFE_HIGH
        }
        pub fn max_deployment_stage(&self) -> DeploymentStage {
            if self.uncertainty_ok() {
                DeploymentStage::Live
            } else {
                DeploymentStage::Sandboxed
            }
        }

        pub fn to_report(&self) -> serde_json::Value {
            serde_json::json!({
                "mu": self.mu,
                "sigma": self.sigma,
                "ci": [self.ci_low, self.ci_high],
                "ood": self.ood,
                "epsilon": self.epsilon,
                "robust_score": self.robust_score(),
                "uncertainty_ok": self.uncertainty_ok(),
                "max_stage": self.max_deployment_stage().as_str(),
            })
        }
    }

