    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct KnowledgeGraphX1 {
        pub claims: Vec<KnowledgeClaim>,
        pub proofs: Vec<KnowledgeProof>,
        pub failures: Vec<KnowledgeFailure>,
        pub lineage: Vec<String>,
    }

    impl Default for KnowledgeGraphX1 {
        fn default() -> Self {
            Self::new()
        }
    }

    impl KnowledgeGraphX1 {
        pub fn new() -> Self {
            Self {
                claims: Vec::new(),
                proofs: Vec::new(),
                failures: Vec::new(),
                lineage: Vec::new(),
            }
        }
        pub fn admit_claim(&mut self, mut claim: KnowledgeClaim) -> bool {
            let ok = claim.evidence_score >= X1_THETA_E
                && claim.verifier_support >= X1_THETA_V
                && claim.contradiction_risk <= X1_RHO_C;
            claim.admitted = ok;
            self.claims.push(claim);
            ok
        }
        pub fn ingest_failure(&mut self, mut failure: KnowledgeFailure) {
            failure.scenario_generated = true;
            failure.benchmark_generated = true;
            failure.verifier_rule_generated = true;
            failure.policy_rule_generated = true;
            self.failures.push(failure);
        }

        pub fn add_proof(&mut self, proof: KnowledgeProof) {
            self.proofs.push(proof);
        }
        pub fn knowledge_value(&self) -> f64 {
            let admitted = self.claims.iter().filter(|c| c.admitted).count();
            let verified = self.proofs.iter().filter(|p| p.verified).count();
            let failure_coverage = self
                .failures
                .iter()
                .filter(|f| f.scenario_generated && f.benchmark_generated)
                .count();
            (admitted + verified + failure_coverage) as f64
        }

        pub fn report(&self) -> serde_json::Value {
            serde_json::json!({
                "claims": self.claims.len(),
                "admitted_claims": self.claims.iter().filter(|c| c.admitted).count(),
                "proofs": self.proofs.len(),
                "verified_proofs": self.proofs.iter().filter(|p| p.verified).count(),
                "failures": self.failures.len(),
                "knowledge_value": self.knowledge_value(),
            })
        }
    }

