    impl HeadEnvelopeX1 {
        pub fn alpha_u(&self, base_alpha: f64, alignment: f64) -> f64 {
            base_alpha * (1.0 - self.risk) * alignment * (1.0 - self.ood) * self.confidence
        }
        pub fn action_lane(&self, base_alpha: f64, alignment: f64) -> &'static str {
            let au = self.alpha_u(base_alpha, alignment);
            if au >= X1_KAPPA_FAST && self.proof_need <= X1_P_LOW {
                "fast"
            } else if au < X1_KAPPA_SLOW || self.proof_need > X1_P_HIGH {
                "slow"
            } else {
                "mixed"
            }
        }
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct ASIOutputExtensionX1 {
        pub causal_intervention_est: f64,
        pub uncertainty_est: f64,
        pub ood_est: f64,
        pub stability_est: f64,
        pub knowledge_delta: f64,
        pub benchmark_signal: f64,
        pub rollback_signal: f64,
        pub human_need_signal: f64,
    }

    impl ASIOutputExtensionX1 {
        pub fn adjusted_risk(&self, base_risk: f64, risk_delta: f64) -> f64 {
            base_risk
                + 0.5 * risk_delta.tanh()
                + X1_LAMBDA_OOD_RISK * self.ood_est
                + X1_LAMBDA_U_RISK * self.uncertainty_est
                + X1_LAMBDA_C_RISK * self.causal_intervention_est
                - X1_LAMBDA_S_RISK * self.stability_est
        }
    }

    pub fn governance_ok_x1(genome: &GenomeX1) -> bool {
        [
            genome.governance_quality.policy_ok(),
            genome.governance_quality.risk_bounded,
            genome.governance_quality.approval_satisfied,
            genome.causal.causal_ok(),
            genome.uncertainty.uncertainty_ok(),
            genome.benchmark.benchmark_ok(),
            genome.stability.stability_ok(),
            genome.deployment.rollback_ok(),
            genome.governance_quality.human_oversight_ok(),
            genome.governance_quality.irreversibility_ok(),
        ]
        .into_iter()
        .all(|ok| ok)
    }

    pub fn fitness_x1(genome: &GenomeX1, weights: &FitnessWeightsX1) -> f64 {
        let positive = weights.w_p * genome.performance
            + weights.w_r * genome.uncertainty.robust_score()
            + weights.w_c * genome.causal.net_causal_value().max(0.0)
            + weights.w_b * genome.benchmark.coverage()
            + weights.w_v * genome.verifier_score
            + weights.w_s
                * if genome.stability.stability_ok() {
                    1.0
                } else {
                    0.0
                }
            + weights.w_k
                * (genome.knowledge_links.claim_ids.len() + genome.knowledge_links.proof_ids.len())
                    as f64
                * 0.1;
        let negative = weights.w_h * genome.causal.expected_harm
            + weights.w_o * genome.uncertainty.ood
            + weights.w_rho * genome.risk
            + weights.w_kappa * genome.complexity;
        (positive - negative).clamp(-1.0, 2.0)
    }

    pub fn accept_x1(genome: &GenomeX1) -> bool {
        !reject_hard_x1(genome)
            && [
                genome.compile_ok,
                genome.runtime_ok,
                genome.proof_residual <= X1_EPSILON_PROOF,
                genome.verifier_drift <= X1_DELTA_V,
                governance_ok_x1(genome),
                genome.causal.causal_ok(),
                genome.uncertainty.uncertainty_ok(),
                genome.benchmark.benchmark_ok(),
                genome.stability.stability_ok(),
                genome.deployment.rollback_ok(),
                genome.fitness_x1 >= X1_THETA_F,
            ]
            .into_iter()
            .all(|ok| ok)
    }

    pub fn reject_hard_x1(genome: &GenomeX1) -> bool {
        [
            genome.causal.hard_reject(),
            !genome.governance_quality.policy_ok(),
            genome.governance_quality.irreversible
                && !genome.governance_quality.human_approved_irreversible,
            genome.proof_residual > X1_EPSILON_PROOF,
            genome.verifier_drift > X1_DELTA_V,
            !genome.stability.stability_ok(),
        ]
        .into_iter()
        .any(|blocked| blocked)
    }

    pub fn promote_x1(genome: &GenomeX1, target: DeploymentStage) -> bool {
        accept_x1(genome) && genome.stage.can_promote_to(target) && genome.deployment.rollback_ok()
    }

    pub fn should_rollback(
        runtime_anomaly: bool,
        policy_breach: bool,
        causal_harm_spike: bool,
        ood_spike: bool,
        verifier_failure: bool,
        human_override: bool,
    ) -> Option<RollbackTrigger> {
        if runtime_anomaly {
            Some(RollbackTrigger::RuntimeAnomaly)
        } else if policy_breach {
            Some(RollbackTrigger::PolicyBreach)
        } else if causal_harm_spike {
            Some(RollbackTrigger::CausalHarmSpike)
        } else if ood_spike {
            Some(RollbackTrigger::OODSpike)
        } else if verifier_failure {
            Some(RollbackTrigger::VerifierFailure)
        } else if human_override {
            Some(RollbackTrigger::HumanOverride)
        } else {
            None
        }
    }

