    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct ProofChannelReport {
        pub channel: String,
        pub ok: bool,
        pub residual: f64,
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct MultiChannelProofX1 {
        pub channels: Vec<ProofChannelReport>,
        pub total_residual: f64,
        pub all_ok: bool,
    }

    impl MultiChannelProofX1 {
        pub fn build(channels: Vec<ProofChannelReport>) -> Self {
            let total_residual: f64 = channels.iter().map(|c| c.residual).sum();
            let all_ok = channels.iter().all(|c| c.ok);
            Self {
                channels,
                total_residual,
                all_ok,
            }
        }
        pub fn proof_channel_completeness(&self) -> bool {
            SETK_PROOF_CHANNELS_X1.iter().all(|expected| {
                self.channels
                    .iter()
                    .any(|channel| channel.channel == *expected)
            })
        }
        pub fn proof_ok_x1(&self) -> bool {
            self.all_ok
                && self.proof_channel_completeness()
                && self.total_residual <= X1_EPSILON_PROOF
        }
        pub fn channel_completeness_report(&self) -> serde_json::Value {
            let missing = SETK_PROOF_CHANNELS_X1
                .iter()
                .filter(|expected| {
                    !self
                        .channels
                        .iter()
                        .any(|channel| channel.channel == **expected)
                })
                .copied()
                .collect::<Vec<_>>();
            let unexpected = self
                .channels
                .iter()
                .filter(|channel| {
                    !SETK_PROOF_CHANNELS_X1
                        .iter()
                        .any(|expected| channel.channel == *expected)
                })
                .map(|channel| channel.channel.clone())
                .collect::<Vec<_>>();
            serde_json::json!({
                "ok": missing.is_empty(),
                "expected_channels": SETK_PROOF_CHANNELS_X1,
                "observed_channels": self.channels.iter().map(|c| c.channel.clone()).collect::<Vec<_>>(),
                "missing_channels": missing,
                "unexpected_channels": unexpected,
            })
        }
        #[allow(clippy::too_many_arguments)]
        pub fn from_components(
            vm_ok: bool,
            vm_residual: f64,
            air_ok: bool,
            air_residual: f64,
            policy_ok: bool,
            causal_ok: bool,
            uncertainty_ok: bool,
            stability_ok: bool,
            rollback_ok: bool,
            audit_ok: bool,
        ) -> Self {
            let gated = |channel: &str, ok: bool| ProofChannelReport {
                channel: channel.into(),
                ok,
                residual: if ok { 0.0 } else { 1.0 },
            };
            Self::build(vec![
                ProofChannelReport {
                    channel: SETK_PROOF_CHANNELS_X1[0].into(),
                    ok: vm_ok,
                    residual: vm_residual,
                },
                ProofChannelReport {
                    channel: SETK_PROOF_CHANNELS_X1[1].into(),
                    ok: air_ok,
                    residual: air_residual,
                },
                gated(SETK_PROOF_CHANNELS_X1[2], policy_ok),
                gated(SETK_PROOF_CHANNELS_X1[3], causal_ok),
                gated(SETK_PROOF_CHANNELS_X1[4], uncertainty_ok),
                gated(SETK_PROOF_CHANNELS_X1[5], stability_ok),
                gated(SETK_PROOF_CHANNELS_X1[6], rollback_ok),
                gated(SETK_PROOF_CHANNELS_X1[7], audit_ok),
            ])
        }

        pub fn to_report(&self) -> serde_json::Value {
            serde_json::json!({
                "proof_ok": self.proof_ok_x1(),
                "total_residual": self.total_residual,
                "all_channels_ok": self.all_ok,
                "channel_completeness": self.channel_completeness_report(),
                "channel_count": self.channels.len(),
                "channels": self.channels.iter().map(|c| {
                    serde_json::json!({"channel": c.channel, "ok": c.ok, "residual": c.residual})
                }).collect::<Vec<_>>(),
            })
        }
    }

