    pub struct GenomeArchiveX1 {
        pub genomes: Vec<GenomeX1>,
        pub next_id: usize,
        pub best_fitness: f64,
        pub generations_run: usize,
        pub knowledge_graph: KnowledgeGraphX1,
        pub benchmark_ecology: BenchmarkEcology,
        pub meta_verifier_stack: MetaVerifierStack,
    }

    impl Default for GenomeArchiveX1 {
        fn default() -> Self {
            Self::new()
        }
    }

    impl GenomeArchiveX1 {
        pub fn new() -> Self {
            Self {
                genomes: Vec::new(),
                next_id: 0,
                best_fitness: f64::NEG_INFINITY,
                generations_run: 0,
                knowledge_graph: KnowledgeGraphX1::new(),
                benchmark_ecology: BenchmarkEcology::new(),
                meta_verifier_stack: MetaVerifierStack::new(),
            }
        }
        pub fn seed_from_x0(&mut self, x0_archive: &HyperAgentArchiveV2) {
            for g in &x0_archive.genomes {
                let mut x1 = GenomeX1::from_x0(g);
                x1.genome_id = self.next_id;
                self.next_id += 1;
                self.genomes.push(x1);
            }
        }
        pub fn run_generation_x1(
            &mut self,
            eval_fn: &dyn Fn(&GenomeX1) -> f64,
            weights: &FitnessWeightsX1,
        ) -> Vec<RSIStepResultX1> {
            let mut results = Vec::new();
            for g in &mut self.genomes {
                g.performance = eval_fn(g);
                g.fitness_x1 = fitness_x1(g, weights);
            }
            self.genomes
                .sort_by(|a, b| b.fitness_x1.total_cmp(&a.fitness_x1));
            if let Some(best) = self.genomes.first() {
                self.best_fitness = best.fitness_x1;
            }
            for g in &self.genomes {
                results.push(RSIStepResultX1 {
                    genome_id: g.genome_id,
                    accepted: accept_x1(g),
                    rejected_hard: reject_hard_x1(g),
                    stage: g.stage,
                    fitness: g.fitness_x1,
                    causal_ok: g.causal.causal_ok(),
                    uncertainty_ok: g.uncertainty.uncertainty_ok(),
                    benchmark_ok: g.benchmark.benchmark_ok(),
                    stability_ok: g.stability.stability_ok(),
                    governance_ok: governance_ok_x1(g),
                    rollback_trigger: None,
                });
            }
            self.generations_run += 1;
            results
        }
        pub fn best_accepted(&self) -> Option<&GenomeX1> {
            self.genomes.iter().find(|g| accept_x1(g))
        }

        pub fn report(&self) -> serde_json::Value {
            let accepted_count = self.genomes.iter().filter(|g| accept_x1(g)).count();
            let hard_rejected = self.genomes.iter().filter(|g| reject_hard_x1(g)).count();
            serde_json::json!({
                "archive_size": self.genomes.len(),
                "best_fitness": self.best_fitness,
                "generations": self.generations_run,
                "accepted": accepted_count,
                "hard_rejected": hard_rejected,
                "knowledge": self.knowledge_graph.report(),
                "benchmarks": self.benchmark_ecology.report(),
                "meta_verifiers": self.meta_verifier_stack.report(),
                "x1_version": JARVIS_X1_GENOME_VERSION,
            })
        }
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct OmegaX1State {
        pub generation: usize,
        pub genome_count: usize,
        pub best_fitness: f64,
        pub accepted_count: usize,
        pub hard_rejected_count: usize,
        pub knowledge_value: f64,
        pub benchmark_coverage: f64,
        pub stability_margin: f64,
        pub deployment_stage: DeploymentStage,
        pub x1_version: String,
    }

    pub fn omega_x1_snapshot(archive: &GenomeArchiveX1) -> OmegaX1State {
        let accepted_count = archive.genomes.iter().filter(|g| accept_x1(g)).count();
        let hard_rejected = archive.genomes.iter().filter(|g| reject_hard_x1(g)).count();
        let avg_coverage = if archive.genomes.is_empty() {
            0.0
        } else {
            archive
                .genomes
                .iter()
                .map(|g| g.benchmark.coverage())
                .sum::<f64>()
                / archive.genomes.len() as f64
        };
        let best_stage = archive
            .best_accepted()
            .map(|g| g.stage)
            .unwrap_or(DeploymentStage::Draft);
        let avg_margin = if archive.genomes.is_empty() {
            0.0
        } else {
            archive
                .genomes
                .iter()
                .map(|g| g.stability.control_margin())
                .sum::<f64>()
                / archive.genomes.len() as f64
        };
        OmegaX1State {
            generation: archive.generations_run,
            genome_count: archive.genomes.len(),
            best_fitness: archive.best_fitness,
            accepted_count,
            hard_rejected_count: hard_rejected,
            knowledge_value: archive.knowledge_graph.knowledge_value(),
            benchmark_coverage: avg_coverage,
            stability_margin: avg_margin,
            deployment_stage: best_stage,
            x1_version: JARVIS_X1_GENOME_VERSION.into(),
        }
    }

