    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct QualityVectorX1 {
        pub q_perf: f64,
        pub q_truth: f64,
        pub q_safety: f64,
        pub q_security: f64,
        pub q_robust: f64,
        pub q_govern: f64,
        pub q_cost: f64,
        pub q_latency: f64,
        pub q_novelty: f64,
        pub q_reversible: f64,
        pub q_identity: f64,
        pub q_agreement: f64,
        pub q_learning: f64,
    }

    impl QualityVectorX1 {
        pub fn components(&self) -> [f64; 13] {
            [
                self.q_perf,
                self.q_truth,
                self.q_safety,
                self.q_security,
                self.q_robust,
                self.q_govern,
                self.q_cost,
                self.q_latency,
                self.q_novelty,
                self.q_reversible,
                self.q_identity,
                self.q_agreement,
                self.q_learning,
            ]
        }

        pub fn weighted_quality(&self) -> f64 {
            let weights = [
                0.14, 0.10, 0.12, 0.10, 0.10, 0.10, 0.06, 0.05, 0.04, 0.07, 0.05, 0.04, 0.03,
            ];
            self.components()
                .iter()
                .zip(weights.iter())
                .map(|(q, w)| q.clamp(0.0, 1.0) * w)
                .sum::<f64>()
        }

        pub fn scalar_score(&self, risk: f64, cost: f64, harm: f64, latency: f64) -> f64 {
            self.weighted_quality() - 0.20 * risk - 0.10 * cost - 0.25 * harm - 0.05 * latency
        }

        pub fn to_report(
            &self,
            risk: f64,
            cost: f64,
            harm: f64,
            latency: f64,
        ) -> serde_json::Value {
            serde_json::json!({
                "components": {
                    "performance": self.q_perf,
                    "truth": self.q_truth,
                    "safety": self.q_safety,
                    "security": self.q_security,
                    "robust": self.q_robust,
                    "governance": self.q_govern,
                    "cost": self.q_cost,
                    "latency": self.q_latency,
                    "novelty": self.q_novelty,
                    "reversible": self.q_reversible,
                    "identity": self.q_identity,
                    "agreement": self.q_agreement,
                    "learning": self.q_learning,
                },
                "weighted_quality": self.weighted_quality(),
                "scalar_score": self.scalar_score(risk, cost, harm, latency),
            })
        }
    }

