    impl DataGateX1 {
        pub fn ok(&self) -> bool {
            self.consent_ok
                && self.purpose_ok
                && self.retention_ok
                && self.access_ok
                && self.pii_ok
                && self.lineage_ok
        }
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct ObjectiveContinuityCertificate {
        pub utility_drift: f64,
        pub human_mandate_change: bool,
        pub governance_approval: bool,
        pub lineage_recorded: bool,
    }

    impl ObjectiveContinuityCertificate {
        pub fn ok(&self) -> bool {
            self.utility_drift <= SETK_OBJECTIVE_DRIFT_EPSILON
                || (self.human_mandate_change && self.governance_approval && self.lineage_recorded)
        }
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct GeneralizationCertificateX1 {
        pub perf_test_delta: f64,
        pub perf_shadow_delta: f64,
        pub ood_robustness_delta: f64,
        pub benchmark_leakage: bool,
    }

    impl GeneralizationCertificateX1 {
        pub fn ok(&self) -> bool {
            !(self.benchmark_leakage
                || (self.perf_test_delta > 0.0
                    && (self.perf_shadow_delta < 0.0 || self.ood_robustness_delta < 0.0)))
        }
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct LongHorizonCertificateX1 {
        pub candidate_value: f64,
        pub baseline_value: f64,
        pub horizon: usize,
        pub gamma: f64,
    }

    impl LongHorizonCertificateX1 {
        pub fn value_delta(&self) -> f64 {
            self.candidate_value - self.baseline_value
        }

        pub fn ok(&self) -> bool {
            self.value_delta() >= SETK_LONG_HORIZON_THRESHOLD
        }
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct RsiAcceptanceCertificateX1 {
        pub performance_gain: f64,
        pub safe_regret_bound: f64,
        pub epsilon: f64,
        pub security_regression: bool,
        pub objective_continuity_ok: bool,
        pub generalization_ok: bool,
        pub human_gate_ok: bool,
    }

    impl RsiAcceptanceCertificateX1 {
        pub fn ok(&self) -> bool {
            self.performance_gain > 0.0
                && self.safe_regret_bound <= self.epsilon
                && !self.security_regression
                && self.objective_continuity_ok
                && self.generalization_ok
                && self.human_gate_ok
        }
    }

