    pub fn setk_i2_x1_section_coverage_report() -> serde_json::Value {
        let sections = setk_i2_x1_section_coverage();
        let unique_sections = sections
            .iter()
            .map(|s| s.section)
            .collect::<HashSet<_>>()
            .len();
        let complete = sections.len() == SETK_I2_X1_SECTION_COUNT
            && unique_sections == SETK_I2_X1_SECTION_COUNT
            && sections
                .iter()
                .enumerate()
                .all(|(idx, section)| section.section == idx + 1);
        serde_json::json!({
            "ok": complete,
            "covered_sections": sections.len(),
            "expected_sections": SETK_I2_X1_SECTION_COUNT,
            "unique_sections": unique_sections,
            "sections": sections,
        })
    }

    pub fn compile_proof_object_x1(compile_report: &UnifiedProofReport) -> serde_json::Value {
        let proof = compile_report.vm_proof.as_ref();
        serde_json::json!({
            "ok": proof.map(|p| p.ok).unwrap_or(false),
            "R_AIR": proof.map(|p| p.residual).unwrap_or(1.0),
            "H_trace": proof.map(|p| p.trace_hash.clone()).unwrap_or_default(),
            "H_final": proof.map(|p| p.final_state_hash.clone()).unwrap_or_default(),
            "y": proof.and_then(|p| p.public_output),
            "L": proof.map(|p| p.witness_rows).unwrap_or(0),
            "Report": proof.map(|p| {
                serde_json::json!({
                    "constraints": p.constraints.clone(),
                    "errors": p.errors.clone(),
                })
            }).unwrap_or_else(|| serde_json::json!({"errors": ["missing_vm_proof"]})),
        })
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct SetkI2X1EvaluationCase {
        pub candidate: CandidateEditX1,
        pub authoritative_external_evidence: bool,
        pub genome: GenomeX1,
        pub quality: QualityVectorX1,
        pub protected_eval: ProtectedEvaluationBoundary,
        pub reality_anchor: RealityAnchorEvidence,
        pub causal_credit: CausalCreditEvidence,
        pub meta_verification: MetaVerificationReport,
        pub proof: MultiChannelProofX1,
        pub security: SecurityGateX1,
        pub data: DataGateX1,
        pub objective: ObjectiveContinuityCertificate,
        pub generalization: GeneralizationCertificateX1,
        pub long_horizon: LongHorizonCertificateX1,
        pub rsi: RsiAcceptanceCertificateX1,
        pub archive_diversity: ArchiveDiversityCertificateX1,
        pub rollback_state: RollbackRecoveryStateX1,
        pub current_stage: DeploymentStage,
        pub target_stage: DeploymentStage,
    }

    impl SetkI2X1EvaluationCase {
        pub fn hard_reject_reasons(&self) -> Vec<String> {
            let mut reasons = Vec::new();
            if self.genome.causal.expected_harm > X1_H_MAX {
                reasons.push("expected_harm_above_0_15".into());
            }
            if !self.genome.governance_quality.policy_ok() {
                reasons.push("policy_not_ok".into());
            }
            if self.genome.governance_quality.irreversible
                && !self.genome.governance_quality.human_approved_irreversible
            {
                reasons.push("irreversible_without_human_approval".into());
            }
            if self.proof.total_residual > X1_EPSILON_PROOF {
                reasons.push("proof_residual_above_1e_5".into());
            }
            if self.genome.verifier_drift > X1_DELTA_V {
                reasons.push("verifier_drift_above_0_10".into());
            }
            if !self.genome.stability.stability_ok() {
                reasons.push("stability_control_margin_negative".into());
            }
            reasons
        }

        pub fn hard_reject(&self) -> bool {
            !self.hard_reject_reasons().is_empty()
        }

        pub fn gate_matrix(&self) -> Vec<GateEvidenceX1> {
            let long_horizon_ok =
                !self.candidate.target.requires_long_horizon() || self.long_horizon.ok();
            let rsi_gate_ok = !self.candidate.target.requires_rsi_acceptance() || self.rsi.ok();
            vec![
            GateEvidenceX1::new(
                "authoritative_external_evidence_missing",
                self.authoritative_external_evidence,
                true,
                "independent BRT V11 validator, bridge, audit, rollback, and shutdown evidence",
                serde_json::json!({
                    "authoritative_external_evidence": self.authoritative_external_evidence,
                    "legacy_reference_values_are_authoritative": false,
                }),
                "quarantine",
            ),
            GateEvidenceX1::new(
                "reject_hard",
                !self.hard_reject(),
                true,
                "no hard rejection reasons",
                serde_json::json!(self.hard_reject_reasons()),
                "reject",
            ),
            GateEvidenceX1::new(
                "compile_not_ok",
                self.genome.compile_ok,
                false,
                "CompileOK=1",
                serde_json::json!(self.genome.compile_ok),
                "reject",
            ),
            GateEvidenceX1::new(
                "runtime_not_ok",
                self.genome.runtime_ok,
                false,
                "RuntimeOK=1",
                serde_json::json!(self.genome.runtime_ok),
                "reject",
            ),
            GateEvidenceX1::new(
                "proof_not_ok",
                self.proof.proof_ok_x1(),
                true,
                "AllChannelsOK and R_proof<=1e-5",
                self.proof.to_report(),
                "reject",
            ),
            GateEvidenceX1::new(
                "verifier_drift_not_ok",
                self.genome.verifier_drift <= X1_DELTA_V,
                true,
                "verifierDrift<=0.10",
                serde_json::json!(self.genome.verifier_drift),
                "reject",
            ),
            GateEvidenceX1::new(
                "governance_not_ok",
                governance_ok_x1(&self.genome),
                false,
                "PolicyOK and risk/causal/uncertainty/benchmark/stability/rollback/human gates",
                serde_json::json!({
                    "policy_ok": self.genome.governance_quality.policy_ok(),
                    "risk_bounded": self.genome.governance_quality.risk_bounded,
                    "approval_satisfied": self.genome.governance_quality.approval_satisfied,
                    "human_oversight_ok": self.genome.governance_quality.human_oversight_ok(),
                    "irreversibility_ok": self.genome.governance_quality.irreversibility_ok(),
                }),
                "reject",
            ),
            GateEvidenceX1::new(
                "causal_not_ok",
                self.genome.causal.causal_ok(),
                false,
                "H<=0.15 and U-2H>=0.10",
                self.genome.causal.to_report(),
                "reject",
            ),
            GateEvidenceX1::new(
                "causal_credit_not_ok",
                self.causal_credit.ok(),
                false,
                "do(edit)-do(null)>=0.10",
                serde_json::json!({
                    "gain_delta": self.causal_credit.gain_delta(),
                    "utility_delta": self.causal_credit.utility_delta(),
                }),
                "reject",
            ),
            GateEvidenceX1::new(
                "uncertainty_not_ok",
                self.genome.uncertainty.uncertainty_ok(),
                false,
                "sigma<=0.30, OOD<=0.25, CI in [0.05,0.95]",
                self.genome.uncertainty.to_report(),
                "cap_at_sandbox_or_reject",
            ),
            GateEvidenceX1::new(
                "benchmark_not_ok",
                self.genome.benchmark.benchmark_ok(),
                false,
                "coverage>=0.70 and adversarial_gap<=0.30",
                serde_json::json!({
                    "coverage": self.genome.benchmark.coverage(),
                    "adversarial_gap": self.genome.benchmark.adversarial_gap(),
                }),
                "reject",
            ),
            GateEvidenceX1::new(
                "meta_verifier_not_ok",
                self.meta_verification.verifier_accept(),
                false,
                "pass and residual<=1e-4 and coverage>=0.80 and soundness>=0.85 and drift<=0.10",
                serde_json::json!(&self.meta_verification),
                "reject",
            ),
            GateEvidenceX1::new(
                "stability_not_ok",
                self.genome.stability.stability_ok(),
                true,
                "DeltaC<=DeltaS+DeltaV+DeltaG+DeltaK",
                self.genome.stability.to_report(),
                "freeze_upgrade",
            ),
            GateEvidenceX1::new(
                "rollback_not_ok",
                self.genome.deployment.rollback_ok() && self.rollback_state.ready(),
                false,
                "rollback tested and recovery state ready",
                serde_json::json!({
                    "deployment_rollback_ok": self.genome.deployment.rollback_ok(),
                    "recovery_state_ready": self.rollback_state.ready(),
                    "deployment": self.genome.deployment,
                    "rollback_state": self.rollback_state,
                }),
                "rollback",
            ),
            GateEvidenceX1::new(
                "protected_eval_not_ok",
                self.protected_eval.ok(),
                false,
                "protected evaluator boundary intact",
                serde_json::json!(&self.protected_eval),
                "quarantine",
            ),
            GateEvidenceX1::new(
                "reality_anchor_not_ok",
                self.reality_anchor.ok(),
                false,
                "reality score>=0.60",
                serde_json::json!({
                    "score": self.reality_anchor.score(),
                    "evidence": self.reality_anchor,
                }),
                "reject",
            ),
            GateEvidenceX1::new(
                "security_not_ok",
                self.security.ok(),
                false,
                "Auth/permission/secret/injection/exfiltration/supply-chain gates",
                serde_json::json!(&self.security),
                "reject",
            ),
            GateEvidenceX1::new(
                "data_not_ok",
                self.data.ok(),
                false,
                "consent/purpose/retention/access/PII/lineage gates",
                serde_json::json!(&self.data),
                "reject",
            ),
            GateEvidenceX1::new(
                "objective_continuity_not_ok",
                self.objective.ok(),
                false,
                "utility drift<=epsilon or approved mandate change",
                serde_json::json!(&self.objective),
                "reject",
            ),
            GateEvidenceX1::new(
                "generalization_not_ok",
                self.generalization.ok(),
                false,
                "no test/shadow inversion, no OOD robustness regression, no leakage",
                serde_json::json!(&self.generalization),
                "reject",
            ),
            GateEvidenceX1::new(
                "long_horizon_not_ok",
                long_horizon_ok,
                false,
                "self/mechanism edits require LH-LH_base>=0",
                serde_json::json!({
                    "required": self.candidate.target.requires_long_horizon(),
                    "value_delta": self.long_horizon.value_delta(),
                    "certificate": self.long_horizon,
                }),
                "reject",
            ),
            GateEvidenceX1::new(
                "rsi_acceptance_not_ok",
                rsi_gate_ok,
                false,
                "self/mechanism edits require performance gain, regret bound, security, objective, generalization, human gate",
                serde_json::json!({
                    "required": self.candidate.target.requires_rsi_acceptance(),
                    "rsi": self.rsi,
                }),
                "reject",
            ),
            GateEvidenceX1::new(
                "fitness_below_0_50",
                self.genome.fitness_x1 >= X1_THETA_F,
                false,
                "F_X1>=0.50",
                serde_json::json!(self.genome.fitness_x1),
                "archive_or_reject",
            ),
        ]
        }

        pub fn gate_matrix_report(&self) -> serde_json::Value {
            let gates = self.gate_matrix();
            let failed = gates.iter().filter(|gate| !gate.ok).count();
            let hard_failed = gates.iter().filter(|gate| !gate.ok && gate.hard).count();
            serde_json::json!({
                "ok": failed == 0,
                "gate_count": gates.len(),
                "failed_count": failed,
                "hard_failed_count": hard_failed,
                "gates": gates,
            })
        }

        pub fn gate_failures(&self) -> Vec<String> {
            self.gate_matrix()
                .into_iter()
                .filter(|gate| !gate.ok)
                .map(|gate| gate.name)
                .collect()
        }

        pub fn risk_adaptation_report(&self) -> serde_json::Value {
            let base_risk = self.candidate.risk;
            let risk_delta = self.genome.risk - self.candidate.risk;
            let uncertainty = self.genome.uncertainty.sigma;
            let causal_intervention_risk = self.genome.causal.expected_harm;
            let stability_score = self.genome.stability.control_margin().clamp(0.0, 1.0);
            let adjusted = base_risk
                + 0.5 * risk_delta.tanh()
                + X1_LAMBDA_OOD_RISK * self.genome.uncertainty.ood
                + X1_LAMBDA_U_RISK * uncertainty
                + X1_LAMBDA_C_RISK * causal_intervention_risk
                - X1_LAMBDA_S_RISK * stability_score;
            serde_json::json!({
                "base_risk": base_risk,
                "risk_delta": risk_delta,
                "ood": self.genome.uncertainty.ood,
                "uncertainty": uncertainty,
                "causal_intervention_risk": causal_intervention_risk,
                "stability_score": stability_score,
                "adjusted_risk": adjusted.clamp(0.0, 1.0),
                "formula": "r'=r0+0.5*tanh(delta_r)+0.3*OOD+0.2*U+0.4*C-0.3*S",
            })
        }

        pub fn routing_report(&self) -> serde_json::Value {
            let proof_need = if self.proof.proof_ok_x1() { 0.10 } else { 0.90 };
            let alpha_u = compute_alpha_u(
                1.0,
                self.genome.risk,
                self.quality.q_identity,
                self.genome.uncertainty.ood,
                self.quality.q_truth,
            );
            serde_json::json!({
                "alpha_u": alpha_u,
                "lane": action_selection_lane(alpha_u, proof_need),
                "proof_need": proof_need,
                "inputs": {
                    "base_alpha": 1.0,
                    "risk": self.genome.risk,
                    "alignment": self.quality.q_identity,
                    "ood": self.genome.uncertainty.ood,
                    "confidence": self.quality.q_truth,
                },
                "fast_lane": alpha_u >= X1_KAPPA_FAST && proof_need <= X1_P_LOW,
                "slow_lane": alpha_u < X1_KAPPA_SLOW || proof_need > X1_P_HIGH,
            })
        }

        pub fn capability_control_report(&self) -> serde_json::Value {
            let control_growth = self.genome.stability.safety_delta
                + self.genome.stability.verifier_delta
                + self.genome.stability.governance_delta
                + self.genome.stability.control_delta;
            let control_margin = control_growth - self.genome.stability.capability_delta;
            serde_json::json!({
                "capability_delta": self.genome.stability.capability_delta,
                "control_growth": control_growth,
                "control_margin": control_margin,
                "freeze_upgrade": self.genome.stability.capability_delta > control_growth,
                "lambda_weights": SETK_CAPABILITY_CONTROL_LAMBDAS,
                "terms": {
                    "delta_safety": self.genome.stability.safety_delta,
                    "delta_eval_quality": self.genome.stability.verifier_delta,
                    "delta_governance": self.genome.stability.governance_delta,
                    "delta_rollback_power": self.genome.stability.control_delta,
                    "delta_interpretability": 0.0,
                },
            })
        }

        pub fn knowledge_admission_report(&self) -> serde_json::Value {
            let evidence_score = self.reality_anchor.score();
            let verifier_support = self.meta_verification.soundness;
            let contradiction_risk = (1.0 - self.quality.q_agreement).clamp(0.0, 1.0);
            let admitted = evidence_score >= X1_THETA_E
                && verifier_support >= X1_THETA_V
                && contradiction_risk <= X1_RHO_C;
            let admitted_count = if admitted { 1usize } else { 0usize };
            let verified_proofs = if self.proof.proof_ok_x1() {
                1usize
            } else {
                0usize
            };
            let covered_failures = if self.generalization.ok() {
                1usize
            } else {
                0usize
            };
            serde_json::json!({
                "claim": {
                    "id": "claim-setk-i2-x1-unified-gate",
                    "evidence_score": evidence_score,
                    "verifier_support": verifier_support,
                    "contradiction_risk": contradiction_risk,
                    "admitted": admitted,
                },
                "knowledge_value": admitted_count + verified_proofs + covered_failures,
                "verified_proofs": verified_proofs,
                "covered_failures": covered_failures,
                "admission_rule": "e>=0.60 and v>=0.80 and rho<=0.20",
            })
        }

        pub fn rsi_accept(&self) -> bool {
            self.accept()
                && self.candidate.target.requires_rsi_acceptance()
                && self.rsi.ok()
                && self.long_horizon.ok()
                && self.genome.stability.stability_ok()
                && self.protected_eval.ok()
                && governance_ok_x1(&self.genome)
                && self.genome.deployment.rollback_ok()
                && self.rollback_state.ready()
        }

        pub fn accept(&self) -> bool {
            self.gate_failures().is_empty()
        }

        pub fn promote(&self) -> bool {
            self.accept()
                && self.current_stage.can_promote_to(self.target_stage)
                && self.genome.deployment.rollback_ok()
        }

        pub fn archive(&self) -> bool {
            !self.accept() && !self.hard_reject() && self.genome.fitness_x1 >= 0.25
        }

        pub fn rollback(&self) -> bool {
            !self.accept() && !self.archive()
        }

        pub fn escalate(&self) -> bool {
            matches!(
                self.candidate.review_route(),
                SetkReviewRoute::ProtectedMetaReview | SetkReviewRoute::HigherOrderApproval
            ) || (self.genome.governance_quality.high_risk
                && !self.genome.governance_quality.human_reviewed)
        }

        pub fn selected_action(&self) -> SetkDecisionActionX1 {
            if self.promote() {
                SetkDecisionActionX1::Promote
            } else if self.escalate() {
                SetkDecisionActionX1::Escalate
            } else if self.archive() {
                SetkDecisionActionX1::Archive
            } else {
                SetkDecisionActionX1::Rollback
            }
        }

        pub fn max_deployment_stage(&self) -> DeploymentStage {
            if self.authoritative_external_evidence {
                self.genome.uncertainty.max_deployment_stage()
            } else {
                DeploymentStage::Sandboxed
            }
        }

        pub fn decision_report(&self) -> serde_json::Value {
            let gate_failures = self.gate_failures();
            let hard_reject_reasons = self.hard_reject_reasons();
            let mut report = serde_json::Map::new();
            report.insert(
                "accept_x1".into(),
                serde_json::json!(gate_failures.is_empty()),
            );
            report.insert("promote".into(), serde_json::json!(self.promote()));
            report.insert("archive".into(), serde_json::json!(self.archive()));
            report.insert("rollback".into(), serde_json::json!(self.rollback()));
            report.insert("escalate".into(), serde_json::json!(self.escalate()));
            report.insert(
                "selected_action".into(),
                serde_json::json!(self.selected_action().as_str()),
            );
            report.insert(
                "hard_reject".into(),
                serde_json::json!(!hard_reject_reasons.is_empty()),
            );
            report.insert(
                "hard_reject_reasons".into(),
                serde_json::json!(hard_reject_reasons),
            );
            report.insert("gate_failures".into(), serde_json::json!(gate_failures));
            report.insert("gate_matrix".into(), self.gate_matrix_report());
            report.insert(
                "current_stage".into(),
                serde_json::json!(self.current_stage.as_str()),
            );
            report.insert(
                "target_stage".into(),
                serde_json::json!(self.target_stage.as_str()),
            );
            report.insert(
                "adjacent_stage".into(),
                serde_json::json!(self.current_stage.can_promote_to(self.target_stage)),
            );
            report.insert(
                "max_deployment_stage".into(),
                serde_json::json!(self.max_deployment_stage().as_str()),
            );
            report.insert("candidate".into(), self.candidate.to_report());
            report.insert(
                "quality".into(),
                self.quality.to_report(
                    self.genome.risk,
                    self.genome.complexity,
                    self.genome.causal.expected_harm,
                    1.0 - self.quality.q_latency,
                ),
            );
            report.insert("proof".into(), self.proof.to_report());
            report.insert("policy_routing".into(), self.routing_report());
            report.insert("risk_adaptation".into(), self.risk_adaptation_report());
            report.insert(
                "protected_eval_ok".into(),
                serde_json::json!(self.protected_eval.ok()),
            );
            report.insert(
                "reality_score".into(),
                serde_json::json!(self.reality_anchor.score()),
            );
            report.insert(
                "reality_ok".into(),
                serde_json::json!(self.reality_anchor.ok()),
            );
            report.insert("causal".into(), self.genome.causal.to_report());
            report.insert(
                "causal_credit".into(),
                serde_json::json!({
                    "ok": self.causal_credit.ok(),
                    "gain_delta": self.causal_credit.gain_delta(),
                    "utility_delta": self.causal_credit.utility_delta(),
                }),
            );
            report.insert("uncertainty".into(), self.genome.uncertainty.to_report());
            report.insert(
                "benchmark".into(),
                serde_json::json!({
                    "coverage": self.genome.benchmark.coverage(),
                    "adversarial_gap": self.genome.benchmark.adversarial_gap(),
                    "benchmark_ok": self.genome.benchmark.benchmark_ok(),
                }),
            );
            report.insert(
                "meta_verification".into(),
                serde_json::json!({
                    "verifier_id": self.meta_verification.verifier_id,
                    "accepted": self.meta_verification.verifier_accept(),
                    "residual": self.meta_verification.residual,
                    "coverage": self.meta_verification.coverage,
                    "soundness": self.meta_verification.soundness,
                    "drift": self.meta_verification.drift,
                }),
            );
            report.insert("stability".into(), self.genome.stability.to_report());
            report.insert(
                "capability_control".into(),
                self.capability_control_report(),
            );
            report.insert(
                "governance_ok".into(),
                serde_json::json!(governance_ok_x1(&self.genome)),
            );
            report.insert(
                "rollback_ok".into(),
                serde_json::json!(self.genome.deployment.rollback_ok()),
            );
            report.insert(
                "rollback_state_ready".into(),
                serde_json::json!(self.rollback_state.ready()),
            );
            report.insert("security_ok".into(), serde_json::json!(self.security.ok()));
            report.insert("data_ok".into(), serde_json::json!(self.data.ok()));
            report.insert(
                "objective_continuity_ok".into(),
                serde_json::json!(self.objective.ok()),
            );
            report.insert(
                "generalization_ok".into(),
                serde_json::json!(self.generalization.ok()),
            );
            report.insert(
                "long_horizon_ok".into(),
                serde_json::json!(self.long_horizon.ok()),
            );
            report.insert("rsi_ok".into(), serde_json::json!(self.rsi.ok()));
            report.insert("rsi_accept".into(), serde_json::json!(self.rsi_accept()));
            report.insert(
                "knowledge_admission".into(),
                self.knowledge_admission_report(),
            );
            report.insert(
                "archive_exploration_boost".into(),
                serde_json::json!(self.archive_diversity.exploration_boost()),
            );
            report.insert(
                "fitness_x1".into(),
                serde_json::json!(self.genome.fitness_x1),
            );
            report.insert(
                "version".into(),
                serde_json::json!(JARVIS_SETK_I2_X1_VERSION),
            );
            serde_json::Value::Object(report)
        }
    }

