    pub fn setk_i2_x1_recursive_self_improvement_report(
        case: &SetkI2X1EvaluationCase,
    ) -> serde_json::Value {
        let self_edit = case.candidate.target == SetkEditTarget::SelfModel;
        let mechanism_edit = case.candidate.target == SetkEditTarget::Mechanism;
        serde_json::json!({
            "target": case.candidate.target.as_str(),
            "self_edit": self_edit,
            "mechanism_edit": mechanism_edit,
            "long_horizon_required": case.candidate.target.requires_long_horizon(),
            "long_horizon_ok": case.long_horizon.ok(),
            "rsi_certificate_ok": case.rsi.ok(),
            "rsi_accept": case.rsi_accept(),
            "capability_control": case.capability_control_report(),
            "capability_may_increase": case.genome.stability.stability_ok(),
            "freeze_upgrade": !case.genome.stability.stability_ok(),
            "safe_rsi_theorem": self_edit || mechanism_edit,
        })
    }

    pub fn setk_i2_x1_end_to_end_loop_report(
        case: &SetkI2X1EvaluationCase,
        compile_report: &UnifiedProofReport,
    ) -> serde_json::Value {
        let proof_object = compile_proof_object_x1(compile_report);
        let decision = case.decision_report();
        let gate_matrix = case.gate_matrix_report();
        let sandbox_hash = stable_json_hash(&serde_json::json!({
            "candidate": case.candidate.to_report(),
            "compile_status": compile_report.compile_status,
            "mlir_bundle_hash": compile_report.mlir_bundle_hash,
            "proof_object": proof_object,
        }));
        let ledger_hash = stable_json_hash(&serde_json::json!({
            "sandbox_hash": sandbox_hash,
            "decision": decision,
            "gate_matrix": gate_matrix,
            "fitness_x1": case.genome.fitness_x1,
            "target_stage": case.target_stage.as_str(),
        }));
        serde_json::json!({
            "ok": case.accept(),
            "contract": setk_i2_x1_end_to_end_loop_contract_report(),
            "state_contract": setk_i2_x1_global_state_contract_report(),
            "candidate_generation": {
                "candidate": case.candidate.to_report(),
                "archive_diversity": &case.archive_diversity,
                "review_route": case.candidate.review_route().as_str(),
            },
            "sandbox": {
                "raw_state_trusted": false,
                "sandbox_hash": sandbox_hash,
                "compile_probe_ok": compile_report.ok,
                "compile_status": compile_report.compile_status,
            },
            "execution": {
                "program_len": compile_report.program.len(),
                "vm_word_size": 32,
                "proof_object": proof_object,
            },
            "proof_stack": case.proof.to_report(),
            "evaluation": {
                "quality": case.quality.to_report(
                    case.genome.risk,
                    case.genome.complexity,
                    case.genome.causal.expected_harm,
                    1.0 - case.quality.q_latency,
                ),
                "protected_eval_ok": case.protected_eval.ok(),
                "reality_anchor_score": case.reality_anchor.score(),
                "causal_credit": {
                    "ok": case.causal_credit.ok(),
                    "gain_delta": case.causal_credit.gain_delta(),
                    "utility_delta": case.causal_credit.utility_delta(),
                },
                "uncertainty": case.genome.uncertainty.to_report(),
                "benchmark": {
                    "coverage": case.genome.benchmark.coverage(),
                    "adversarial_gap": case.genome.benchmark.adversarial_gap(),
                    "ok": case.genome.benchmark.benchmark_ok(),
                },
                "meta_verification": &case.meta_verification,
            },
            "governance_stack": setk_i2_x1_governance_stack_report(case),
            "deployment_lattice": setk_i2_x1_deployment_lattice_report(case),
            "rollback_recovery": setk_i2_x1_rollback_recovery_report(case),
            "knowledge_admission": case.knowledge_admission_report(),
            "fitness": {
                "F_X1": case.genome.fitness_x1,
                "threshold": X1_THETA_F,
                "ok": case.genome.fitness_x1 >= X1_THETA_F,
            },
            "decision": decision,
            "acceptance_contract": setk_i2_x1_acceptance_contract_report(case),
            "recursive_self_improvement": setk_i2_x1_recursive_self_improvement_report(case),
            "ledger_hash": ledger_hash,
        })
    }

    pub fn setk_i2_x1_model_conformance_report(
        case: &SetkI2X1EvaluationCase,
        compile_report: &UnifiedProofReport,
    ) -> serde_json::Value {
        let section_report = setk_i2_x1_section_coverage_report();
        let state_report = setk_i2_x1_global_state_contract_report();
        let loop_report = setk_i2_x1_end_to_end_loop_report(case, compile_report);
        let acceptance = setk_i2_x1_acceptance_contract_report(case);
        serde_json::json!({
            "ok": section_report.get("ok").and_then(|v| v.as_bool()).unwrap_or(false)
                && state_report.get("ok").and_then(|v| v.as_bool()).unwrap_or(false)
                && case.proof.proof_channel_completeness()
                && loop_report.get("ok").and_then(|v| v.as_bool()).unwrap_or(false)
                && acceptance.get("ok").and_then(|v| v.as_bool()).unwrap_or(false),
            "section_coverage_ok": section_report.get("ok").and_then(|v| v.as_bool()).unwrap_or(false),
            "state_contract_ok": state_report.get("ok").and_then(|v| v.as_bool()).unwrap_or(false),
            "proof_channel_completeness": case.proof.channel_completeness_report(),
            "acceptance_contract": acceptance,
            "loop_ledger_hash": loop_report.get("ledger_hash").cloned().unwrap_or(serde_json::Value::Null),
            "final_overhaul_model": "A transformation is promotable only if it executes correctly, proves correctly, improves causally, survives uncertainty and benchmark tests, preserves objectives, satisfies governance, remains reversible, and increases capability no faster than control.",
        })
    }

