    pub fn build_setk_i2_x1_safety_case_report(
        framework: &JarvisProductionFramework,
    ) -> FrameworkResult<serde_json::Value> {
        let typed_spec = CompileSpec::new("math", "add", serde_json::json!({"a": 4, "b": 5}))?;
        let compile_report = framework.try_compile_spec(&typed_spec)?;
        let case = setk_i2_x1_reference_case(&compile_report);
        let decision = case.decision_report();
        let end_to_end_loop = setk_i2_x1_end_to_end_loop_report(&case, &compile_report);
        let model_conformance = setk_i2_x1_model_conformance_report(&case, &compile_report);
        let ok = decision
            .get("accept_x1")
            .and_then(|value| value.as_bool())
            .unwrap_or(false)
            && decision
                .get("promote")
                .and_then(|value| value.as_bool())
                .unwrap_or(false)
            && model_conformance
                .get("ok")
                .and_then(|value| value.as_bool())
                .unwrap_or(false);
        Ok(serde_json::json!({
            "ok": ok,
            "status": report_status(ok),
            "verdict": report_verdict(ok, "setk_i2_x1_reference_gate_pass", "setk_i2_x1_reference_gate_failed"),
            "schema_version": JARVIS_ARTIFACT_SCHEMA_VERSION,
            "command": "setk-i2-x1",
            "run_id": framework_hash_run_id("setk-i2-x1-"),
            "model_version": JARVIS_MODEL_VERSION,
            "setk_i2_x1_version": JARVIS_SETK_I2_X1_VERSION,
            "reference_model": build_setk_i2_x1_reference_model_report(),
            "section_coverage": setk_i2_x1_section_coverage_report(),
            "decision": decision,
            "model_conformance": model_conformance,
            "end_to_end_loop": end_to_end_loop,
            "global_machine": setk_i2_x1_global_machine_report(),
            "global_state_contract": setk_i2_x1_global_state_contract_report(),
            "governance_stack": setk_i2_x1_governance_stack_report(&case),
            "deployment_lattice": setk_i2_x1_deployment_lattice_report(&case),
            "rollback_recovery": setk_i2_x1_rollback_recovery_report(&case),
            "recursive_self_improvement": setk_i2_x1_recursive_self_improvement_report(&case),
            "acceptance_contract": setk_i2_x1_acceptance_contract_report(&case),
            "proof_object": compile_proof_object_x1(&compile_report),
            "compile_probe": {
                "ok": compile_report.ok,
                "status": compile_report.compile_status,
                "program_len": compile_report.program.len(),
                "vm_proof_ok": compile_report.vm_proof.as_ref().map(|proof| proof.ok).unwrap_or(false),
                "vm_proof_residual": compile_report.vm_proof.as_ref().map(|proof| proof.residual).unwrap_or(1.0),
                "mlir_bundle_hash": compile_report.mlir_bundle_hash,
            },
            "central_gate": "AcceptX1 iff no hard reject and compile/runtime/proof/governance/causal/causal-credit/uncertainty/benchmark/meta-verifier/stability/rollback/protected-eval/reality/security/data/objective/generalization/long-horizon/fitness gates pass.",
            "mutation_policy": {
                "autonomous_source_writes_allowed": false,
                "proposal_only_until_human_approved": true,
                "evaluator_edits_quarantined": true,
                "governance_edits_require_higher_order_approval": true,
                "rollback_required_for_promotion": true,
                "adjacent_deployment_only": true,
                "source_mutation_without_human_gate": false,
            },
            "next_commands": [
                "cargo check --bin llm-javis",
                "cargo run --bin llm-javis -- jarvis setk-i2-x1",
                "cargo run --bin llm-javis -- jarvis self-test"
            ],
        }))
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct UGCGeometricCoreEvidence {
        pub edit_loss: f64,
        pub laplacian_loss: f64,
        pub distance_loss: f64,
        pub curvature_loss: f64,
        pub equivariance_loss: f64,
        pub topology_loss: f64,
        pub chart_loss: f64,
        pub holonomy_loss: f64,
        pub harness_loss: f64,
        pub graph_nodes: usize,
        pub graph_edges: usize,
    }

    impl UGCGeometricCoreEvidence {
        pub fn total_loss(&self) -> f64 {
            self.edit_loss
                + self.laplacian_loss
                + self.distance_loss
                + self.curvature_loss
                + self.equivariance_loss
                + self.topology_loss
                + self.chart_loss
                + self.holonomy_loss
                + self.harness_loss
        }

        pub fn geometry_ok(&self) -> bool {
            self.total_loss() <= UGC_GEOMETRY_LOSS_MAX && self.edit_loss <= UGC_EDIT_EPSILON
        }

        pub fn chart_ok(&self) -> bool {
            self.chart_loss <= UGC_CHART_EPSILON
        }

        pub fn topology_ok(&self) -> bool {
            self.topology_loss <= UGC_TOPOLOGY_EPSILON && self.holonomy_loss <= UGC_TOPOLOGY_EPSILON
        }

        pub fn to_report(&self) -> serde_json::Value {
            serde_json::json!({
                "ok": self.geometry_ok() && self.chart_ok() && self.topology_ok(),
                "L_GEO": self.total_loss(),
                "threshold": UGC_GEOMETRY_LOSS_MAX,
                "graph": {
                    "nodes": self.graph_nodes,
                    "edges": self.graph_edges,
                    "laplacian_loss": self.laplacian_loss,
                },
                "loss_terms": {
                    "edit": self.edit_loss,
                    "distance": self.distance_loss,
                    "curvature": self.curvature_loss,
                    "equivariance": self.equivariance_loss,
                    "topology": self.topology_loss,
                    "chart": self.chart_loss,
                    "holonomy": self.holonomy_loss,
                    "harness": self.harness_loss,
                },
                "checks": {
                    "geometry_ok": self.geometry_ok(),
                    "chart_ok": self.chart_ok(),
                    "topology_ok": self.topology_ok(),
                },
            })
        }
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct UGCRuntimeIntelligenceEvidence {
        pub sampled_paths: usize,
        pub thinking_depth: usize,
        pub temperature: f64,
        pub top_p: f64,
        pub self_consistency_vote: f64,
        pub refinement_rounds: usize,
        pub refine_gain: f64,
        pub compute_cost: f64,
        pub compute_budget: f64,
    }

    impl UGCRuntimeIntelligenceEvidence {
        pub fn runtime_ok(&self) -> bool {
            self.sampled_paths > 0
                && self.thinking_depth > 0
                && self.self_consistency_vote >= UGC_RUNTIME_MIN_VOTE
                && self.refine_gain >= UGC_RUNTIME_MIN_REFINE_GAIN
                && self.compute_cost <= self.compute_budget
        }

        pub fn score(&self) -> f64 {
            (0.35 * self.self_consistency_vote
                + 0.25 * self.refine_gain.clamp(0.0, 1.0)
                + 0.20 * ((self.sampled_paths as f64) / 8.0).clamp(0.0, 1.0)
                + 0.20 * ((self.thinking_depth as f64) / 8.0).clamp(0.0, 1.0)
                - 0.10 * (self.compute_cost / self.compute_budget.max(1e-9)).clamp(0.0, 1.0))
            .clamp(0.0, 1.0)
        }

        pub fn to_report(&self) -> serde_json::Value {
            serde_json::json!({
                "ok": self.runtime_ok(),
                "score": self.score(),
                "sampled_paths": self.sampled_paths,
                "thinking_depth": self.thinking_depth,
                "temperature": self.temperature,
                "top_p": self.top_p,
                "self_consistency_vote": self.self_consistency_vote,
                "refinement_rounds": self.refinement_rounds,
                "refine_gain": self.refine_gain,
                "compute": {
                    "cost": self.compute_cost,
                    "budget": self.compute_budget,
                    "within_budget": self.compute_cost <= self.compute_budget,
                },
            })
        }
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct UGCHarnessEvidence {
        pub code_reasoning: bool,
        pub code_acting: bool,
        pub code_environment: bool,
        pub tool_schema_ok: bool,
        pub permission_ok: bool,
        pub policy_ok: bool,
        pub sandbox_ok: bool,
        pub output_sanitized: bool,
        pub telemetry_ok: bool,
        pub feedback_ok: bool,
        pub update_loss: f64,
        pub tool_risk: f64,
    }

    impl UGCHarnessEvidence {
        pub fn tool_ok(&self) -> bool {
            self.tool_schema_ok
                && self.permission_ok
                && self.policy_ok
                && self.sandbox_ok
                && self.output_sanitized
                && self.tool_risk <= UGC_TOOL_RISK_MAX
        }

        pub fn harness_ok(&self) -> bool {
            self.code_reasoning
                && self.code_acting
                && self.code_environment
                && self.tool_ok()
                && self.telemetry_ok
                && self.feedback_ok
                && self.update_loss <= UGC_HARNESS_LOSS_MAX
        }

        pub fn score(&self) -> f64 {
            let checks = [
                self.code_reasoning,
                self.code_acting,
                self.code_environment,
                self.tool_schema_ok,
                self.permission_ok,
                self.policy_ok,
                self.sandbox_ok,
                self.output_sanitized,
                self.telemetry_ok,
                self.feedback_ok,
            ];
            checks.iter().filter(|ok| **ok).count() as f64 / checks.len() as f64
        }

        pub fn to_report(&self) -> serde_json::Value {
            serde_json::json!({
                "ok": self.harness_ok(),
                "score": self.score(),
                "interfaces": {
                    "code_reasoning": self.code_reasoning,
                    "code_acting": self.code_acting,
                    "code_environment": self.code_environment,
                },
                "tool_lifecycle": {
                    "tool_ok": self.tool_ok(),
                    "schema_ok": self.tool_schema_ok,
                    "permission_ok": self.permission_ok,
                    "policy_ok": self.policy_ok,
                    "sandbox_ok": self.sandbox_ok,
                    "output_sanitized": self.output_sanitized,
                    "tool_risk": self.tool_risk,
                    "tool_risk_max": UGC_TOOL_RISK_MAX,
                },
                "update_loss": self.update_loss,
                "update_loss_max": UGC_HARNESS_LOSS_MAX,
                "telemetry_ok": self.telemetry_ok,
                "feedback_ok": self.feedback_ok,
            })
        }
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct UGCRollbackPathEvidence {
        pub reversible: bool,
        pub snapshot_ok: bool,
        pub restore_ok: bool,
        pub lineage_ok: bool,
        pub rollback_tested: bool,
        pub path_cost: f64,
        pub blast_radius: f64,
    }

    impl UGCRollbackPathEvidence {
        pub fn rollback_path_ok(&self) -> bool {
            self.reversible
                && self.snapshot_ok
                && self.restore_ok
                && self.lineage_ok
                && self.rollback_tested
                && self.path_cost + self.blast_radius <= UGC_ROLLBACK_PATH_COST_MAX
        }

        pub fn to_report(&self) -> serde_json::Value {
            serde_json::json!({
                "ok": self.rollback_path_ok(),
                "reversible": self.reversible,
                "snapshot_ok": self.snapshot_ok,
                "restore_ok": self.restore_ok,
                "lineage_ok": self.lineage_ok,
                "rollback_tested": self.rollback_tested,
                "path_cost": self.path_cost,
                "blast_radius": self.blast_radius,
                "total_cost": self.path_cost + self.blast_radius,
                "max_cost": UGC_ROLLBACK_PATH_COST_MAX,
            })
        }
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct UGCProvenanceEvidence {
        pub source_hash: String,
        pub compile_hash: String,
        pub trace_hash: String,
        pub evidence_hash: String,
        pub source_tests: usize,
        pub compile_passes: usize,
        pub vm_program_len: usize,
        pub witness_rows: usize,
        pub geometry_derived_from_compile: bool,
        pub runtime_derived_from_candidates: bool,
        pub harness_derived_from_artifacts: bool,
        pub reference_only: bool,
    }

    impl UGCProvenanceEvidence {
        pub fn ok(&self) -> bool {
            !self.source_hash.is_empty()
                && !self.compile_hash.is_empty()
                && !self.trace_hash.is_empty()
                && !self.evidence_hash.is_empty()
                && self.source_tests >= UGC_PROVENANCE_MIN_SOURCE_TESTS
                && self.compile_passes > 0
                && self.vm_program_len > 0
                && self.witness_rows > 0
                && self.geometry_derived_from_compile
                && self.runtime_derived_from_candidates
                && self.harness_derived_from_artifacts
                && !self.reference_only
        }

        pub fn to_report(&self) -> serde_json::Value {
            serde_json::json!({
                "ok": self.ok(),
                "source_hash": self.source_hash,
                "compile_hash": self.compile_hash,
                "trace_hash": self.trace_hash,
                "evidence_hash": self.evidence_hash,
                "source_tests": self.source_tests,
                "source_tests_min": UGC_PROVENANCE_MIN_SOURCE_TESTS,
                "compile_passes": self.compile_passes,
                "vm_program_len": self.vm_program_len,
                "witness_rows": self.witness_rows,
                "derived": {
                    "geometry_from_compile": self.geometry_derived_from_compile,
                    "runtime_from_candidates": self.runtime_derived_from_candidates,
                    "harness_from_artifacts": self.harness_derived_from_artifacts,
                    "reference_only": self.reference_only,
                },
            })
        }
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct UGCQualityVector {
        pub q_perf: f64,
        pub q_truth: f64,
        pub q_safety: f64,
        pub q_security: f64,
        pub q_robust: f64,
        pub q_govern: f64,
        pub q_cost: f64,
        pub q_latency: f64,
        pub q_novelty: f64,
        pub q_reversible: f64,
        pub q_identity: f64,
        pub q_agreement: f64,
        pub q_learning: f64,
        pub q_geometry: f64,
        pub q_chart: f64,
        pub q_topology: f64,
        pub q_harness: f64,
        pub q_runtime: f64,
        pub q_proof: f64,
        pub q_causal: f64,
        pub q_deployment: f64,
    }

    impl UGCQualityVector {
        pub fn from_case(
            case: &SetkI2X1EvaluationCase,
            geometry: &UGCGeometricCoreEvidence,
            harness: &UGCHarnessEvidence,
            runtime: &UGCRuntimeIntelligenceEvidence,
        ) -> Self {
            Self {
                q_perf: case.quality.q_perf,
                q_truth: case.quality.q_truth,
                q_safety: case.quality.q_safety,
                q_security: case.quality.q_security,
                q_robust: case.quality.q_robust,
                q_govern: case.quality.q_govern,
                q_cost: case.quality.q_cost,
                q_latency: case.quality.q_latency,
                q_novelty: case.quality.q_novelty,
                q_reversible: case.quality.q_reversible,
                q_identity: case.quality.q_identity,
                q_agreement: case.quality.q_agreement,
                q_learning: case.quality.q_learning,
                q_geometry: if geometry.geometry_ok() { 0.94 } else { 0.0 },
                q_chart: if geometry.chart_ok() { 0.92 } else { 0.0 },
                q_topology: if geometry.topology_ok() { 0.90 } else { 0.0 },
                q_harness: harness.score(),
                q_runtime: runtime.score(),
                q_proof: if case.proof.proof_ok_x1() { 0.95 } else { 0.0 },
                q_causal: if case.genome.causal.causal_ok() {
                    0.90
                } else {
                    0.0
                },
                q_deployment: if case.promote() { 0.90 } else { 0.50 },
            }
        }

        pub fn components(&self) -> [f64; 21] {
            [
                self.q_perf,
                self.q_truth,
                self.q_safety,
                self.q_security,
                self.q_robust,
                self.q_govern,
                self.q_cost,
                self.q_latency,
                self.q_novelty,
                self.q_reversible,
                self.q_identity,
                self.q_agreement,
                self.q_learning,
                self.q_geometry,
                self.q_chart,
                self.q_topology,
                self.q_harness,
                self.q_runtime,
                self.q_proof,
                self.q_causal,
                self.q_deployment,
            ]
        }

        pub fn score(&self) -> f64 {
            self.components()
                .iter()
                .map(|v| v.clamp(0.0, 1.0))
                .sum::<f64>()
                / self.components().len() as f64
        }

        pub fn to_report(&self) -> serde_json::Value {
            serde_json::json!({
                "weighted_quality": self.score(),
                "components": {
                    "performance": self.q_perf,
                    "truth": self.q_truth,
                    "safety": self.q_safety,
                    "security": self.q_security,
                    "robust": self.q_robust,
                    "governance": self.q_govern,
                    "cost": self.q_cost,
                    "latency": self.q_latency,
                    "novelty": self.q_novelty,
                    "reversible": self.q_reversible,
                    "identity": self.q_identity,
                    "agreement": self.q_agreement,
                    "learning": self.q_learning,
                    "geometry": self.q_geometry,
                    "chart": self.q_chart,
                    "topology": self.q_topology,
                    "harness": self.q_harness,
                    "runtime": self.q_runtime,
                    "proof": self.q_proof,
                    "causal": self.q_causal,
                    "deployment": self.q_deployment,
                },
            })
        }
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct UGCContractSection {
        pub name: String,
        pub score: f64,
        pub residual: f64,
        pub ok: bool,
        pub evidence: serde_json::Value,
    }

    #[derive(Debug, Clone, Serialize, Deserialize)]
    pub struct UGCEvaluationCase {
        pub x1: SetkI2X1EvaluationCase,
        pub geometry: UGCGeometricCoreEvidence,
        pub runtime: UGCRuntimeIntelligenceEvidence,
        pub harness: UGCHarnessEvidence,
        pub rollback_path: UGCRollbackPathEvidence,
        pub provenance: UGCProvenanceEvidence,
        pub quality: UGCQualityVector,
        pub air_residual: f64,
        pub proof_residual: f64,
        pub objective_drift: f64,
    }

    impl UGCEvaluationCase {
        pub fn ugc_ok(&self) -> bool {
            self.geometry.geometry_ok()
                && self.geometry.chart_ok()
                && self.geometry.topology_ok()
                && self.harness.harness_ok()
                && self.runtime.runtime_ok()
                && self.rollback_path.rollback_path_ok()
                && self.provenance.ok()
        }

        pub fn proof_ok(&self) -> bool {
            self.air_residual <= UGC_AIR_RESIDUAL_MAX
                && self.proof_residual <= X1_EPSILON_PROOF
                && self.x1.proof.proof_ok_x1()
        }

        pub fn fitness_ugc(&self) -> f64 {
            let positive = self.quality.score()
                + 0.10 * self.runtime.score()
                + 0.10 * (1.0 - self.geometry.total_loss()).clamp(0.0, 1.0)
                + 0.10 * if self.proof_ok() { 1.0 } else { 0.0 }
                + 0.05 * self.harness.score();
            let penalty = self.geometry.total_loss()
                + self.x1.genome.causal.expected_harm
                + self.x1.genome.uncertainty.sigma
                + self.x1.genome.uncertainty.ood
                + self.x1.genome.risk
                + self.objective_drift
                + self.runtime.compute_cost / self.runtime.compute_budget.max(1e-9) * 0.05
                + self.proof_residual * 1000.0;
            (positive - penalty).clamp(-1.0, 2.0)
        }

        pub fn fitness_ok(&self) -> bool {
            self.fitness_ugc() >= X1_THETA_F
        }

        pub fn gate_matrix(&self) -> Vec<GateEvidenceX1> {
            let mut gates = self.x1.gate_matrix();
            gates.extend([
            GateEvidenceX1::new(
                "air_residual_not_ok",
                self.air_residual <= UGC_AIR_RESIDUAL_MAX,
                true,
                "rho_AIR<1e-6",
                serde_json::json!(self.air_residual),
                "reject",
            ),
            GateEvidenceX1::new(
                "geometry_not_ok",
                self.geometry.geometry_ok(),
                false,
                "L_GEO<=0.25 and L_edit<=0.05",
                self.geometry.to_report(),
                "archive_or_refine",
            ),
            GateEvidenceX1::new(
                "chart_not_ok",
                self.geometry.chart_ok(),
                false,
                "rho_chart<=0.05",
                serde_json::json!({"chart_loss": self.geometry.chart_loss}),
                "refine_chart_alignment",
            ),
            GateEvidenceX1::new(
                "topology_not_ok",
                self.geometry.topology_ok(),
                false,
                "topology and holonomy residuals<=0.05",
                serde_json::json!({
                    "topology_loss": self.geometry.topology_loss,
                    "holonomy_loss": self.geometry.holonomy_loss,
                }),
                "refine_topology",
            ),
            GateEvidenceX1::new(
                "harness_not_ok",
                self.harness.harness_ok(),
                false,
                "code reasoning/acting/environment, tool lifecycle, telemetry, feedback",
                self.harness.to_report(),
                "quarantine_tool_or_code_path",
            ),
            GateEvidenceX1::new(
                "runtime_think_not_ok",
                self.runtime.runtime_ok(),
                false,
                "N,T>0, vote>=0.60, refine_gain>=0.01, compute within budget",
                self.runtime.to_report(),
                "sample_or_refine_more",
            ),
            GateEvidenceX1::new(
                "rollback_path_not_ok",
                self.rollback_path.rollback_path_ok(),
                true,
                "reversible path with snapshots, restore, lineage, tests, cost<=0.50",
                self.rollback_path.to_report(),
                "rollback",
            ),
            GateEvidenceX1::new(
                "evidence_derivation_not_ok",
                self.provenance.ok(),
                true,
                "UGC evidence must be derived from source hash, compile hash, VM trace, tests, and non-reference candidate evidence",
                self.provenance.to_report(),
                "reject_reference_only_report",
            ),
            GateEvidenceX1::new(
                "fitness_ugc_below_0_50",
                self.fitness_ok(),
                false,
                "F_UGC>=0.50",
                serde_json::json!(self.fitness_ugc()),
                "archive_or_reject",
            ),
        ]);
            gates
        }

        pub fn accept_ugc(&self) -> bool {
            self.gate_matrix().iter().all(|gate| gate.ok)
                && self.x1.accept()
                && self.proof_ok()
                && self.ugc_ok()
                && self.objective_drift <= SETK_OBJECTIVE_DRIFT_EPSILON
                && self.fitness_ok()
        }

        pub fn gate_matrix_report(&self) -> serde_json::Value {
            let gates = self.gate_matrix();
            let failed = gates.iter().filter(|gate| !gate.ok).count();
            let hard_failed = gates.iter().filter(|gate| !gate.ok && gate.hard).count();
            serde_json::json!({
                "ok": failed == 0,
                "gate_count": gates.len(),
                "x1_gate_count": self.x1.gate_matrix().len(),
                "ugc_extension_gate_count": UGC_CONTRACT_EXTENSION_COUNT,
                "failed_count": failed,
                "hard_failed_count": hard_failed,
                "gates": gates,
            })
        }

        pub fn contract_extension(&self) -> Vec<UGCContractSection> {
            vec![
                UGCContractSection {
                    name: "xi_geo".into(),
                    score: (1.0 - self.geometry.total_loss()).clamp(0.0, 1.0),
                    residual: self.geometry.total_loss(),
                    ok: self.geometry.geometry_ok(),
                    evidence: self.geometry.to_report(),
                },
                UGCContractSection {
                    name: "xi_chart".into(),
                    score: (1.0 - self.geometry.chart_loss).clamp(0.0, 1.0),
                    residual: self.geometry.chart_loss,
                    ok: self.geometry.chart_ok(),
                    evidence: serde_json::json!({"chart_loss": self.geometry.chart_loss}),
                },
                UGCContractSection {
                    name: "xi_topo".into(),
                    score: (1.0 - self.geometry.topology_loss - self.geometry.holonomy_loss)
                        .clamp(0.0, 1.0),
                    residual: self.geometry.topology_loss + self.geometry.holonomy_loss,
                    ok: self.geometry.topology_ok(),
                    evidence: serde_json::json!({
                        "topology_loss": self.geometry.topology_loss,
                        "holonomy_loss": self.geometry.holonomy_loss,
                    }),
                },
                UGCContractSection {
                    name: "xi_harness".into(),
                    score: self.harness.score(),
                    residual: self.harness.update_loss,
                    ok: self.harness.harness_ok(),
                    evidence: self.harness.to_report(),
                },
                UGCContractSection {
                    name: "xi_runtime".into(),
                    score: self.runtime.score(),
                    residual: 1.0 - self.runtime.score(),
                    ok: self.runtime.runtime_ok(),
                    evidence: self.runtime.to_report(),
                },
                UGCContractSection {
                    name: "xi_tool".into(),
                    score: if self.harness.tool_ok() { 1.0 } else { 0.0 },
                    residual: self.harness.tool_risk,
                    ok: self.harness.tool_ok(),
                    evidence: self.harness.to_report(),
                },
                UGCContractSection {
                    name: "xi_rollback_path".into(),
                    score: (1.0 - self.rollback_path.path_cost - self.rollback_path.blast_radius)
                        .clamp(0.0, 1.0),
                    residual: self.rollback_path.path_cost + self.rollback_path.blast_radius,
                    ok: self.rollback_path.rollback_path_ok(),
                    evidence: self.rollback_path.to_report(),
                },
                UGCContractSection {
                    name: "xi_provenance".into(),
                    score: if self.provenance.ok() { 1.0 } else { 0.0 },
                    residual: if self.provenance.ok() { 0.0 } else { 1.0 },
                    ok: self.provenance.ok(),
                    evidence: self.provenance.to_report(),
                },
                UGCContractSection {
                    name: "xi_accept_ugc".into(),
                    score: if self.accept_ugc() { 1.0 } else { 0.0 },
                    residual: 1.0 - self.fitness_ugc().clamp(0.0, 1.0),
                    ok: self.accept_ugc(),
                    evidence: serde_json::json!({
                        "accept_ugc": self.accept_ugc(),
                        "F_UGC": self.fitness_ugc(),
                    }),
                },
            ]
        }
    }

    fn ugc_source_test_count(path: &str) -> usize {
        let inventory = framework_source_test_inventory(path, "jarvis");
        inventory
            .get("tests")
            .and_then(|value| value.as_array())
            .map(|tests| tests.len())
            .or_else(|| {
                inventory
                    .get("test_count")
                    .and_then(|value| value.as_u64())
                    .map(|value| value as usize)
            })
            .unwrap_or(0)
    }

    fn ugc_scaled_loss(raw: f64, scale: f64, floor: f64, span: f64) -> f64 {
        (floor + span * (raw / (raw + scale.max(1e-9)))).clamp(0.0, floor + span)
    }

    pub fn ugc_reference_case(compile_report: &UnifiedProofReport) -> UGCEvaluationCase {
        let x1 = setk_i2_x1_reference_case(compile_report);
        let vm_residual = compile_report
            .vm_proof
            .as_ref()
            .map(|proof| proof.residual)
            .unwrap_or(1.0);
        let witness_rows = compile_report
            .vm_proof
            .as_ref()
            .map(|proof| proof.witness_rows)
            .unwrap_or(0);
        let trace_hash = compile_report
            .vm_proof
            .as_ref()
            .map(|proof| proof.trace_hash.clone())
            .unwrap_or_default();
        let combined_source = Path::new(env!("CARGO_MANIFEST_DIR")).join("llm-javis.rs");
        let source_path = if combined_source.is_file() {
            combined_source
        } else {
            Path::new(env!("CARGO_MANIFEST_DIR")).join("jarvis_rust_0.rs")
        };
        let source_hash = framework_file_sha256(&source_path).unwrap_or_default();
        let source_tests = ugc_source_test_count(&source_path.display().to_string());
        let compile_hash = if compile_report.mlir_bundle_hash.is_empty() {
            stable_json_hash(&serde_json::json!({
                "compile_status": compile_report.compile_status,
                "program": compile_report.program,
                "pass_log": compile_report.pass_log,
            }))
        } else {
            compile_report.mlir_bundle_hash.clone()
        };
        let diagnostics = compile_report.diagnostics.len() as f64;
        let pass_count = compile_report.pass_log.len();
        let program_len = compile_report.program.len();
        let graph_nodes = SETK_GLOBAL_STATE_SLOTS_X1.len()
            + SETK_GLOBAL_MACHINE_COMPONENTS_X1.len()
            + compile_report.program.len()
            + compile_report.pass_log.len()
            + 3;
        let graph_edges = graph_nodes
            + compile_report.lowering_snapshots.len()
            + compile_report
                .proof_ir
                .as_ref()
                .map(|proof| proof.obligations.len())
                .unwrap_or(0)
            + compile_report
                .memory_ir
                .as_ref()
                .map(|memory| memory.reads.len() + memory.writes.len())
                .unwrap_or(0);
        let geometry = UGCGeometricCoreEvidence {
            edit_loss: ugc_scaled_loss(diagnostics + vm_residual * 1_000_000.0, 12.0, 0.004, 0.035),
            laplacian_loss: ugc_scaled_loss(graph_edges as f64, 256.0, 0.006, 0.030),
            distance_loss: ugc_scaled_loss(
                (graph_nodes.saturating_sub(graph_edges)) as f64,
                128.0,
                0.005,
                0.025,
            ),
            curvature_loss: ugc_scaled_loss(
                compile_report.lowering_snapshots.len() as f64,
                32.0,
                0.004,
                0.025,
            ),
            equivariance_loss: ugc_scaled_loss(
                compile_report.plugin_outputs.len() as f64,
                16.0,
                0.004,
                0.020,
            ),
            topology_loss: ugc_scaled_loss(source_tests as f64, 128.0, 0.005, 0.020),
            chart_loss: ugc_scaled_loss(pass_count as f64, 128.0, 0.004, 0.025),
            holonomy_loss: ugc_scaled_loss(witness_rows as f64, 512.0, 0.004, 0.022),
            harness_loss: ugc_scaled_loss(
                compile_report.manifest.len() as f64,
                128.0,
                0.004,
                0.020,
            ),
            graph_nodes,
            graph_edges,
        };
        let sampled_paths =
            (compile_report.pass_log.len() + compile_report.lowering_snapshots.len()).clamp(1, 16);
        let thinking_depth = (compile_report.program.len() + witness_rows).clamp(1, 32);
        let failed_diagnostics = compile_report
            .diagnostics
            .iter()
            .filter(|diag| diag.level.eq_ignore_ascii_case("error"))
            .count();
        let self_consistency_vote = if compile_report.ok {
            1.0 - ((failed_diagnostics as f64) / ((compile_report.diagnostics.len() + 1) as f64))
        } else {
            0.0
        }
        .clamp(0.0, 1.0);
        let refine_gain = ((pass_count as f64)
            / ((pass_count + compile_report.diagnostics.len() + 1) as f64))
            .clamp(0.0, 1.0);
        let runtime = UGCRuntimeIntelligenceEvidence {
            sampled_paths,
            thinking_depth,
            temperature: (0.20 + x1.genome.uncertainty.sigma).clamp(0.05, 1.0),
            top_p: (1.0 - x1.genome.uncertainty.ood).clamp(0.50, 0.99),
            self_consistency_vote,
            refinement_rounds: compile_report.lowering_snapshots.len().max(1),
            refine_gain,
            compute_cost: ((program_len + witness_rows + pass_count) as f64 / 256.0)
                .clamp(0.01, 1.0),
            compute_budget: 1.0,
        };
        let source_artifacts = jarvis_source_artifact_report();
        let source_artifacts_exist = framework_source_artifacts_exist(&source_artifacts);
        let proof_obligations = compile_report
            .proof_ir
            .as_ref()
            .map(|proof| proof.obligations.len())
            .unwrap_or(0);
        let harness = UGCHarnessEvidence {
            code_reasoning: compile_report.domain_ir.is_some(),
            code_acting: !compile_report.program.is_empty(),
            code_environment: source_artifacts_exist,
            tool_schema_ok: compile_report.skill_package.is_some(),
            permission_ok: compile_report
                .skill_package
                .as_ref()
                .map(|skill| !skill.permissions.is_empty())
                .unwrap_or(false),
            policy_ok: x1.genome.governance_quality.policy_ok(),
            sandbox_ok: compile_report.ok
                && compile_report
                    .vm_proof
                    .as_ref()
                    .map(|proof| proof.ok)
                    .unwrap_or(false),
            output_sanitized: compile_report.diagnostics.iter().all(|diag| {
                !diag.message.to_ascii_lowercase().contains("secret")
                    && !diag.message.to_ascii_lowercase().contains("token")
            }),
            telemetry_ok: !compile_report.pass_log.is_empty(),
            feedback_ok: proof_obligations > 0,
            update_loss: ugc_scaled_loss(
                compile_report.diagnostics.len() as f64,
                32.0,
                0.004,
                0.030,
            ),
            tool_risk: x1.genome.risk.max(x1.genome.causal.expected_harm),
        };
        let rollback_path = UGCRollbackPathEvidence {
            reversible: x1.genome.deployment.reversible,
            snapshot_ok: x1.rollback_state.snapshots > 0,
            restore_ok: x1.rollback_state.recovery_plans > 0,
            lineage_ok: true,
            rollback_tested: x1.genome.deployment.rollback_tested,
            path_cost: x1.genome.deployment.rollback_cost,
            blast_radius: x1.genome.deployment.blast_radius,
        };
        let evidence_hash = stable_json_hash(&serde_json::json!({
            "source_hash": source_hash,
            "compile_hash": compile_hash,
            "trace_hash": trace_hash,
            "geometry": geometry,
            "runtime": runtime,
            "harness": harness,
            "rollback_path": rollback_path,
        }));
        let provenance = UGCProvenanceEvidence {
            source_hash,
            compile_hash,
            trace_hash,
            evidence_hash,
            source_tests,
            compile_passes: pass_count,
            vm_program_len: program_len,
            witness_rows,
            geometry_derived_from_compile: graph_nodes > SETK_GLOBAL_STATE_SLOTS_X1.len()
                && graph_edges >= graph_nodes,
            runtime_derived_from_candidates: sampled_paths > 1
                && self_consistency_vote >= UGC_RUNTIME_MIN_VOTE,
            harness_derived_from_artifacts: source_artifacts_exist
                && compile_report.skill_package.is_some(),
            reference_only: false,
        };
        let quality = UGCQualityVector::from_case(&x1, &geometry, &harness, &runtime);
        UGCEvaluationCase {
            x1,
            geometry,
            runtime,
            harness,
            rollback_path,
            provenance,
            quality,
            air_residual: vm_residual,
            proof_residual: vm_residual,
            objective_drift: 0.01,
        }
    }

