    pub fn ugc_end_to_end_pipeline_report(
        case: &UGCEvaluationCase,
        compile_report: &UnifiedProofReport,
    ) -> serde_json::Value {
        let gate_matrix = case.gate_matrix_report();
        let proof_object = compile_proof_object_x1(compile_report);
        let pipeline_hash = stable_json_hash(&serde_json::json!({
            "ugc_version": JARVIS_UGC_VERSION,
            "candidate": case.x1.candidate.to_report(),
            "geometry": case.geometry.to_report(),
            "runtime": case.runtime.to_report(),
            "harness": case.harness.to_report(),
            "proof": proof_object,
            "gates": gate_matrix,
            "F_UGC": case.fitness_ugc(),
        }));
        serde_json::json!({
            "ok": case.accept_ugc(),
            "steps": [
                "Observe",
                "HarnessEncode",
                "GeometricEncode",
                "RuntimeSearch",
                "GeometricEdit",
                "ToolCodeHarness",
                "Sandbox",
                "Compile",
                "VM",
                "AIR",
                "Proof",
                "Eval",
                "Fitness",
                "AcceptUGC",
                "PromoteArchiveRollbackEscalateReject"
            ],
            "candidate": case.x1.candidate.to_report(),
            "compile_probe": {
                "ok": compile_report.ok,
                "status": compile_report.compile_status,
                "program_len": compile_report.program.len(),
                "vm_proof_ok": compile_report.vm_proof.as_ref().map(|proof| proof.ok).unwrap_or(false),
                "vm_proof_residual": compile_report.vm_proof.as_ref().map(|proof| proof.residual).unwrap_or(1.0),
            },
            "geometry": case.geometry.to_report(),
            "runtime": case.runtime.to_report(),
            "harness": case.harness.to_report(),
            "rollback_path": case.rollback_path.to_report(),
            "provenance": case.provenance.to_report(),
            "quality": case.quality.to_report(),
            "proof": {
                "air_residual": case.air_residual,
                "proof_residual": case.proof_residual,
                "proof_ok": case.proof_ok(),
                "proof_object": proof_object,
            },
            "x1": {
                "accept_x1": case.x1.accept(),
                "decision": case.x1.decision_report(),
                "gate_matrix": case.x1.gate_matrix_report(),
            },
            "F_UGC": case.fitness_ugc(),
            "accept_ugc": case.accept_ugc(),
            "gate_matrix": gate_matrix,
            "pipeline_hash": pipeline_hash,
        })
    }

    pub fn ugc_acceptance_contract_report(case: &UGCEvaluationCase) -> serde_json::Value {
        serde_json::json!({
            "ok": case.accept_ugc(),
            "accept_x1": case.x1.accept(),
            "proof_ok": case.proof_ok(),
            "causal_ok": case.x1.genome.causal.causal_ok(),
            "uncertainty_ok": case.x1.genome.uncertainty.uncertainty_ok(),
            "benchmark_ok": case.x1.genome.benchmark.benchmark_ok(),
            "verifier_ok": case.x1.meta_verification.verifier_accept(),
            "stability_ok": case.x1.genome.stability.stability_ok(),
            "governance_ok": governance_ok_x1(&case.x1.genome),
            "rollback_ok": case.x1.genome.deployment.rollback_ok() && case.x1.rollback_state.ready(),
            "knowledge_ok": case.x1.knowledge_admission_report().get("claim").and_then(|v| v.get("admitted")).and_then(|v| v.as_bool()).unwrap_or(false),
            "tool_ok": case.harness.tool_ok(),
            "harness_ok": case.harness.harness_ok(),
            "runtime_ok_think": case.runtime.runtime_ok(),
            "ugc_ok": case.ugc_ok(),
            "provenance_ok": case.provenance.ok(),
            "geometry_ok": case.geometry.geometry_ok(),
            "chart_ok": case.geometry.chart_ok(),
            "topology_ok": case.geometry.topology_ok(),
            "security_ok": case.x1.security.ok(),
            "capability_ok": case.x1.genome.stability.stability_ok(),
            "F_UGC": case.fitness_ugc(),
            "fitness_ok": case.fitness_ok(),
        })
    }

    pub fn build_ugc_safety_case_report(
        framework: &JarvisProductionFramework,
    ) -> FrameworkResult<serde_json::Value> {
        let typed_spec = CompileSpec::new("math", "add", serde_json::json!({"a": 4, "b": 5}))?;
        let compile_report = framework.try_compile_spec(&typed_spec)?;
        let case = ugc_reference_case(&compile_report);
        let end_to_end_pipeline = ugc_end_to_end_pipeline_report(&case, &compile_report);
        let acceptance = ugc_acceptance_contract_report(&case);
        let contract_extension = case.contract_extension();
        let contract_extension_ok = contract_extension.iter().all(|section| section.ok);
        let ok = case.accept_ugc()
            && acceptance
                .get("ok")
                .and_then(|value| value.as_bool())
                .unwrap_or(false)
            && contract_extension_ok;
        Ok(serde_json::json!({
            "ok": ok,
            "status": report_status(ok),
            "verdict": report_verdict(ok, "ugc_reference_gate_pass", "ugc_reference_gate_failed"),
            "schema_version": JARVIS_ARTIFACT_SCHEMA_VERSION,
            "command": "ugc",
            "run_id": framework_hash_run_id("ugc-"),
            "model_version": JARVIS_MODEL_VERSION,
            "ugc_version": JARVIS_UGC_VERSION,
            "setk_i2_x1_version": JARVIS_SETK_I2_X1_VERSION,
            "reference_model": build_ugc_reference_model_report(),
            "x1_reference_model": build_setk_i2_x1_reference_model_report(),
            "contract_extension": {
                "ok": contract_extension_ok,
                "x1_section_count": SETK_I2_X1_SECTION_COUNT,
                "ugc_extension_count": contract_extension.len(),
                "sections": contract_extension,
            },
            "acceptance_contract": acceptance,
            "end_to_end_pipeline": end_to_end_pipeline,
            "geometric_core": case.geometry.to_report(),
            "runtime_intelligence": case.runtime.to_report(),
            "code_as_agent_harness": case.harness.to_report(),
            "rollback_path": case.rollback_path.to_report(),
            "evidence_provenance": case.provenance.to_report(),
            "quality": case.quality.to_report(),
            "fitness": {
                "F_UGC": case.fitness_ugc(),
                "threshold": X1_THETA_F,
                "ok": case.fitness_ok(),
            },
            "single_master_equation": {
                "select": "argmax_i Score(e_i) subject to Accept_UGC(e_i)=1",
                "score_terms": [
                    "log p_theta(e_i|x_t,GEO_t,HAR_t)",
                    "F_UGC",
                    "GeoScore",
                    "ProofScore",
                    "HarnessScore",
                    "RuntimeScore",
                    "Vote",
                    "RefineGain",
                    "-rho_AIR",
                    "-rho_proof",
                    "-rho_chart",
                    "-Risk",
                    "-OOD",
                    "-OD",
                    "-ComputeCost"
                ],
            },
            "central_gate": "Accept_UGC iff X1 gates plus AIR/proof/geometric/chart/topology/harness/runtime/tool/rollback-path/fitness gates pass.",
            "next_commands": [
                "cargo check --bin llm-javis",
                "cargo run --bin llm-javis -- jarvis ugc",
                "cargo test --bin llm-javis ugc"
            ],
        }))
    }

