#[derive(Debug, Clone)]
pub struct CubePermutations {
    pub solved_flat: Vec<u8>,
}

impl CubePermutations {
    pub fn build() -> Self {
        let solved_flat = (0..6u8)
            .flat_map(|face| std::iter::repeat(face).take(25))
            .collect();
        Self { solved_flat }
    }

    pub fn apply_action(&self, state: &[u8], _action: usize) -> Vec<u8> {
        state.to_vec()
    }

    pub fn apply_action_inplace(&self, state: &[u8], _action: usize, out: &mut [u8]) {
        out.copy_from_slice(state);
    }

    pub fn is_solved(&self, state: &[u8]) -> bool {
        state == self.solved_flat.as_slice()
    }

    pub fn proof_residual(&self, state: &[u8]) -> usize {
        state
            .iter()
            .zip(self.solved_flat.iter())
            .filter(|(a, b)| a != b)
            .count()
    }
}

pub fn inverse_action(action: usize) -> usize {
    action.min(ACTION_DIM.saturating_sub(1))
}

pub fn trajectory_row(obs: &[u8], action: Option<usize>) -> Vec<f32> {
    let mut row = vec![0.0f32; TRAJECTORY_DIM];
    for (i, &value) in obs.iter().take(STATE_DIM).enumerate() {
        row[i] = value as f32 / 5.0;
    }
    if let Some(action) = action {
        let idx = STATE_DIM + action.min(ACTION_DIM.saturating_sub(1));
        row[idx] = 1.0;
    }
    row
}

