fn preset_spec(preset: &str, smoke: bool) -> LlmModelSpec {
    if smoke || preset == "smoke" {
        return LlmModelSpec::sized(8, 2, 32, 8, 8, 4, 2, 1, 4, 1, 0, 1, 4);
    }
    match preset {
        "production" => LlmModelSpec::default(),
        "base" => LlmModelSpec::sized(32, 4, 128, 32, 16, 16, 4, 2, 64, 50, 30, 10, 32),
        "small" => LlmModelSpec::sized(32, 3, 96, 24, 16, 8, 2, 1, 32, 20, 10, 10, 32),
        "tiny" => LlmModelSpec::sized(16, 2, 48, 12, 12, 4, 2, 1, 8, 5, 3, 4, 16),
        _ => LlmModelSpec::default(),
    }
}

#[derive(Default)]
struct TranscriptState {
    buffered: Vec<String>,
    writer: Option<BufWriter<fs::File>>,
    write_error: Option<String>,
    lines_written: usize,
    bytes_written: usize,
}

static TRANSCRIPT: OnceLock<Mutex<TranscriptState>> = OnceLock::new();

fn transcript() -> &'static Mutex<TranscriptState> {
    TRANSCRIPT.get_or_init(|| Mutex::new(TranscriptState::default()))
}

fn reset_transcript() {
    if let Ok(mut state) = transcript().lock() {
        if let Some(writer) = state.writer.as_mut() {
            let _ = writer.flush();
        }
        *state = TranscriptState::default();
    }
}

fn configure_transcript(path: &Path) -> Result<(), String> {
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent).map_err(|e| format!("{}: {}", parent.display(), e))?;
    }
    let file = fs::File::create(path).map_err(|e| format!("{}: {}", path.display(), e))?;
    let mut writer = BufWriter::with_capacity(64 * 1024, file);
    let mut state = transcript()
        .lock()
        .map_err(|_| "transcript lock poisoned".to_string())?;
    let buffered = std::mem::take(&mut state.buffered);
    for line in buffered {
        writeln!(writer, "{}", line).map_err(|e| format!("{}: {}", path.display(), e))?;
        state.lines_written += 1;
        state.bytes_written += line.len() + 1;
    }
    state.writer = Some(writer);
    Ok(())
}

fn emit_line(line: impl AsRef<str>) {
    let line = line.as_ref().to_string();
    println!("{}", line);
    if let Ok(mut state) = transcript().lock() {
        if let Some(writer) = state.writer.as_mut() {
            if let Err(err) = writeln!(writer, "{}", line) {
                state.write_error = Some(err.to_string());
            } else {
                state.lines_written += 1;
                state.bytes_written += line.len() + 1;
            }
        } else {
            state.buffered.push(line);
        }
    }
}

fn emit_blank() {
    emit_line("");
}

fn flush_transcript() -> Result<(usize, usize), String> {
    let mut state = transcript()
        .lock()
        .map_err(|_| "transcript lock poisoned".to_string())?;
    if let Some(error) = state.write_error.take() {
        return Err(error);
    }
    if let Some(writer) = state.writer.as_mut() {
        writer.flush().map_err(|e| e.to_string())?;
    }
    Ok((state.lines_written, state.bytes_written))
}

