fn effective_spec(args: &PretrainArgs) -> LlmModelSpec {
    let mut spec = preset_spec(&args.preset, args.smoke);
    if args.block_size > 0 {
        spec.block_size = args.block_size;
    }
    if args.batch_size > 0 {
        spec.batch_size = args.batch_size;
    }
    if let Some(layers) = args.layers {
        spec.n_layers = layers.max(1);
    }
    if let Some(embd) = args.embd {
        spec.n_embd = embd.max(spec.n_head);
    }
    if args.max_new_tokens > 0 {
        spec.max_new_tokens = args.max_new_tokens;
    }
    if args.samples_per_strategy > 0 {
        spec.samples = args.samples_per_strategy;
    }
    spec.n_head = spec.n_head.max(1);
    spec.n_embd = spec.n_embd.max(spec.n_head);
    spec.rope_head_dim = spec.n_embd / spec.n_head;
    spec.expert_top_k = spec.expert_top_k.clamp(1, spec.n_experts.max(1));
    spec.n_shared_experts = spec.n_shared_experts.max(1);
    spec
}

fn varmap_param_count(varmap: &VarMap) -> usize {
    varmap
        .all_vars()
        .iter()
        .map(|tensor| tensor.elem_count())
        .sum()
}

fn named_var_tensors(varmap: &VarMap) -> Result<Vec<(String, Tensor)>, String> {
    let data = varmap
        .data()
        .lock()
        .map_err(|_| "VarMap lock poisoned".to_string())?;
    let mut vars = data
        .iter()
        .map(|(name, var)| (name.clone(), var.as_tensor().clone()))
        .collect::<Vec<_>>();
    vars.sort_by(|a, b| a.0.cmp(&b.0));
    Ok(vars)
}

fn named_vars(varmap: &VarMap) -> Result<Vec<(String, candle_core::Var)>, String> {
    let data = varmap
        .data()
        .lock()
        .map_err(|_| "VarMap lock poisoned".to_string())?;
    let mut vars = data
        .iter()
        .map(|(name, var)| (name.clone(), var.clone()))
        .collect::<Vec<_>>();
    vars.sort_by(|(name_a, _), (name_b, _)| name_a.cmp(name_b));
    Ok(vars)
}

fn cached_named_tensors(vars: &[(String, candle_core::Var)]) -> Vec<(String, Tensor)> {
    vars.iter()
        .map(|(name, var)| (name.clone(), var.as_tensor().clone()))
        .collect()
}

fn deterministic_initialize_varmap(varmap: &VarMap, seed: u64) -> CResult<()> {
    let mut data = varmap
        .data()
        .lock()
        .map_err(|_| candle_core::Error::Msg("VarMap lock poisoned".into()))?;
    let mut names = data.keys().cloned().collect::<Vec<_>>();
    names.sort();
    for name in names {
        let Some(var) = data.get_mut(&name) else {
            continue;
        };
        let dims = var.dims().to_vec();
        let elem_count = var.elem_count();
        let lower_name = name.to_ascii_lowercase();
        let values = if lower_name.ends_with("bias") {
            vec![0.0f32; elem_count]
        } else if lower_name.ends_with("lambda") {
            vec![0.8f32; elem_count]
        } else if lower_name.contains("norm") && lower_name.ends_with("weight") {
            vec![1.0f32; elem_count]
        } else {
            let mut hasher = Sha256::new();
            hasher.update(seed.to_le_bytes());
            hasher.update(name.as_bytes());
            let digest = hasher.finalize();
            let mut seed_bytes = [0u8; 8];
            seed_bytes.copy_from_slice(&digest[..8]);
            let mut rng = rand::rngs::StdRng::seed_from_u64(u64::from_le_bytes(seed_bytes));
            let fan_in = dims.last().copied().unwrap_or(1).max(1) as f64;
            let fan_out = if dims.len() >= 2 {
                dims[dims.len() - 2].max(1) as f64
            } else {
                dims.first().copied().unwrap_or(1).max(1) as f64
            };
            let limit = (6.0 / (fan_in + fan_out)).sqrt() as f32;
            (0..elem_count)
                .map(|_| rng.gen_range(-limit..=limit))
                .collect::<Vec<_>>()
        };
        let initialized = Tensor::from_vec(values, dims, var.device())?;
        var.set(&initialized)?;
    }
    Ok(())
}

fn print_production_header(
    runtime: &ProductionRunContext,
    device: &Device,
    device_report: &serde_json::Value,
) {
    emit_blank();
    emit_line("======================================================================");
    emit_line(format!(
        "  {} {} {} StateSpace: Multi-Scale Holographic Production Runtime",
        JARVIS_MODEL_FAMILY, JARVIS_MODEL_VERSION, JARVIS_DISPLAY_NAME
    ));
    emit_line("  Domain: llm");
    emit_line(format!("  Run mode: {}", runtime.run_mode));
    emit_line(format!("  Run ID: {}", runtime.run_id));
    emit_line(format!("  Artifacts: {}", runtime.run_dir.display()));
    emit_line(format!("  Device: {}", device_label(device)));
    if let Some(gpu_name) = device_report
        .get("cuda_probe")
        .and_then(|v| v.get("gpu_name"))
        .and_then(|v| v.as_str())
    {
        emit_line(format!("  GPU probe: {}", gpu_name));
    }
    if let Some(reason) = device_report
        .get("fallback_reason")
        .and_then(|v| v.as_str())
    {
        emit_line(format!("  Rust CUDA fallback: {}", reason));
    }
    emit_line("======================================================================");
    emit_blank();
}

