#[derive(Debug, Clone)]
struct CharTokenizer {
    chars: Vec<char>,
    stoi: HashMap<char, usize>,
}

impl CharTokenizer {
    fn from_documents(docs: &[String]) -> Self {
        let mut set = BTreeSet::new();
        for doc in docs {
            for ch in doc.chars() {
                set.insert(ch);
            }
        }
        let chars: Vec<char> = set.into_iter().collect();
        let stoi = chars
            .iter()
            .enumerate()
            .map(|(i, &ch)| (ch, i + 1))
            .collect();
        Self { chars, stoi }
    }

    fn encode(&self, text: &str) -> Vec<usize> {
        text.chars()
            .map(|ch| self.stoi.get(&ch).copied().unwrap_or(self.bos_token_id()))
            .collect()
    }

    fn decode(&self, tokens: &[usize]) -> String {
        let mut out = String::new();
        for &token in tokens {
            if token == self.bos_token_id() {
                continue;
            }
            if let Some(ch) = self.chars.get(token.saturating_sub(1)) {
                out.push(*ch);
            } else {
                out.push('?');
            }
        }
        out
    }

    fn vocab_size(&self) -> usize {
        self.chars.len() + 1
    }

    fn bos_token_id(&self) -> usize {
        0
    }

    fn vocab_preview(&self) -> String {
        self.chars.iter().take(48).collect()
    }

    fn vocab_tokens(&self) -> Vec<String> {
        let mut tokens = Vec::with_capacity(self.vocab_size());
        tokens.push("<BOS>".into());
        tokens.extend(self.chars.iter().map(|ch| ch.to_string()));
        tokens
    }

    fn vocab_hash(&self) -> String {
        runtime_shared::sha256_hex(
            serde_json::to_string(&self.vocab_tokens())
                .unwrap_or_else(|_| "[]".into())
                .as_bytes(),
        )
    }
}

#[derive(Debug, Clone)]
struct CharDataset {
    tokens: Vec<usize>,
    block_size: usize,
    target_horizon: usize,
}

impl CharDataset {
    fn new(
        docs: &[String],
        tokenizer: &CharTokenizer,
        block_size: usize,
        target_horizon: usize,
    ) -> Self {
        let mut tokens = Vec::new();
        for doc in docs {
            tokens.push(tokenizer.bos_token_id());
            tokens.extend(tokenizer.encode(doc));
        }
        tokens.push(tokenizer.bos_token_id());
        Self {
            tokens,
            block_size,
            target_horizon: target_horizon.max(1),
        }
    }

    fn len(&self) -> usize {
        self.tokens
            .len()
            .saturating_sub(self.block_size + self.target_horizon)
            .saturating_add(1)
    }

    fn is_empty(&self) -> bool {
        self.len() == 0
    }

    fn input_token(&self, start: usize, offset: usize) -> Option<usize> {
        self.tokens.get(start + offset).copied()
    }

    fn target_token(&self, start: usize, offset: usize, horizon_offset: usize) -> Option<usize> {
        if horizon_offset == 0 || horizon_offset > self.target_horizon {
            return None;
        }
        self.tokens.get(start + offset + horizon_offset).copied()
    }
}

