struct CayleyResidualBlock {
    fc1: Linear,
    fc2: Linear,
}

impl CayleyResidualBlock {
    fn new(width: usize, vb: VarBuilder) -> CResult<Self> {
        Ok(Self {
            fc1: linear(width, width, vb.pp("fc1"))?,
            fc2: linear(width, width, vb.pp("fc2"))?,
        })
    }
}

impl Module for CayleyResidualBlock {
    fn forward(&self, x: &Tensor) -> CResult<Tensor> {
        let h = self.fc1.forward(x)?.relu()?;
        let h = self.fc2.forward(&h)?;
        (x + h)?.relu()
    }
}

struct CayleyDistanceHead {
    input_norm: RMSNorm,
    input_linear: Linear,
    hidden_linear: Option<Linear>,
    blocks: Vec<CayleyResidualBlock>,
    out: Linear,
}

impl CayleyDistanceHead {
    fn new(
        dim: usize,
        hidden1: usize,
        hidden2: usize,
        n_blocks: usize,
        vb: VarBuilder,
    ) -> CResult<Self> {
        let hidden1 = hidden1.max(1);
        let input_norm = RMSNorm::new(dim, 1e-6, vb.pp("input_norm"))?;
        let input_linear = linear(dim, hidden1, vb.pp("input_linear"))?;
        let (hidden_linear, width) = if hidden2 > 0 {
            (
                Some(linear(hidden1, hidden2, vb.pp("hidden_linear"))?),
                hidden2,
            )
        } else {
            (None, hidden1)
        };
        let mut blocks = Vec::new();
        if hidden2 > 0 {
            for idx in 0..n_blocks {
                blocks.push(CayleyResidualBlock::new(
                    width,
                    vb.pp(format!("block_{}", idx)),
                )?);
            }
        }
        let out = linear(width, 1, vb.pp("out"))?;
        Ok(Self {
            input_norm,
            input_linear,
            hidden_linear,
            blocks,
            out,
        })
    }

    fn softplus(x: &Tensor) -> CResult<Tensor> {
        let neg_x = x.neg()?;
        let sigmoid_neg = candle_nn::ops::sigmoid(&neg_x)?;
        sigmoid_neg.log()?.neg()
    }
}

impl Module for CayleyDistanceHead {
    fn forward(&self, hidden_states: &Tensor) -> CResult<Tensor> {
        let mut x = self.input_norm.forward(hidden_states)?;
        x = self.input_linear.forward(&x)?.relu()?;
        if let Some(hidden_linear) = &self.hidden_linear {
            x = hidden_linear.forward(&x)?.relu()?;
        }
        for block in &self.blocks {
            x = block.forward(&x)?;
        }
        Self::softplus(&self.out.forward(&x)?.squeeze(D::Minus1)?)
    }
}

