fn rust_doctor_report(args: DoctorArgs) -> serde_json::Value {
    let data_path = resolve_data_path(args.data_path.as_deref());
    let artifact_root = framework_option_path(
        args.artifact_root.as_deref(),
        "JARVIS_LLM_ARTIFACT_ROOT",
        || PathBuf::from("/dev/shm/jarvis-rust-runs"),
    );
    let target_dir = env::var("CARGO_TARGET_DIR")
        .map(PathBuf::from)
        .unwrap_or_else(|_| PathBuf::from(env!("CARGO_MANIFEST_DIR")).join("target"));
    let cargo = env::var("JARVIS_LLM_CARGO")
        .ok()
        .filter(|value| !value.trim().is_empty())
        .or_else(|| {
            env::var("HOME")
                .ok()
                .map(|home| PathBuf::from(home).join(".cargo/bin/cargo"))
                .filter(|path| path.is_file())
                .map(|path| path.display().to_string())
        })
        .unwrap_or_else(|| "cargo".into());
    let cargo_available = Command::new(&cargo)
        .arg("--version")
        .output()
        .map(|output| output.status.success())
        .unwrap_or(false);

    let probe = CudaProbe::detect();
    let requested_device = args.device.clone();
    let device_resolution = resolve_device(&requested_device);
    let (device_selected, device_report, device_error) = match device_resolution {
        Ok((device, report)) => (
            device_label(&device).to_string(),
            report,
            serde_json::Value::Null,
        ),
        Err(err) => {
            let report = serde_json::json!({
                "requested": requested_device,
                "selected": serde_json::Value::Null,
                "cuda_probe": &probe,
                "fallback_reason": err.clone(),
                "build_hint": LlmFrameworkApp.build_hint(),
                "device_policy": device_policy_report(&requested_device, "unavailable", Some(err.as_str()), &probe),
                "cuda_policy": cuda_policy_report(&probe),
                "cuda_status": cuda_runtime_status_report(&requested_device, "unavailable", Some(err.as_str()), &probe),
                "wrapper_cuda_status": wrapper_cuda_status_report(),
            });
            ("unavailable".into(), report, serde_json::json!(err))
        }
    };
    let sources = source_artifact_report();
    let sources_ok = framework_source_artifacts_exist(&sources);
    let data_exists = data_path.is_file();
    let setk_report = build_llm_setk_i2_x1_report(&SetkI2X1Args {
        report_output: None,
        data_path: args.data_path.clone(),
        device: requested_device.clone(),
        seed: 42,
    });
    let setk_ok = runtime_shared::json_bool_at(&setk_report, &["ok"]).unwrap_or(false);
    let health_ok = cargo_available && data_exists && sources_ok && device_error.is_null();
    let ok = health_ok;
    let report = serde_json::json!({
        "ok": ok,
        "command": "doctor",
        "selected_build_mode": if device_selected == "cuda" { "cuda" } else { "cpu-portable" },
        "device_selected": device_selected,
        "device_error": device_error,
        "cargo": {
            "command": cargo,
            "available": cargo_available,
            "target_dir": target_dir,
            "target_disk": disk_report(&target_dir),
        },
        "data": {
            "path": data_path,
            "exists": data_exists,
            "sha256": if data_exists {
                serde_json::json!(file_sha256(&data_path).unwrap_or_else(|err| format!("error: {}", err)))
            } else {
                serde_json::Value::Null
            },
        },
        "artifact_root": {
            "path": artifact_root,
            "disk": disk_report(&artifact_root),
        },
        "sources": sources,
        "issues": {
            "cargo_missing": !cargo_available,
            "data_missing": !data_exists,
            "source_missing": !sources_ok,
            "device_error": !device_error.is_null()
        },
        "warnings": {
            "setk_i2_x1_gate_blocked": !setk_ok,
            "doctor_does_not_promote_x1": !setk_ok,
        },
        "promotion_gate": {
            "ok": setk_ok,
            "blocking_for_doctor": false,
            "blocking_for_production_promotion": !setk_ok,
            "note": "doctor validates CLI/runtime health; SETK-I2-X1 remains a separate production-promotion gate",
        },
        "asi_os_domain_evidence": llm_asi_os_domain_evidence(&device_report),
        "setk_i2_x1": setk_report,
    });
    stable_artifact_fields(report, None, &device_report)
}

fn print_doctor_report(args: DoctorArgs) -> Result<bool, String> {
    let report_output = args.report_output.clone();
    let report = rust_doctor_report(args);
    let ok = report
        .get("ok")
        .and_then(|value| value.as_bool())
        .unwrap_or(false);
    write_json_output(&report, report_output.as_deref())?;
    Ok(ok)
}

fn llm_preflight_report(vocab_size: usize, device_report: &serde_json::Value) -> serde_json::Value {
    let compile_spec = HashMap::from([
        ("domain".into(), serde_json::json!("math")),
        ("task".into(), serde_json::json!("add")),
        ("inputs".into(), serde_json::json!({"a": 4, "b": 5})),
    ]);
    let compile_report = compile_domain_spec(&compile_spec);
    let scheduler = run_compiler_native_scheduler_self_test();
    let head_contract = jarvis_native_head_contract(vocab_size);
    let checks = serde_json::json!({
        "compiler_native_math_add": compile_report.ok
            && compile_report.vm_proof.as_ref().and_then(|p| p.public_output) == Some(9),
        "scheduler": scheduler.get("ok").and_then(|v| v.as_bool()).unwrap_or(false),
        "head_contract_17_heads": head_contract.get("head_count").and_then(|v| v.as_u64()) == Some(17),
        "dynamic_language_width": head_contract
            .get("heads")
            .and_then(|v| v.as_array())
            .and_then(|heads| heads.first())
            .and_then(|head| head.get("dim"))
            .and_then(|v| v.as_u64()) == Some(vocab_size as u64),
    });
    let ok = checks
        .as_object()
        .map(|items| items.values().all(|value| value.as_bool().unwrap_or(false)))
        .unwrap_or(false);
    serde_json::json!({
        "ok": ok,
        "checks": checks,
        "compiler_native": compile_report,
        "scheduler": scheduler,
        "head_contract": head_contract,
        "device_report": device_report,
        "device_policy": runtime_shared::json_key(device_report, "device_policy"),
        "cuda_policy": runtime_shared::json_key(device_report, "cuda_policy"),
    })
}

