fn attach_final_mtp_artifact_metrics(
    mut report: serde_json::Value,
    final_metrics: &StepMetrics,
) -> serde_json::Value {
    let training_metrics = serde_json::json!({
        "target_horizon": final_metrics.target_horizon,
        "mtp_horizon": final_metrics.mtp_horizon,
        "mtp_loss": final_metrics.mtp_loss,
        "mtp_valid_tokens": final_metrics.mtp_valid_tokens,
        "cayley_distance_loss": final_metrics.cayley_distance_loss,
        "cayley_distance_mean": final_metrics.cayley_distance_mean,
        "cayley_distance_target_mean": final_metrics.cayley_distance_target_mean,
    });
    if let Some(obj) = report.as_object_mut() {
        obj.insert(
            "target_horizon".to_string(),
            serde_json::json!(final_metrics.target_horizon),
        );
        obj.insert(
            "mtp_horizon".to_string(),
            serde_json::json!(final_metrics.mtp_horizon),
        );
        obj.insert(
            "mtp_loss".to_string(),
            serde_json::json!(final_metrics.mtp_loss),
        );
        obj.insert(
            "mtp_valid_tokens".to_string(),
            serde_json::json!(final_metrics.mtp_valid_tokens),
        );
        obj.insert(
            "cayley_distance_loss".to_string(),
            serde_json::json!(final_metrics.cayley_distance_loss),
        );
        obj.insert(
            "cayley_distance_mean".to_string(),
            serde_json::json!(final_metrics.cayley_distance_mean),
        );
        obj.insert(
            "cayley_distance_target_mean".to_string(),
            serde_json::json!(final_metrics.cayley_distance_target_mean),
        );
        if let Some(cayley_obj) = obj
            .get_mut("cayley")
            .and_then(|value| value.as_object_mut())
        {
            cayley_obj.insert(
                "cayley_distance_loss".to_string(),
                serde_json::json!(final_metrics.cayley_distance_loss),
            );
            cayley_obj.insert(
                "cayley_distance_mean".to_string(),
                serde_json::json!(final_metrics.cayley_distance_mean),
            );
            cayley_obj.insert(
                "cayley_distance_target_mean".to_string(),
                serde_json::json!(final_metrics.cayley_distance_target_mean),
            );
        }
        obj.insert("training_metrics".to_string(), training_metrics);
        for section in ["model", "training"] {
            if let Some(section_obj) = obj.get_mut(section).and_then(|value| value.as_object_mut())
            {
                section_obj.insert(
                    "target_horizon".to_string(),
                    serde_json::json!(final_metrics.target_horizon),
                );
                section_obj.insert(
                    "mtp_horizon".to_string(),
                    serde_json::json!(final_metrics.mtp_horizon),
                );
                section_obj.insert(
                    "mtp_loss".to_string(),
                    serde_json::json!(final_metrics.mtp_loss),
                );
                section_obj.insert(
                    "mtp_valid_tokens".to_string(),
                    serde_json::json!(final_metrics.mtp_valid_tokens),
                );
                section_obj.insert(
                    "cayley_distance_loss".to_string(),
                    serde_json::json!(final_metrics.cayley_distance_loss),
                );
                section_obj.insert(
                    "cayley_distance_mean".to_string(),
                    serde_json::json!(final_metrics.cayley_distance_mean),
                );
                section_obj.insert(
                    "cayley_distance_target_mean".to_string(),
                    serde_json::json!(final_metrics.cayley_distance_target_mean),
                );
            }
        }
    }
    report
}

