        let mut input = vec![0.0f32; 4 * 8];
        for (row, token) in [0usize, 1, 2, 3].iter().copied().enumerate() {
            input[row * 8 + token] = 1.0;
        }
        let x = Tensor::from_vec(input, (1, 4, 8), &Device::Cpu)?;
        let target_ids = Tensor::new(&[[1u32, 2, 3, 4]], &Device::Cpu)?;
        let (_language, world_prediction, hidden_seq) = net.forward_train_core(&x)?;
        let report = LlmPolicyNet::compute_world_model_loss(
            &world_prediction,
            &hidden_seq,
            Some(&target_ids),
            None,
        )?;
