    #[test]
    fn reflector_intervenes_and_recovers_within_bounds() {
        let mut reflector = TrainingReflector::new(100);
        reflector.observe(
            ReflectorObservation {
                step: 1,
                loss: 5.0,
                loss_ema: 5.0,
                accuracy: 0.01,
                grad_norm: 10.0,
                world_loss: 2.0,
                ema_divergence: 1.0,
                risk: 0.80,
                alignment: 0.10,
                uncertainty: 0.90,
                reflection: 0.80,
            },
            1.0,
        );
        let stabilized_lr = reflector.decision.lr_scale;
        assert_eq!(reflector.decision.mode, "stabilize_hard");
        assert!(stabilized_lr < 1.0);
        assert_eq!(reflector.decision.diagnostic_interval, 1);
        assert!(reflector.decision.world_weight > ASI_WORLD_LOSS_WEIGHT);

        for step in 2..12 {
            reflector.observe(
                ReflectorObservation {
                    step,
                    loss: 4.0 - step as f64 * 0.01,
                    loss_ema: 4.5 - step as f64 * 0.01,
                    accuracy: 0.20,
                    grad_norm: 0.5,
                    world_loss: 0.8,
                    ema_divergence: 0.2,
                    risk: 0.30,
                    alignment: 0.60,
                    uncertainty: 0.30,
                    reflection: 0.40,
                },
                1.0,
            );
        }
        assert!(reflector.decision.lr_scale > stabilized_lr);
        assert!(reflector.decision.lr_scale <= 1.0);
        assert!(reflector.decision.native_aux_weight <= 0.025);
        assert!(reflector.decision.diagnostic_interval > 1);
        assert!(reflector.recovery_steps > 0);
    }

