    #[test]
    fn autonomous_rsi_contract_emits_child_ai_blueprints_with_closed_write_barrier() {
        let metrics = test_full_next_state_metrics();
        let world_model = llm_world_model_contract(&metrics);
        let full_next_state_world_model = llm_full_next_state_objective_contract(&metrics);
        let rlg_world_model = llm_rl_geometric_world_model_contract(&metrics);
        let latent_mas = llm_latent_mas_contract(&metrics);
        let hyperagent = test_hyperagent_report();
        let moe_routing_health = serde_json::json!({"ok": true});

        let contract = llm_autonomous_rsi_contract(
            &metrics,
            &world_model,
            &full_next_state_world_model,
            &rlg_world_model,
            &latent_mas,
            Some(&hyperagent),
            &moe_routing_health,
        );

        assert_eq!(contract.get("ok").and_then(|v| v.as_bool()), Some(true));
        assert_eq!(
            contract
                .get("ai_creates_ai_status")
                .and_then(|value| value.as_str()),
            Some("candidate_child_ai_blueprints_and_upgrade_schedule_emitted")
        );
        assert_eq!(
            runtime_shared::json_bool_at(&contract, &["write_barrier", "source_writes_allowed"]),
            Some(false)
        );
        assert_eq!(
            runtime_shared::json_bool_at(
                &contract,
                &["write_barrier", "human_review_required_before_source_write"]
            ),
            Some(true)
        );
        assert_eq!(
            runtime_shared::json_bool_at(
                &contract,
                &["write_barrier", "autonomous_upgrade_scheduling_allowed"]
            ),
            Some(true)
        );
        assert_eq!(
            runtime_shared::json_bool_at(
                &contract,
                &["write_barrier", "autonomous_upgrade_execution_allowed"]
            ),
            Some(false)
        );
        assert!(
            contract
                .get("candidate_child_ai_blueprints")
                .and_then(|value| value.as_array())
                .map(|items| items.len())
                .unwrap_or(0)
                >= LLM_AUTONOMOUS_RSI_MIN_CANDIDATES
        );

        let missing_hyperagent = llm_autonomous_rsi_contract(
            &metrics,
            &world_model,
            &full_next_state_world_model,
            &rlg_world_model,
            &latent_mas,
            None,
            &moe_routing_health,
        );
        assert_eq!(
            missing_hyperagent.get("ok").and_then(|v| v.as_bool()),
            Some(false)
        );
        assert_eq!(
            runtime_shared::json_bool_at(&missing_hyperagent, &["gates", "hyperagent_archive_ok"]),
            Some(false)
        );
    }

    #[test]
    fn autonomous_rsi_v4_schedules_upgrade_curriculum_with_shadow_replay() {
        let metrics = test_full_next_state_metrics();
        let world_model = llm_world_model_contract(&metrics);
        let full_next_state_world_model = llm_full_next_state_objective_contract(&metrics);
        let rlg_world_model = llm_rl_geometric_world_model_contract(&metrics);
        let latent_mas = llm_latent_mas_contract(&metrics);
        let hyperagent = test_hyperagent_report();
        let moe_routing_health = serde_json::json!({"ok": true});
        let contract = llm_autonomous_rsi_contract(
            &metrics,
            &world_model,
            &full_next_state_world_model,
            &rlg_world_model,
            &latent_mas,
            Some(&hyperagent),
            &moe_routing_health,
        );

        assert_eq!(
            contract.get("version").and_then(|value| value.as_str()),
            Some(LLM_AUTONOMOUS_RSI_VERSION)
        );
        assert_eq!(
            contract
                .pointer("/rsi_control_plane/mode")
                .and_then(|value| value.as_str()),
            Some("governed_autonomous_upgrade_scheduler_control_plane")
        );
        assert_eq!(
            contract
                .pointer("/rsi_control_plane/source_mutation_authority")
                .and_then(|value| value.as_str()),
            Some("schedule_and_synthesize_only_no_apply")
        );
        assert_eq!(
            runtime_shared::json_bool_at(&contract, &["proof_ledger", "ok"]),
            Some(true)
        );
        assert!(contract
            .pointer("/proof_ledger/ledger_hash")
            .and_then(|value| value.as_str())
            .map(|digest| !digest.trim().is_empty())
            .unwrap_or(false));
        assert_eq!(
            runtime_shared::json_bool_at(&contract, &["gates", "ranked_candidates_ok"]),
            Some(true)
        );
        assert_eq!(
            runtime_shared::json_bool_at(&contract, &["gates", "candidate_proof_ok"]),
            Some(true)
        );
        assert_eq!(
            runtime_shared::json_bool_at(&contract, &["gates", "lineage_ok"]),
            Some(true)
        );
        assert_eq!(
            runtime_shared::json_bool_at(&contract, &["gates", "sandbox_simulation_ok"]),
            Some(true)
        );
        assert_eq!(
            runtime_shared::json_bool_at(&contract, &["gates", "autonomous_patch_bundle_ok"]),
            Some(true)
        );
        assert_eq!(
            runtime_shared::json_bool_at(&contract, &["gates", "upgrade_scheduler_ok"]),
            Some(true)
        );
        assert_eq!(
            runtime_shared::json_bool_at(&contract, &["gates", "upgrade_task_count_ok"]),
            Some(true)
        );
        assert_eq!(
            runtime_shared::json_bool_at(&contract, &["gates", "shadow_replay_ok"]),
            Some(true)
        );
        assert!(
            contract
                .pointer("/rsi_control_plane/accepted_candidate_count")
                .and_then(|value| value.as_u64())
                .unwrap_or(0)
                >= LLM_AUTONOMOUS_RSI_MIN_ACCEPTED_CANDIDATES as u64
        );
        assert_eq!(
            contract
                .pointer("/rsi_control_plane/autonomous_patch_bundle_count")
                .and_then(|value| value.as_u64()),
            Some(LLM_AUTONOMOUS_RSI_MIN_CANDIDATES as u64)
        );
        assert_eq!(
            runtime_shared::json_bool_at(&contract, &["rsi_control_plane", "upgrade_scheduler_ok"]),
            Some(true)
        );
        assert!(contract
            .pointer("/rsi_control_plane/upgrade_scheduler_hash")
            .and_then(|value| value.as_str())
            .map(|digest| !digest.trim().is_empty())
            .unwrap_or(false));
        assert!(contract
            .pointer("/proof_ledger/upgrade_scheduler_hash")
            .and_then(|value| value.as_str())
            .map(|digest| !digest.trim().is_empty())
            .unwrap_or(false));

        let scheduler = contract
            .get("upgrade_scheduler")
            .expect("upgrade scheduler emitted");
        assert_eq!(
            scheduler.get("ok").and_then(|value| value.as_bool()),
            Some(true)
        );
        assert_eq!(
            scheduler.get("mode").and_then(|value| value.as_str()),
            Some("governed_autonomous_upgrade_scheduler")
        );
        assert!(scheduler
            .pointer("/upgrade_tasks")
            .and_then(|value| value.as_array())
            .map(|items| items.len() >= LLM_AUTONOMOUS_RSI_MIN_UPGRADE_TASKS)
            .unwrap_or(false));
        assert!(scheduler
            .pointer("/shadow_replay_steps")
            .and_then(|value| value.as_array())
            .map(|items| items.len() >= LLM_AUTONOMOUS_RSI_MIN_SHADOW_REPLAY_STEPS)
            .unwrap_or(false));
        assert_eq!(
            runtime_shared::json_bool_at(
                scheduler,
                &["execution_barrier", "autonomous_upgrade_execution_allowed"]
            ),
            Some(false)
        );
        assert_eq!(
            runtime_shared::json_bool_at(
                scheduler,
                &["execution_barrier", "source_writes_allowed"]
            ),
            Some(false)
        );

        let candidates = contract
            .get("candidate_child_ai_blueprints")
            .and_then(|value| value.as_array())
            .expect("candidate child-AI blueprints");
        let mut previous_score = f64::INFINITY;
        for (index, candidate) in candidates.iter().enumerate() {
            assert_eq!(
                candidate.get("rank").and_then(|value| value.as_u64()),
                Some((index + 1) as u64)
            );
            let score = candidate
                .get("score")
                .and_then(|value| value.as_f64())
                .expect("candidate score");
            assert!(score <= previous_score);
            previous_score = score;
            assert_eq!(
                candidate
                    .pointer("/candidate_patch_plan/write_status")
                    .and_then(|value| value.as_str()),
                Some("not_written_closed_write_barrier")
            );
            assert_eq!(
                candidate
                    .pointer("/autonomous_patch_bundle/patch_application_status")
                    .and_then(|value| value.as_str()),
                Some("not_applied_closed_write_barrier")
            );
            assert_eq!(
                runtime_shared::json_bool_at(
                    candidate,
                    &["autonomous_patch_bundle", "source_mutation_performed"]
                ),
                Some(false)
            );
            assert!(candidate
                .pointer("/autonomous_patch_bundle/verifier_matrix")
                .and_then(|value| value.as_array())
                .map(|items| items.len() >= LLM_AUTONOMOUS_RSI_MIN_VERIFIER_STEPS)
                .unwrap_or(false));
            assert_eq!(
                runtime_shared::json_bool_at(
                    candidate,
                    &["autonomous_patch_bundle", "rollback_plan", "ok"]
                ),
                Some(true)
            );
            assert_eq!(
                runtime_shared::json_bool_at(
                    candidate,
                    &["autonomous_patch_bundle", "canary_plan", "ok"]
                ),
                Some(true)
            );
            assert_eq!(
                runtime_shared::json_bool_at(
                    candidate,
                    &["sandbox_simulation", "source_mutation_performed"]
                ),
                Some(false)
            );
            assert!(
                candidate
                    .pointer("/proof/stage_count")
                    .and_then(|value| value.as_u64())
                    .unwrap_or(0)
                    >= LLM_AUTONOMOUS_RSI_MIN_PROOF_STAGES as u64
            );
            assert!(candidate
                .pointer("/proof/proof_digest")
                .and_then(|value| value.as_str())
                .map(|digest| !digest.trim().is_empty())
                .unwrap_or(false));
            assert_eq!(
                runtime_shared::json_bool_at(candidate, &["proof", "verifier_matrix_ok"]),
                Some(true)
            );
            assert_eq!(
                runtime_shared::json_bool_at(candidate, &["proof", "rollback_plan_ok"]),
                Some(true)
            );
            assert_eq!(
                runtime_shared::json_bool_at(candidate, &["proof", "canary_plan_ok"]),
                Some(true)
            );
        }
    }

